-- Poems batch 161
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('76147431-321c-4849-a2fa-bcdaa0603bd7','又和三首 感鶺鴒原','袁說友','宋','宋诗','song-poetry','','[]','兄弟生同室，長大相差池。',48,'全唐诗/poet.song.161000.json','["兄弟生同室，長大相差池。", "浮生朝露如，歡樂隨憂悲。", "南來幾飛鴈，北去歸同時。", "嗟君胡不知，恨此何可追。"]'),
('0ce683c4-c88c-46b3-9d85-ff19b8ad4e15','又和三首 懷蕭居','袁說友','宋','宋诗','song-poetry','','[]','前生老居士，識我臭味同。',48,'全唐诗/poet.song.161000.json','["前生老居士，識我臭味同。", "詩囊欲往來，一別已再冬。", "相從能幾何，歲晚驚飄蓬。", "須賦早歸歟，共老千巖松。"]'),
('dad451c3-0d2d-4154-94e4-11503c9a1797','又和三首 歎七十','袁說友','宋','宋诗','song-poetry','','[]','人生自作難，百念一已多。',48,'全唐诗/poet.song.161000.json','["人生自作難，百念一已多。", "七十古稀有，况此疾病何。", "紛紛老駘駑，失脚千丈坡。", "行樂當及茲，歲月如經過。"]'),
('36f792bd-725d-4675-9281-2758e615c595','和王德和知縣謁蕭千巖韻二首  其一','袁說友','宋','宋诗','song-poetry','','[]','虛名誤壯夫，黄金變顔色。',48,'全唐诗/poet.song.161000.json','["虛名誤壯夫，黄金變顔色。", "誰歟帛米謀，困此芻狗迹。", "安和一榻上，精神餘筆力。", "我欲造之深，劇談忘漏刻。"]'),
('e0f3dd2d-3e5c-4fac-9d50-4cad61114602','和王德和知縣謁蕭千巖韻二首  其二','袁說友','宋','宋诗','song-poetry','','[]','詩工解窮人，詞苦乃見意。',48,'全唐诗/poet.song.161000.json','["詩工解窮人，詞苦乃見意。", "味公千巖篇，粗了瑟僩義。", "平生師友念，正爾金蘭契。", "毋使我迴還，執炙不知味。"]'),
('ec2e702e-033c-42f3-b5d6-0b7a6d5d425e','和林子長訓諸郎韻','袁說友','宋','宋诗','song-poetry','','[]','祝臝不知難，舐犢不知累。',276,'全唐诗/poet.song.161000.json','["祝臝不知難，舐犢不知累。", "我生飽經涉，一一如歷塊。", "泛觀孩提兒，鏗鏘捷應對。", "由其學不學，所入遂同異。", "有子當務教，否則基業墜。", "明經仰韋賢，所重識與器。", "黄金委塵土，教子遊於藝。", "父子踵黄閣，功業美且粹。", "最憐房杜家，門戶早覆簣。", "紛紛不肖子，掃蕩等劇戲。", "賢愚豈少年，成敗見晚歲。", "君家萬金産，兩兩蘭玉萃。", "兒時見頭角，已負食牛氣。", "誦詩了瑟僩，引義觸儔類。", "長大守經訓，含咀樂心醉。", "瀾翻紙上語，筆力功憑恃。", "老蚌生明珠，光彩爛足畏。", "渥漥墮龍種，不數蟾蜍輩。", "孟仲叔季間，更盛而迭貴。", "吾兒豚犬耳，衣鉢倘可遺。", "登門倚羣玉，辱交每不外。", "譬如般若光，照此大海會。", "願續無盡燈，庶爲宗門慰。"]'),
('e1427049-59c3-4109-9106-3f23d150ba4c','和梁飾甫通判招飲林子長溪堂韻  其一','袁說友','宋','宋诗','song-poetry','','[]','多病苦長夏，炎歊盛朱明。',96,'全唐诗/poet.song.161000.json','["多病苦長夏，炎歊盛朱明。", "得秋如故人，一見意已清。", "夜來風襲月，桂柳窺欄楹。", "頗憶橫塘溪，百計無餘營。", "清風菡萏秋，摇摇月中聲。", "剽聞有新約，賓主意各傾。", "妙語含風漪，一笑槊可橫。", "尊前欠佳客，豈無葛强生。"]'),
('da597074-62f0-41fe-929e-df4e8e23ab74','和梁飾甫通判招飲林子長溪堂韻  其二','袁說友','宋','宋诗','song-poetry','','[]','千家滿明月，更覺雙溪明。',96,'全唐诗/poet.song.161000.json','["千家滿明月，更覺雙溪明。", "秋來詩酒無，毋乃亦太清。", "詩筒解我意，續續堆軒楹。", "豈無斗酒藏，而待君所營。", "頓聞別駕賢，行聽立鵠聲。", "秋光恐無幾，有酒何從傾。", "扁舟下滄浪，及此月猶橫。", "要當辦茲遊，奇絕誇平生。"]'),
('948a7847-01c6-440a-a78c-76807e285204','郡寮案樂飲趙判院有詩次其韻','袁說友','宋','宋诗','song-poetry','','[]','簿書紛如絲，取樂得少空。',144,'全唐诗/poet.song.161000.json','["簿書紛如絲，取樂得少空。", "悠然杯勺興，藉此歌舞送。", "從事來官厨，醉不睡隣甕。", "衣裳賸蘭澤，言議雜囂鬨。", "人生醒忌獨，勝日飲須痛。", "向來韝上鷹，府公解其縱。", "先生作禪卧，肯以靜嗤動。", "形臞詩則昌，萬境供日用。", "文字與紅裙，寧非一理共。", "退之强分別，無乃夢中夢。", "絲竹娛中年，耐此髮種種。", "明當解予酲，酒德賡舊頌。"]'),
('7a95b6de-de4a-4503-9498-aa53fd0d178f','病不能從沈德遠少卿草堂醵飲','袁說友','宋','宋诗','song-poetry','','[]','溪南十里山，有客今淵明。',120,'全唐诗/poet.song.161000.json','["溪南十里山，有客今淵明。", "歸來厭城市，著脚鷗鷺汀。", "客來笑談劇，日暮車馬行。", "我昔曾見之，浩氣猶憑陵。", "尊酒浸成列，翰墨時相迎。", "慚渠前日約，念此故舊情。", "衝風走籃輿，剝啄山頭扃。", "人生等游戲，底問割與烹。", "但令賓主歡，莫識衆我醒。", "毋以患難移，政須公主盟。"]'),
('871a67b6-1096-4f94-aad7-a987aa3e572f','李兼濟分教江陰','袁說友','宋','宋诗','song-poetry','','[]','結交不在久，但問交者誰。',276,'全唐诗/poet.song.161000.json','["結交不在久，但問交者誰。", "相從何用頻，要以道誼期。", "我初未識君，已誦班馬辭。", "太學金薤篇，爛若琳琅垂。", "妙理遡家學，雄文想英姿。", "天乎慰此心，而獲親芝眉。", "一見語未盡，覺我驕氣移。", "荷君偶過聽，得我嗟何遲。", "我方縛微官，君亦居所疑。", "於今五六年，見日常差池。", "有時適相逢，一語不及私。", "往往從容間，百篇惟新詩。", "歸來念所得，如日身親之。", "君將抱停涵，一灑澄江緇。", "想君車馬至，短褐環旌旂。", "萬口如一詞，是曰得所師。", "一斑見稍稍，士氣今虹霓。", "江城見儒英，而我失所資。", "自慚索米久，不去今何爲。", "及瓜早歸歟，問舍江之湄。", "政須邇門牆，作意頻追隨。", "窮達於其天，紛紛徒自欺。", "買羊沽酒日，剖此胸中奇。"]'),
('11643f32-6c8e-41b4-a259-89d99e3c7eed','沈德遠守衢州用林子長通判送行韻','袁說友','宋','宋诗','song-poetry','','[]','宦海足風波，洶湧百態動。',216,'全唐诗/poet.song.161000.json','["宦海足風波，洶湧百態動。", "更嗟爲郡難，一木支橈棟。", "利害秦越瘠，謗讟鄒魯鬨。", "區區美衆口，於道竟何用。", "一墮怨憎機，玉毀石可貢。", "鄉來羞染指，負此淮陽重。", "公今上柯山，威望壓羣衆。", "州橫車馬衝，吏黠機巧共。", "寬猛歎何適，往事成一夢。", "利孔百已竭，舉手下輒訟。", "其難皆如此，要以人折衷。", "如公補天子，輕重識抱甕。", "善刀而藏之，游刃真總總。", "政成餘嘯坐，事定略銜控。", "人生五馬貴，願公還舊供。", "歸來佐雄略，一洗潢池弄。", "我方煙霞痼，爾若丹霄鳳。", "儻知下愚賢，應笑臧文仲。"]'),
('a30004c1-c425-4610-bcda-ea57a46b3f26','王恭父出守洋州二首  其一','袁說友','宋','宋诗','song-poetry','','[]','胸中萬卷書，足下四方志。',60,'全唐诗/poet.song.161000.json','["胸中萬卷書，足下四方志。", "士任重道遠，渠以中外異。", "肯戀承明直，狹此天下計。", "方此議遠略，慷慨誰襆被。", "翻然有抗章，屬之英儒耳。"]'),
('b784905b-d236-450b-b55d-80c676620cfe','王恭父出守洋州二首  其二','袁說友','宋','宋诗','song-poetry','','[]','我懷粗憂世，所遇輒盾矛。',60,'全唐诗/poet.song.161000.json','["我懷粗憂世，所遇輒盾矛。", "自公握手初，臭味一一投。", "一麾咸陽邊，而豈但寢謀。", "應有齊人者，歸此侵疆不。", "小策洋州勳，不止萬戶侯。"]'),
('1a379f90-71db-46ae-bdd4-6a0131ff2b48','鄭惠叔閣學守建寧三首  其一','袁說友','宋','宋诗','song-poetry','','[]','天生棟梁姿，本作棟梁用。',60,'全唐诗/poet.song.161000.json','["天生棟梁姿，本作棟梁用。", "豈其天下望，可使觖萬衆。", "乾坤欲開泰，數定不可霿。", "我公胸中秋，萬寶一未種。", "士其少須之，要以他日重。"]'),
('0c6b6e98-96ac-4592-b2b4-9114d21d1d36','鄭惠叔閣學守建寧三首  其二','袁說友','宋','宋诗','song-poetry','','[]','周之士也貴，如圭璧璠璵。',60,'全唐诗/poet.song.161000.json','["周之士也貴，如圭璧璠璵。", "東陝與南土，出入本裕如。", "高冠不可羈，位次實有餘。", "輕此一葉舟，孰肯戲魯儒。", "自公抗章行，益以貴士夫。"]'),
('c5ad9823-c1dd-459a-8963-74e0117ef8ad','鄭惠叔閣學守建寧三首  其三','袁說友','宋','宋诗','song-poetry','','[]','公乎斯文宗，學者仰泰北。',60,'全唐诗/poet.song.161000.json','["公乎斯文宗，學者仰泰北。", "而我幸姻婭，心切迹每梏。", "龍門甫登進，已動驪駒曲。", "江湖摇歸心，我亦慕高躅。", "更愁帆風船，無路送雙目。"]'),
('751fbb41-2269-4194-a596-263f3a2f94df','贈王副伴','袁說友','宋','宋诗','song-poetry','','[]','將軍年少時，束髮在行伍。',216,'全唐诗/poet.song.161000.json','["將軍年少時，束髮在行伍。", "西方頃多事，二十勇如虎。", "一身殆百戰，手足瘡四五。", "征行久邊戍，肯憚服役苦。", "西陲五十郡，一一經險阻。", "一官三十年，銖積僅如許。", "我聞中興後，卷甲久未舉。", "宿將零落盡，屈指不可數。", "政恐據鞍者，驕懦如嬰乳。", "時平偶無事，酒肉而子女。", "問之行陣事，縮頭而栗股。", "有如將軍乎，少小服軍旅。", "金瘡歷歷在，末老勇亦賈。", "抵掌談世事，忠憤氣如鼓。", "願欲奏君王，臣不知死所。", "輕舟明月夜，慷慨聞奏語。", "釃酒誓長淮，有力期共努。", "歸去覲前旒，此懷須盡吐。"]'),
('495b2350-275d-467e-9dca-69e0b05c0c73','觀野塘荷花','袁說友','宋','宋诗','song-poetry','','[]','淤泥生荷化，物外各有性。',48,'全唐诗/poet.song.161000.json','["淤泥生荷化，物外各有性。", "環城散紅錦，颭灧滿支徑。", "人卧蓮葉舟，酒吸碧筩柄。", "箇中有真樂，樂盡意不盡。"]'),
('571a7282-192a-4718-b985-cfc9950c707b','松坡','袁說友','宋','宋诗','song-poetry','','[]','陵坡擢孤根，生意已翹楚。',48,'全唐诗/poet.song.161000.json','["陵坡擢孤根，生意已翹楚。", "主人歲寒姿，於此眼目具。", "夷荒挺勁節，偃蓋浥漙露。", "相對琳琅篇，後來慚驥附。"]'),
('9537350e-64b5-4baa-bfb1-2376c9e77d91','大石','袁說友','宋','宋诗','song-poetry','','[]','困卧籃輿中，醒視人影直。',228,'全唐诗/poet.song.161000.json','["困卧籃輿中，醒視人影直。", "伸頭起四望，不斷山環碧。", "羊腸路百轉，當面一蹲石。", "高廣不可際，隆重誰與匹。", "宛如百楹屋，玄繒四籠羃。", "又如龍虎踞，煙雲繞其側。", "突出衆山間，旁無他石立。", "古今歲年久，光彩凈如拭。", "兒童梯級上，羣聚相戲劇。", "偉哉殊特觀，我來聊扣擊。", "汝從何代有，長養成大質。", "汝今閲世多，幾見陵谷易。", "漢王欲東時，曾經車馬迹。", "武侯三顧後，曾見王師出。", "衮衮千萬載，人與事如織。", "興亡竟何在，而汝獨如昔。", "古有石能言，今乃不可詰。", "徘徊不忍去，撫掌重太息。", "安得李將軍，一箭誇雄力。"]'),
('a12a1557-09d6-4dfc-8663-351fd9003e77','遂寧府庫古銅物','袁說友','宋','宋诗','song-poetry','','[]','我貌殊不古，而有好古心。',180,'全唐诗/poet.song.161000.json','["我貌殊不古，而有好古心。", "未老已成癖，此病那砭鍼。", "本非口腹累，乃困耳目侵。", "遂州古名邦，有物歲月深。", "一一銅作器，得之古墓陰。", "燈罌間管柱，匜耳擎杯斟。", "劍弰累蒼節，鳳口塗黄金。", "人形雜獸面，詭異難橅臨。", "糢糊滓塵土，剝蝕遭晴霖。", "摩挲細拂拭，名代不可尋。", "楛矢辨形質，古磬鳴聲音。", "一經聖賢手，疑信別古今。", "佳哉今所藏，歷世方駸駸。", "會當有博雅，破此聾與瘖。", "敢效石鼓歌，吾意豈微吟。"]'),
('4537bf44-9836-4368-8026-18d42f6f9e96','蘇公內翰柏石圖','袁說友','宋','宋诗','song-poetry','','[]','柏生兩石間，顔狀何落落。',108,'全唐诗/poet.song.161000.json','["柏生兩石間，顔狀何落落。", "行鬚接石脈，生理初甚約。", "豈無螻蟻窺，未免風雨剝。", "孤撐謝栽培，欲取那可攫。", "森然兩石意，與柏真不薄。", "崢嶸炎凉外，盤踞互相絡。", "千尺意有餘，凜凜未可度。", "公看養口體，怪此軀幹削。", "滿眼較短長，瑣細公所略。"]'),
('ac87b76b-418d-49b2-a21e-8493e05331b0','題陳氏凈香亭','袁說友','宋','宋诗','song-poetry','','[]','人生樂事難，清節視險夷。',204,'全唐诗/poet.song.161000.json','["人生樂事難，清節視險夷。", "遇坎而履坦，詎以得喪虧。", "我觀萬物間，獨此琅玕宜。", "頎然挺冰操，得之風雨時。", "秋風桐飛翻，夏雨民怨咨。", "怵迫真乃見，嗟物如一岐。", "此君豈其然，風雨而不移。", "娟娟凈明月，細細香浮漪。", "此理固千載，俗士難與知。", "洮湖著危亭，千畝胸中奇。", "植此凜凜節，照公堂堂姿。", "仕已輕浮雲，喜慍不一施。", "山高空翠濕，草勁便疾吹。", "此風此雨至，公乎無磷緇。", "我方索米久，官事成癡兒。", "望公瀟洒中，糞壤與菌芝。", "何當亭上遊，細誦簡齋詩。"]'),
('4bf69b71-39ef-4a89-b6bd-01b5c2dcfec7','題楊誠齋南海集二首  其一','袁說友','宋','宋诗','song-poetry','','[]','君侯大雅姿，萬態歸物色。',48,'全唐诗/poet.song.161000.json','["君侯大雅姿，萬態歸物色。", "商略南海句，以心不以迹。", "試吐胸中奇，如臂指運力。", "今推王揚賢，童子漫雕刻。"]'),
('39c2987d-d8f0-4fe3-99c4-3450c38e924d','題楊誠齋南海集二首  其二','袁說友','宋','宋诗','song-poetry','','[]','詩以變成雅，騷以變達意。',48,'全唐诗/poet.song.161000.json','["詩以變成雅，騷以變達意。", "變其權者徒，中有至當義。", "水清石自見，變定道乃契。", "文章豈無底，過此恐少味。"]'),
('9954a3f8-0c60-4357-ad36-5ecf1dc35536','至游堂二首  其一','袁說友','宋','宋诗','song-poetry','','[]','力田須逢年，掘井須及泉。',240,'全唐诗/poet.song.161000.json','["力田須逢年，掘井須及泉。", "學者志於道，如以規正圓。", "及其見道時，攬轡誰爭先。", "筌蹄蛻陳迹，羽化而登僊。", "是中時反觀，一一人之天。", "森然衆妙現，所見惟所便。", "猗與至游者，日運萬里船。", "胸中三景軸，與道相因緣。", "道大心以悟，心遠見孰偏。", "一室景象存，物物隨餐眠。", "不游以爲游，至樂無冥顛。", "游非在山水，默與山水聯。", "天下有至游，得道有至賢。", "賢者以道游，百游不一愆。", "至于游俱忘，公與道獨全。", "談笑出清風，樽罍益欣然。", "張扁詫中郎，訓記增雄編。", "嗟予幸升堂，頓覺塵垢湔。", "從公至游境，左右餘芳鮮。", "歸來欲語人，心知口難傳。"]'),
('c14221e5-06a7-4bf8-a8f7-4f901707f556','至游堂二首  其二','袁說友','宋','宋诗','song-poetry','','[]','嗟哉予少年，學志如蒙泉。',240,'全唐诗/poet.song.161000.json','["嗟哉予少年，學志如蒙泉。", "區區指漫血，未識方與圓。", "晚於方冊間，再拜予公先。", "琳琅粲珠璣，意公真其僊。", "寒窗手不停，朝暮披雲天。", "已辦膺門登，肯放邊腹便。", "一身落宦海，去若不繫船。", "懷此日月長，歲晚而夤緣。", "長安初拜公，摳趨立庭偏。", "一見意未盡，憒憒如醉眠。", "春闈接從容，拜賜喜欲顛。", "夜半呼論文，不復懷官聯。", "此身願持似，稽首從公賢。", "一意門牆歸，稍却名利愆。", "尋幽並湖山，百計一未全。", "而公亦倦游，卜築方怡然。", "把酒問明月，誨我詩成編。", "淋浪身上衣，歸喜那更湔。", "雄篇富褒拂，字字華衮鮮。", "吾儕一瓣香，斯文今有傳。"]'),
('2e7e89ae-b0de-4289-9856-68045b94cb73','仲春勸耕有獻兩岐麥者和丁端叔茶使韻','袁說友','宋','宋诗','song-poetry','','[]','周原膴膴侔歌頌，我訪春郊屆羲仲。',256,'全唐诗/poet.song.161000.json','["周原膴膴侔歌頌，我訪春郊屆羲仲。", "市橋曲屈古招提，媚日暄風傍韉鞚。", "布宣德意父老喜，醉飽盤餐兒女共。", "眼看秀色壟頭多，風落輕花枝穗重。", "東皇生意滿阡陌，不待池塘春草夢。", "道傍瑞麥獻者誰，秀出雙枝駭羣衆。", "春風和氣下披拂，産出禎祥呈妙用。", "我思昔歲旱爲虐，幾度牋天香火供。", "懸知政拙漫心勞，自慚弗稱甘泉從。", "今年春到一犁雨，是處膏腴飽耕種。", "舉趾于耜競東作，剝棗烹葵弭田訟。", "三農儻遂富庶樂，四體如忘疴癢痛。", "只今貽此來牟喜，大手鋪張煩屈宋。", "崆峒有詠拾遺語，茂陵作頌相如諷。", "詩成豈待擊鉢催，句惡自慚操管弄。", "與君拍手頌豐年，姑置別離傾酒甕。"]'),
('2135c112-81d3-48f4-aba6-599c9e503ae9','行麥壟','袁說友','宋','宋诗','song-poetry','','[]','農操豚蹄競謀鬼，已信今年非昔比。',96,'全唐诗/poet.song.161000.json','["農操豚蹄競謀鬼，已信今年非昔比。", "十日五日風雨時，好語急傳兒女喜。", "南來麥熟春事收，東郊日落人影稠。", "騷人一見喜不盡，新詩預慶豐年秋。", "懸知聖德回天地，荒政已修非罪歲。", "目前更看牧羊人，不覺維魚來夢寐。"]'),
('dba8ba91-bace-4d6b-b5eb-1825fc163e48','禱祈喜以甲子日得晴','袁說友','宋','宋诗','song-poetry','','[]','去年閔雨忙，今年以晴禱。',124,'全唐诗/poet.song.161000.json','["去年閔雨忙，今年以晴禱。", "年年水旱苦關心，憂國不知身暗老。", "蜀田百里無陂池，山頭隴畝如畫棋。", "平時憂旱不憂水，秋水十日憂雨垂。", "天公忍使垂成阨，但把精誠期感格。", "扶桑忽上東海來，一夜天清風露白。", "今朝甲子逢晴秋，定應無耳生禾頭。", "少待餘糧棲畝日，倩渠送我歸田休。"]'),
('4bd3ad65-0576-4c23-9edf-492ad782f88e','詠晴','袁說友','宋','宋诗','song-poetry','','[]','農夫一飽嘗憂遲，十年五旱無已時。',128,'全唐诗/poet.song.161000.json','["農夫一飽嘗憂遲，十年五旱無已時。", "今年隴上消息好，天不靳我食與衣。", "黄梅雨了時雨至，三尺稻梗一尺泥。", "不憂夏潦憂甲子，阿香忽放雷車歸。", "白波翠浪雨霑足，已覺抄雲先簸粞。", "新春入甑供晨炊，吾農自此今無饑。", "邇來更說蠲輸好，州邑撫我如嬰兒。", "如今不怨田家苦，但憶詩人歌子婦。"]'),
('dd68c2da-dd9b-42b5-ae94-dc0c7ec5d7e4','喜晴即用前韻','袁說友','宋','宋诗','song-poetry','','[]','春田欲雨常憂遲，夏田得雨嗟踰時。',128,'全唐诗/poet.song.161000.json','["春田欲雨常憂遲，夏田得雨嗟踰時。", "春耕夏耨兩無及，眼乾淚竭空沾衣。", "翻翻聯聯脚力盡，萬車不救一尺泥。", "朝看東南暮西北，晚霞倏忽山頭歸。", "白日一照黄潦定，秋來準擬篩紅粞。", "早田拾得晚田熟，今年更救明年饑。", "念夫隴上一月宿，趁晴歸欲呼妻兒。", "與夫歲歲同甘苦，未容恤緯慙嫠婦。"]'),
('3125f29e-a916-4f15-a8e4-6124b4e0d7c3','江行有惠梅花者因憶杜少陵云江上被花惱不徹無處告訴只顛狂遂借此意而吟','袁說友','宋','宋诗','song-poetry','','[]','去年短櫂孤山閣，尋得橫斜在籬落。',96,'全唐诗/poet.song.161000.json','["去年短櫂孤山閣，尋得橫斜在籬落。", "带花飲酒六七人，醉傍錢塘城下泊。", "今年江上花惱時，無處告訴狂如癡。", "一枝的皪對無語，獨把詩酒相羈縻。", "平生百念輕於髮，惟有梅花心未歇。", "只愁花謝老相催，老盡頭白花又發。"]'),
('754ca06d-e7d9-484e-8cf3-197a14874dc8','峽中聞杜鵑','袁說友','宋','宋诗','song-poetry','','[]','春風破曉晴嵐濕，客子竛竮去程急。',67,'全唐诗/poet.song.161000.json','["春風破曉晴嵐濕，客子竛竮去程急。", "空山兩兩杜鵑聲，回首家鄉無羽翼。", "勸歸不歸聲厭多，旅懷剌剌空奈何。", "君不見秭歸城上今啼不，多少行人滿江口。"]'),
('badcddcc-3da0-4b7b-af78-64fa1e2198b6','聽道人彈琴','袁說友','宋','宋诗','song-poetry','','[]','東城尋春春事濃，長嘯理策蓬菴中。',96,'全唐诗/poet.song.161000.json','["東城尋春春事濃，長嘯理策蓬菴中。", "道人飯了徒快睡，萬慮一洗惟絲桐。", "高山不斷春嘖嘖，流水無言聲磔磔。", "月明露冷意有餘，夜想朝吟恨誰釋。", "平生心賞竹間尋，歲晚欣逢正始音。", "煩君更撫文王操，慰我寒窗在此琴。"]'),
('16d76030-bc67-4e41-87b3-53b42cb07eec','和林子長海棠韻','袁說友','宋','宋诗','song-poetry','','[]','去年寒食猶依然，海棠花落南溪前。',128,'全唐诗/poet.song.161000.json','["去年寒食猶依然，海棠花落南溪前。", "風隨雨雪作三厄，燕支落盡無人憐。", "今年花下去年色，不暖不寒三月天。", "花間置酒君有意，我負宿約慚周旋。", "年年惜春春易老，春去花殘常恨早。", "勸君更辦一杯春，明朝捲地東風掃。", "園溪已漲桃花急，月明夜釣漁舟笠。", "君能割我半亭溪，寧嘆此錐無地立。"]'),
('54e12a0c-e906-4cec-bd8f-970f11526537','和趙周錫詠魏南伯家葱茶韻','袁說友','宋','宋诗','song-poetry','','[]','武夷十月嘗先春，風生兩腋撩詩人。',160,'全唐诗/poet.song.161000.json','["武夷十月嘗先春，風生兩腋撩詩人。", "玉塵一縷輕且純，不與凡味爭比鄰。", "鐺中碧玉濤湧銀，七碗不厭烹啜頻。", "書窗假寐熟欠伸，重煎倍覺滋味勻。", "吾鄉此茗孰與倫，誰家却說江茶珍。", "剝葱細切誇珠蠙，泛甌更騁如鋪璘。", "不知珉玉難並陳，從來居上嗟積薪。", "魏君胡爲白頭新，懷兄詎可論不均。", "我雖曾沃齒下齦，不敢溢美忘鄉津。", "方圭圓璧當春晨，請君反本毋予嗔。"]'),
('11cdc2f0-895e-4442-915d-00ec9872b42a','和林子長謝徐吉甫蒲萄韻','袁說友','宋','宋诗','song-poetry','','[]','吾兒癸卯豚犬耳，徐家同日生明珠。',112,'全唐诗/poet.song.161000.json','["吾兒癸卯豚犬耳，徐家同日生明珠。", "廼翁愛子愛其類，堆盤歲歲分甘腴。", "嘗新既足旨甘奉，遣送更欲均有無。", "但肯食芹而美矣，如渠此意夫豈徒。", "嗟予已老將疾至，肉味不啜惟僧蔬。", "忽驚馬乳墮几案，未免饞口餐其餘。", "及茲滿架未零落，少待明月相携壺。"]'),
('d2e55ca8-d492-439b-bbe9-e5f5304cf5ef','和魏南伯乞酒韻','袁說友','宋','宋诗','song-poetry','','[]','古人行旆誇碧油，我舟寂寞隨處留。',64,'全唐诗/poet.song.161000.json','["古人行旆誇碧油，我舟寂寞隨處留。", "何人夜半詩博酒，鬼神欲泣如楚囚。", "一朝江上同漂泊，莫向樽前情淡薄。", "爲君更作白頭吟，欲辦錦囊慙句惡。"]'),
('f1df00f8-9703-47ce-a9f3-32dfac4fb624','小飲','袁說友','宋','宋诗','song-poetry','','[]','殘蟬古路無人跡，瑟瑟西風已三日。',64,'全唐诗/poet.song.161000.json','["殘蟬古路無人跡，瑟瑟西風已三日。", "杜門却掃處一室，顛倒筆硯理書帙。", "平生但恐辜吟筆，薄宦雲浮奚固必。", "客來相與入詩律，一葉庭柯恍如失。"]'),
('f1941246-4142-4cf2-96b9-a46f5298ec87','和王使君惠詩酒韻','袁說友','宋','宋诗','song-poetry','','[]','我生紀歷三逢申，久矣隻影誰爲親。',144,'全唐诗/poet.song.161000.json','["我生紀歷三逢申，久矣隻影誰爲親。", "戀彼溪山意已在，舉目更友君子人。", "言論道德歸大醇，葑菲下采顔色溫。", "買羊一見慰饑渴，載酒三就忘辛勤。", "今朝好語幾盈門，排攢炫晃驚童孫。", "字向紙上欲翻舞，句生妙處增清新。", "推窗更沃囁嚅口，便覺四體陶然春。", "嗟予從此毋多作，君方袖手韜奇略。", "詩壇行即拜將軍，莫謂小兒多淺薄。"]'),
('8837313b-47a1-4985-862b-61ae1254b4f7','和董顯叔韻','袁說友','宋','宋诗','song-poetry','','[]','江南人物在覿面，足以慰予疇昔念。',256,'全唐诗/poet.song.161000.json','["江南人物在覿面，足以慰予疇昔念。", "識公只在文字間，君子若人今子賤。", "江湖路遠睽言談，八年於外自亦閒。", "有時拂拭舊珠玉，端欲論詩伯仲間。", "公懷席珍方就聘，一航我欲長安近。", "只知喜接故人歡，寧羨官高如斗印。", "羈懷寂寞逢春光，未著語意何可當。", "下帷諸孫出新句，如繭抽緒思無疆。", "一詩傑出駭奇創，陡覺詩壇羣膽喪。", "自憐老退無好懷，語不驚人慚少壯。", "宦情不絕真如絲，有憤莫吐誰與咨。", "只今猶得斯人語，剩有風騷同激推。", "不堪人事長乖處，聞說扁舟復西去。", "十年一見意匆匆，更寫瀟湘別離句。", "男兒氣節天所資，道大何計合與違。", "但讀詩書談世事，看公衣錦他年歸。"]'),
('72386330-dfc6-4610-8bc6-92d06645c28f','和野堂惠老中秋月蝕韻','袁說友','宋','宋诗','song-poetry','','[]','一年清絕中秋時，仰天高欲攀桂枝。',128,'全唐诗/poet.song.161000.json','["一年清絕中秋時，仰天高欲攀桂枝。", "乾坤鎔入玉奩鑑，萬象一掃光芒垂。", "今年不見今宵月，有物噉之傾且仄。", "惜哉至此狼狽凶，空效玉川歌月蝕。", "一盃相囑三更夜，安得飛來明月借。", "明年應解勝今年，莫使詩人愁筆下。", "吁嗟今夕知何夕，且對孤燈照窗隙。", "夜闌搔首獨翻書，且喜燈前雙眼碧。"]'),
('73d8b797-6765-4ba2-8997-32c293f91817','和張季長少卿塵外亭韻','袁說友','宋','宋诗','song-poetry','','[]','金城玉壘雄西邊，雲崖凜凜摩蒼天。',240,'全唐诗/poet.song.161000.json','["金城玉壘雄西邊，雲崖凜凜摩蒼天。", "環城萬井四十里，無處著眼江頭煙。", "我來登臨重嘆息，搜索勝景披雲巔。", "結亭百雉上南郭，山川映带圍桑田。", "春風城南細麥好，夏雨城北圓荷鮮。", "長瀾四溢去不斷，茂林百種森當前。", "朝光下卷西山霧，界天一白如鎔甄。", "兩年寂寞誰知己，一日邂逅詩中仙。", "品題印可喜所遇，瀾翻筆下源流泉。", "平山醉翁何以重，一詞一記垂千年。", "於今塵外已獨步，壯觀絕致誰爭妍。", "癡兒莫苦簿書債，一笑亭上應忘筌。", "春來花柳賸遨樂，念我一舸方東遄。", "甘棠遺愛定無有，赤壁懷去猶能全。", "他年吳蜀問安好，簡繒各寄滄浪篇。"]'),
('8fbaf516-a0ca-4341-98af-cbdbb76407d9','和周元吉提刑席上得雨韻三首  其一','袁說友','宋','宋诗','song-poetry','','[]','西山忽作暮捲勢，長蜺噀水驅炎暉。',64,'全唐诗/poet.song.161000.json','["西山忽作暮捲勢，長蜺噀水驅炎暉。", "雷車震動吹海立，火傘退避如鷁飛。", "天公不憚翻覆手，客醉何惜淋浪衣。", "雲收暑退夜空闊，歸路已覺星河稀。"]'),
('755915a3-ceda-4e80-9efd-4e26b2f21142','和周元吉提刑席上得雨韻三首  其二','袁說友','宋','宋诗','song-poetry','','[]','湖山十里圍萬井，烟雲過盡迎朝暉。',64,'全唐诗/poet.song.161000.json','["湖山十里圍萬井，烟雲過盡迎朝暉。", "連巒得雨有餘態，歸鷺倚風無限飛。", "田頭遠布翠縠浪，池上暗濕紅裙衣。", "山翁何惜一倒載，及此訟簡人已稀。"]'),
('80956b07-9986-4d07-bb2c-67559f9d6f41','和周元吉提刑席上得雨韻三首  其三','袁說友','宋','宋诗','song-poetry','','[]','蓬萊秦望兩如峙，中有萬頃浮光暉。',64,'全唐诗/poet.song.161000.json','["蓬萊秦望兩如峙，中有萬頃浮光暉。", "自憐俗吏脚不歷，每欣奇觀身欲飛。", "芃芃布野翠捲浪，靄靄出袖雲爲衣。", "詩材滿目供不盡，只恐寡和詩人稀。"]'),
('86e28f45-585d-4b3a-83f3-5818033b41c6','野堂惠老惠筍','袁說友','宋','宋诗','song-poetry','','[]','騎臺落日餐秋菊，寒食江南饌餳粥。',160,'全唐诗/poet.song.161000.json','["騎臺落日餐秋菊，寒食江南饌餳粥。", "一年節物正撩人，賸把嘗新伴幽獨。", "平生慣飽藜藿淡，口腹累人何日足。", "故園又作穿籬態，解籜呈新包一束。", "甘寒不澆礧磈腸，一飯更須炊白玉。", "年來稍學長沙味，一月煨藏愛餘馥。", "腥羶棄去不復念，從渠且負將軍腹。", "老僧日食常住供，飽坐饑食不論斛。", "春來不訟籜龍冤，每誦坡僊食無肉。", "箇中風味有誰同，付與新詩照湖綠。"]'),
('2459783b-a637-4096-b073-4bcb3722c8dd','謝惠補之送梁杲墨','袁說友','宋','宋诗','song-poetry','','[]','江南黟歙千峰長，盤紆融結百鳥頏。',128,'全唐诗/poet.song.161000.json','["江南黟歙千峰長，盤紆融結百鳥頏。", "鍾靈孕秀山之玉，中有石墨時伏翔。", "曹公萬斤如贏糧，士龍二螺石髓香。", "人間那得掣筆郎，此物我亦成空囊。", "松煤僅貯陳玄光，磨楯未辦文檄梁。", "知公腹稿誇成章，夢中盈袖方櫝藏。", "仲將一點容升堂，佳哉秀句來一方。", "愧我學書臨池旁，幸公瓊報毋相忘。"]'),
('d8e7e9bd-0853-4fea-8a8f-76f7a35e082d','寄于忠父先生  其一','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天教英雄聲名好，滿眼看渠騰蹋早。',128,'全唐诗/poet.song.161000.json','["天教英雄聲名好，滿眼看渠騰蹋早。", "吁嗟世事暗如漆，虞卿窮困劉蕡老。", "平生翰墨彌九州，豐城埋劍干斗牛。", "一官了不受羈束，婆娑風月聊歸休。", "天欲成之煩一蹶，子美東屯笑耕月。", "諸山摇落不成林，看取孤松歲寒發。", "西湖十頃玻璃風，酒闌豪氣詩千筒。", "請君流水照冰雪，長魚豈與蝦蜆同。"]'),
('b5db8dd8-b70b-41ac-91b0-9ee6a2649d8c','寄于忠父先生  其二','袁說友','宋','宋诗','song-poetry','','[]','詩來已報平安好，猶恨得公詩不早。',128,'全唐诗/poet.song.161000.json','["詩來已報平安好，猶恨得公詩不早。", "忽聞單舸下滄浪，却喜此翁元未老。", "折腰耐辱來皇州，大手妙割無鷄牛。", "平生拄腹五千卷，百未一究真難休。", "我昔從之曾竭蹶，刮眼期公空歲月。", "老來猶足舉千鈞，豈是周郎獨英發。", "苕溪獵獵蘋花風，溪樓萬瓦如鋪筒。", "未須黄帽催歸去，尊酒一笑期君同。"]'),
('36e62d91-208d-47da-9a8e-d48fe965ed15','贈青眼楊相士','袁說友','宋','宋诗','song-poetry','','[]','秋風摵摵敲庭檟，獨卧孤窗類瘖瘂。',96,'全唐诗/poet.song.161000.json','["秋風摵摵敲庭檟，獨卧孤窗類瘖瘂。", "道人剝啄向東塘，欲識酸寒孟東野。", "公今以直不以情，我亦論心不論形。", "平生方寸只如此，政可煩公雙眼青。", "年來萬事翻成覆，幸有藏家書可讀。", "丁寧莫學世間癡，苦欲從公專問福。"]'),
('627a417e-d841-4962-aba7-ddbf13790da6','潜聖汪君辱借詩編作小詩歸之','袁說友','宋','宋诗','song-poetry','','[]','是客胸中春百頃，日夜葩花落毛穎。',96,'全唐诗/poet.song.161000.json','["是客胸中春百頃，日夜葩花落毛穎。", "奇芳珍艷亦不乏，綠賸紅餘盡桃杏。", "定收三冬充腹肆，那費五車壓牛領。", "不憂銅雀吻乾燥，正喜詩泉勢奔猛。", "舉檛聊作漁陽摻，成篇半是吳江冷。", "誰憂玄豹老雲霧，寒谷空濛光欲炳。"]'),
('a218271e-5784-429d-81b0-10a21e14f325','渡嘉陵江宿什邡驛','袁說友','宋','宋诗','song-poetry','','[]','山程十日不見江，前日初逢黎渡水。',96,'全唐诗/poet.song.161000.json','["山程十日不見江，前日初逢黎渡水。", "牽車又到渠江畔，漾漾翻波意尤美。", "今朝嘉陵江水寬，危峰大石更巑岏。", "棹兒艇子呼晚渡，亦刜鉦鼓推標竿。", "渡頭楓綠薔薇密，我宿山南雍城側。", "細思青史什邡侯，君恩何似嗟來食。"]'),
('490b0884-826d-4c10-82d4-d85ddb915e6c','過蝦蟆泉','袁說友','宋','宋诗','song-poetry','','[]','平生一壑清濯裳，愛泉謹護如隄防。',96,'全唐诗/poet.song.161000.json','["平生一壑清濯裳，愛泉謹護如隄防。", "酌飲爰至蝦蟆涪，水經第四源流長。", "天教神禹使壬甲，幻得蟾蜍半山壓。", "建瓴瀉出沆瀣清，底事汗流猶背浹。", "惠山車馬松江舟，兩泉寒冽天下求。", "不知此水更奇品，世間實處多名浮。"]'),
('9ee26c41-dd33-4c73-bed8-4b707d913659','過渠江渡','袁說友','宋','宋诗','song-poetry','','[]','櫂歌江峽三月程，頗厭風濤困征艣。',192,'全唐诗/poet.song.161000.json','["櫂歌江峽三月程，頗厭風濤困征艣。", "驅車山路兩旬浹，又覺崎嶇萃勞苦。", "甘溪嶺下冉村路，一道渠江拆山塢。", "風平雨細無皺面，浥浥寒漪清客暑。", "渡船也學鉦鼓聲，催上籃輿傍江滸。", "夷猶短檝瞥眼過，却懷江程久如許。", "山蹤水跡本遊戲，南北東西慣安處。", "茲行兩脚不遺力，千里環山幾艱阻。", "一江淼淼橫目前，如渴得泉旱得雨。", "流波聞向合州去，却入恭江匯西溆。", "便欲挾浪扁舟西，褰裳回首忻從之。", "君恩如天未酬一，一念惓惓繫孤跡。"]'),
('b5c13b42-d3c3-4d33-9547-ae006af27df7','過故郡渡','袁說友','宋','宋诗','song-poetry','','[]','山路一千三百里，中間四渡今江流。',64,'全唐诗/poet.song.161000.json','["山路一千三百里，中間四渡今江流。", "天涯作客壯年事，老馬長途幾日休。", "誰知江深念歸客，日向峨岷無盡頭。", "舉首白雲天共遠，四方上下與同愁。"]'),
('4f03dc36-53af-4b22-9611-3d0ae5850db9','過黄泥坂','袁說友','宋','宋诗','song-poetry','','[]','牽車緩上黄泥坂，複嶺重崗甚前日。',64,'全唐诗/poet.song.161000.json','["牽車緩上黄泥坂，複嶺重崗甚前日。", "躋攀千級下如之，十里三山三降陟。", "平生兩脚疲辛酸，歲晚行路熟蹣跚。", "人言蜀道如登天，未必登天如此難。"]'),
('74a30294-17f0-425c-9105-7c4a63d77e0d','登嘉州萬景樓','袁說友','宋','宋诗','song-poetry','','[]','我行大江西，勝槩數追逐。',200,'全唐诗/poet.song.161000.json','["我行大江西，勝槩數追逐。", "南樓岳陽上，雄絕快心目。", "今到西南第一樓，嗟哉餘子真碌碌。", "巖層嶂疊匝天外，蒲凈葭叢蘸江曲。", "三峩之雪晚在望，九頂之雲暗相矗。", "縈紆拱揖儼左右，吞吐澎湃環山腹。", "瀰瀰漭漭三萬頃，何止江郊供遠矚。", "俯觀大象欲墮地，仰摘星辰幾可掬。", "一天萬景不可狀，盡付此樓歸約束。", "危欄徙倚納清觀，蹁躚意已追鴻鵠。", "仙官五千九百到，我亦悠然立於獨。", "霧收江際天接水，日動山尖光漾木。", "倚樓拍手叫青天，一笑江橫送飛鶩。"]'),
('7ee0846c-bc76-4dc6-8112-c11686abd60f','舟行遇逆風','袁說友','宋','宋诗','song-poetry','','[]','扁舟直下滄浪綠，百里溪程消一宿。',96,'全唐诗/poet.song.161000.json','["扁舟直下滄浪綠，百里溪程消一宿。", "天公噓吸解窮人，逆水衝風何太酷。", "年來矻矻便深居，一動一靜誠何如。", "不堪世事苦相逼，政自未免奔走餘。", "今朝莫訝東風逆，明日歸舟順如翼。", "世間逆順豈關人，自是人心長戚戚。"]'),
('e3632ee0-1cf4-45af-9d87-eedf89a5b05a','過馬肝峽石形與色皆如馬肝迸出峭壁之上予觀之蓋石芝耳大窠一本小者四五不知風雨幾百載而質不敗賦石芝行','袁說友','宋','宋诗','song-poetry','','[]','巉巖復巉巖，昨日通靈灘。',164,'全唐诗/poet.song.161000.json','["巉巖復巉巖，昨日通靈灘。", "通靈二十里，有峽名馬肝。", "一山削壁立萬仞，中有突兀如芝蟠。", "輪囷累片葉，盤結分枝欒。", "宛然老枝菌，如出枯樹端。", "大窠數尺迸崖縫，小者四五高低攢。", "往來競稱馬肝石，不悟石芝爲異觀。", "朝廷日清明，郡國無曠官。", "鍾此溫厚氣，瑞草凝巑岏。", "不見爲羊又爲馬，石芝靈異元非難。", "此芝瑞峽中，一一行人看。", "何人果妙丹青手，便可圖上歸長安。"]'),
('c01e7ba3-02f1-4a52-956f-6a598803ad2e','舟人强以二鍰多取漁人之魚余增百錢與之作漁父行','袁說友','宋','宋诗','song-poetry','','[]','老父家住逢家洲，無田可種漁爲舟。',128,'全唐诗/poet.song.161000.json','["老父家住逢家洲，無田可種漁爲舟。", "春和夏炎網頭坐，茫茫不覺秋冬過。", "賣魚日不滿百錢，妻兒三口窮相煎。", "朝餐已了夕不飽，空手歸去蘆灣眠。", "今朝何人買鮮鯽，直得千錢酬二百。", "拋錢帆去了不譍，却謝君子爲增益。", "嗟嗟莫怨行路人，滿江風月儂最親。", "但看漁翁更强健，銀刀赤尾長鱗鱗。"]'),
('88e9c0d7-d5d9-4c28-a589-4f604ff76262','峽中瀑布泉','袁說友','宋','宋诗','song-poetry','','[]','萬石枕山眠，千峰隨路轉。',56,'全唐诗/poet.song.161000.json','["萬石枕山眠，千峰隨路轉。", "林深暝巖穴，一道寒泉濺。", "分明冰箒垂空壁，隠約珠簾掛蒼石。", "深山寂寞有誰知，只與行人潤詩筆。"]'),
('b7ec374e-79be-492f-bab8-abb52c11b798','孔明廟柏','袁說友','宋','宋诗','song-poetry','','[]','陵邱冉冉烟草新，叢祠寂寂君與臣。',64,'全唐诗/poet.song.161000.json','["陵邱冉冉烟草新，叢祠寂寂君與臣。", "千年不死一庭柏，八陣猶餘三峽春。", "昔人已化遼東鶴，古往今來事如昨。", "當年魚水奮雲龍，天不興劉死諸葛。"]'),
('797af90d-74ec-4d68-86ab-f5fd8f87a475','題天衣寺','袁說友','宋','宋诗','song-poetry','','[]','稽山道上多名蹟，萬頃湖光襯山色。',256,'全唐诗/poet.song.161000.json','["稽山道上多名蹟，萬頃湖光襯山色。", "雲蒸霧集累千年，屈指風流幾人物。", "平生佳處身曾經，頼此泉石供餘齡。", "愛山何惜買山費，明珠不博娉與婷。", "我聞天衣最奇絕，萬頃清凉掃煩熱。", "持經夜半鳥鼠聽，忽覩金僊起還滅。", "把茅從此成開山，法華妙果僧中賢。", "當時十詔徵不起，神奇變化泥生蓮。", "山神謹護泥封詔，獨有遺風傳內教。", "袈裟金縷照琉璃，時放祥光蔽雲物。", "我來官守無時閒，著脚未歷城南山。", "區區俗眼空自翳，耿耿此意如循環。", "我心豈是真如石，慙愧新詩與推激。", "自憐未到此山中，想見入山深未得。", "要令攻俗如攻城，茲遊約與秋風迎。", "吾曹豈辦癡兒事，爲君一醉南湖清。"]'),
('736a7c7e-e009-41eb-81d0-c832e0cf0e66','朱東父作室','袁說友','宋','宋诗','song-poetry','','[]','貪夫築室齊雲湄，滿溢既死不可持。',160,'全唐诗/poet.song.161000.json','["貪夫築室齊雲湄，滿溢既死不可持。", "佳哉高人世念薄，丈室緝綴如繭絲。", "門前流水照明月，門裏有詩清更絕。", "汲泉欲漱齒怯寒，携杖先登腰易劣。", "客不待速來往頻，剝啄扣門有誰譍。", "主人酌酒要客醉，坐客見花心自醒。", "長松古柏垂楊岸，爲萁一畝酒無算。", "花開詩酒足逢迎，花謝蝶蜂漫零亂。", "萬物榮枯付達觀，我欲從君著眼看。", "儻能剩掃床頭金，笑彼人間癡死漢。"]'),
('433e7fbf-30ea-4d80-bb04-ae20acad9d59','揚州堡寨','袁說友','宋','宋诗','song-poetry','','[]','西風一舸來揚州，疋馬直上新城頭。',293,'全唐诗/poet.song.161000.json','["西風一舸來揚州，疋馬直上新城頭。", "環城九里十六步，一一峭壁臨深溝。", "俄焉唯喏兩軍士，衆手指示陳其由。", "揚鞭試問築城意，曰堡曰寨何所謀。", "誦言長淮十六郡，天險地利茲其尤。", "江橫萬里限南北，藉此屏翰屯咽喉。", "向來强敵蹈此境，夜半一叱遭虔劉。", "平疇曠野不可限，一城未足防侵牟。", "高城西北古城後，因勢决策成楚丘。", "四門大開樓櫓備，中有萬甲藏戈矛。", "譬如一鎧何足恃，被之重鎧前無憂。", "乃知舊臣建議僅出此，我亦策馬嗟去休。", "不知城二勢則一，添足畫蛇真贅疣。", "君不見紫巖先生昔經理，釣橋深塹先防秋。", "當時方略豈不究，而使浪策爲今羞。", "吁哉成事不復說，只恐說計無時酬。", "書生銜命偶經履，一見敢謂可與不。", "世間萬事一笑裏，輕帆送我催行舟。"]'),
('aff03c79-62b9-48ca-92f5-96e9848ed805','題陳日華二友堂','袁說友','宋','宋诗','song-poetry','','[]','書生作吏從朱墨，官事紛紛何日息。',96,'全唐诗/poet.song.161000.json','["書生作吏從朱墨，官事紛紛何日息。", "不堪鴈鶩對敲朴，寧解詩書伴松竹。", "太丘退食何蕭然，筆研不落塵埃邊。", "前歲讀書山水縣，今年二友來通川。", "料君捧詔還朝日，老蓋寒梢應的皪。", "此時留與後人看，要使清風繼前跡。"]'),
('b75d6d8c-4251-4ae1-8202-e438e3e04550','送陳景齋宰鉛山','袁說友','宋','宋诗','song-poetry','','[]','我昔曾爲江左國，賸說鵝湖今壯邑。',96,'全唐诗/poet.song.161000.json','["我昔曾爲江左國，賸說鵝湖今壯邑。", "頻年官府苦催科，百里齊民猶珥筆。", "男兒遇事難是圖，猛士縛獸須於菟。", "才高政不較難易，知公此去無趦趄。", "嗟予仰韓如仰斗，公亦登門及予否。", "爲言饑餓六年中，兩眼猶能記千首。"]'),
('bb93a5f6-e71f-46a5-8117-7746ee6df7b9','送周可大守通州','袁說友','宋','宋诗','song-poetry','','[]','丈夫憂國如憂身，疴癢疾痛均傷生。',336,'全唐诗/poet.song.161000.json','["丈夫憂國如憂身，疴癢疾痛均傷生。", "胸中百藥寒凉明，有疾一試真權衡。", "我觀周郎真豪英，落落磊磊通而清。", "少年志欲天下平，夜光無因匹夫驚。", "萬卷堆胸兀相撐，尚論千載欣談兵。", "不堪北首瞻神京，抵掌不平中屢鳴。", "老來符竹疏新榮，捧檄正須堪一行。", "舌翻衮衮傾波瀛，察譏之說何鏗鍧。", "龍頭悅懌意若迎，領略健論心爲傾。", "朱轓好去方北征，黄堂暇日煩經營。", "老狐戀戀巢穴成，兩雛競鬭誇紛爭。", "料公志略須縱橫，邊塵一洗誅長鯨。", "片言定可攻聊城，覆巢熏穴無餘氓。", "牢盆細務毋太縈，簿書期會毋留情。", "只今了却功與名，大副昔年梁楚聲。", "我來蹤跡水上萍，與公相望幾連甍。", "交情契合踰弟兄，頡頏上下相嘲評。", "有時立論披腹呈，彼此浩氣俱崢嶸。", "公今事業行軒轟，我懷礧磈方聾盲。", "願公不負忠與誠，歸來闊步名公卿。", "願我百念一羽輕，公乎訪我惟巖耕。"]'),
('bff23a2b-22a7-4892-9eee-3912c4f5106e','送王齊卿教授造朝','袁說友','宋','宋诗','song-poetry','','[]','江浄孤月寒，山空野梅白。',56,'全唐诗/poet.song.161000.json','["江浄孤月寒，山空野梅白。", "我是天涯人，却送東行客。", "送君直上蓬山首，莫忘西南困征取。", "功名富貴不須多，只把詩書垂不朽。"]'),
('6a5d0fec-ec4b-4b5f-9b34-fb574df68370','寄中都故人','袁說友','宋','宋诗','song-poetry','','[]','千山疊疊高入天，中有縹緲之神仙。',64,'全唐诗/poet.song.161000.json','["千山疊疊高入天，中有縹緲之神仙。", "壁立煙容風虎卧，林深洞啟雲龍潜。", "長安詩翁有健筆，蜀道客子無新篇。", "尺書萬里寄天遠，萬一故人曾我憐。"]'),
('0ffe3dec-3ddf-4856-9071-203b2ce1f88b','用楊誠齋韻題吳夢與集','袁說友','宋','宋诗','song-poetry','','[]','大鈞落落元無鉤，百尺空卧元龍樓。',64,'全唐诗/poet.song.161000.json','["大鈞落落元無鉤，百尺空卧元龍樓。", "天生斯人竟何用，摇筆僅可供眉愁。", "詩人慣作驚人語，富貴迫人嗟幾許。", "世間萬事要其終，只今此道猶能東。"]'),
('c36ab929-5695-4b9f-b833-f5dcf73687e2','陳日華刪定讀書林','袁說友','宋','宋诗','song-poetry','','[]','雄編已汗南山竹，對坐松篁誇鼎足。',64,'全唐诗/poet.song.161000.json','["雄編已汗南山竹，對坐松篁誇鼎足。", "猶嫌官事作癡兒，故向書林巧徵逐。", "蒼龍宛轉鱗之而，此君寂寞清且高。", "晚來鴈鶩無人進，又報明公欲變騷。"]'),
('dafab55b-1218-4140-99e9-013526ec2e3e','題王順伯秘書所藏蘭亭修禊帖','袁說友','宋','宋诗','song-poetry','','[]','永和九年暮春日，蘭亭修禊羣賢集。',388,'全唐诗/poet.song.161000.json','["永和九年暮春日，蘭亭修禊羣賢集。", "含毫欲下意已先，媚日暄風佐摇筆。", "當時一筆三百字，但說斯文感今昔。", "誰知已作尤物看，流傳人間天上得。", "天高地遠閟不示，僅許一二翻摹勒。", "忽然飛上白雲俱，徑入昭陵陪玉骨。", "識真之士已絕少，真者一去嗟難覓。", "紛紛好事眼空眩，只把殘碑慕真迹。", "蕭郎袖去明真贋，定武傳來差甲乙。", "如丁如爪辨形似，不豐不露分肥瘠。", "人亡無復見風流，漫費精神疲得失。", "臨川先生天下士，古貌古心成古癖。", "搜奇日富老不厭，如渴欲飲饑欲食。", "有時瞥眼道傍見，倒屣迎之如不及。", "牙籤軸已過三萬，集古錄多千卷帙。", "平生著意右軍處，並蓄兼收一何力。", "賞音本在筆墨外，何必此優而彼劣。", "清波萬頃渾一點，明月一輪雲半入。", "是中元不礙真趣，氣象典刑尤歷歷。", "知我罪我春秋乎，政爾未容言語直。", "我方隨羣厚其嗜，門戶弗彊纔僅立。", "幾年冥搜政無那，剩欲流涎分半席。", "閲公善本三四五，不覺長歌書卷側。", "羲之死矣空費公家九萬箋，安得斯人寫金石。"]'),
('a908f392-d1e7-40bf-9269-fc51768efd9e','十月雪四白','袁說友','宋','宋诗','song-poetry','','[]','夜來風絮鳴觚稜，紛紛消息何頻仍。',128,'全唐诗/poet.song.161000.json','["夜來風絮鳴觚稜，紛紛消息何頻仍。", "不堪十月已四白，豈暇一歲誇三登。", "祁寒未必小民怨，哭雪政恐樵夫憎。", "窮閻冷市糴貴穀，破竈濕葦燒層冰。", "寒窗又凍詩翁筆，清夜誰憐貧婦織。", "人言宜瑞不宜多，官放論錢不論日。", "請君高吟祈碧蒼，願天今夕開扶桑。", "寄語龍公且相卹，忍待明年莫倉卒。"]'),
('6518c251-af67-4ab4-96b4-1fce11967c98','傚東坡從歐陽公詠雪體不用鹽玉鶴鷺絮蝶飛舞爲比不使皓白潔素等字','袁說友','宋','宋诗','song-poetry','','[]','樓頭一夜寒聲促，但怪重衾慣藏六。',240,'全唐诗/poet.song.161000.json','["樓頭一夜寒聲促，但怪重衾慣藏六。", "小窗起聽枯葉鳴，更覺凝寒透肌粟。", "乃知龍公修故事，幻作輕細巧翻覆。", "摶空積勢欺簷楹，過眼隨風滿坑谷。", "雲濤衮衮浩無際，頃刻庭前三萬斛。", "小山愛我已霜鬢，老盡蒼崖垂布瀑。", "兒童愛雪不愛身，堆削形橅笑盈掬。", "風梢嫋娜困無奈，一一扶頭恣敲朴。", "我來苕霅四寒暑，破漏憐渠數間屋。", "無人推戶起僵卧，漫把清風繼前躅。", "寒爐夜撥終不焰，凍筆呵吟已先禿。", "人間憂樂有定分，隣家乃奏琵琶曲。", "回飈落屑點翠袖，紛紛花映花奴肉。", "杜陵老眼不禁寒，只有詩筒再三讀。", "請君早辦雪兒歌，喚取詩翁醉醽醁。"]'),
('2b7dd55e-20d4-4fc5-af7d-33bec2c92f90','雪中簡林子長','袁說友','宋','宋诗','song-poetry','','[]','玉沙飛墮何衮衮，一夜青山損顔色。',96,'全唐诗/poet.song.161000.json','["玉沙飛墮何衮衮，一夜青山損顔色。", "此山底事厭青姿，故學何郎輕傅粉。", "曉來窗戶何人開，僵卧欲起驚皚皚。", "微風淅瀝捲還起，片片直上雙毛來。", "扁舟賸欲敲鄰屋，料得羔羊酒初熟。", "瓊瑶欲盡不可留，梁園歌吹須君侯。"]'),
('e8ea421a-0888-4b36-8cbf-157120bf8471','巫山十二峰二十五韻','袁說友','宋','宋诗','song-poetry','','[]','巫山磊塊山林姿，一邱一壑貪成癡。',394,'全唐诗/poet.song.161000.json','["巫山磊塊山林姿，一邱一壑貪成癡。", "寸峰拳石瞥眼過，張皇攫覓惟憂遲。", "東南佳山多秀麗，就中所欠雄與奇。", "飽聞巫山冠巴峽，奇峰十二相參差。", "昔年圖畫常一見，欲見此山無路之。", "扁舟西泝上三峽，千巖萬壑爭追隨。", "終朝應接已不暇，心目洞駭俱忘疲。", "驀然鐘鼓高唐上，峰巒二六排旌旗。", "一峰霞彩迥在望，一峰展翠開屏帷。", "無心出岫雲吐色，偃蓋平巒松並枝。", "仙蹤鶴駕羽衣近，壇石瑶臺閶闔低。", "白雲一起鳳皇下，清泉四合蛟龍嬉。", "羣峰角立變態異，一一大巧乾坤爲。", "外堪擊拊試聲律，中含造化分四時。", "天下名山亦多矣，未有列岫奇如茲。", "九華一景固天巧，惜與江流相背馳。", "南北兩峰喧衆口，妝抹却恨同西施。", "何如此峰無限好，行行列列臨江湄。", "烟雲漠漠出寸碧，風雨時時橫黛眉。", "舟人漁子漫回首，騷士墨客勞支頤。", "我來穿水入天去，貂裘章甫生塵緇。", "昂頭見此大奇特，躋攀不上空嗟嘻。", "吾將欲訪三島登九嶷，上蓬萊道山之壁，絕泰華終南之嵋。", "飛鳬去舄嘯滄海，却來巫峽溫前詩。"]'),
('8a9456d2-7998-4d3d-ad38-5acdec637340','喜晴放海棠','袁說友','宋','宋诗','song-poetry','','[]','春日海棠早，媚雲開遠嵐。',48,'全唐诗/poet.song.161000.json','["春日海棠早，媚雲開遠嵐。", "醉容猶未足，睡態已微酣。", "嫩綠千枝襯，殷紅一點含。", "東君真有助，落筆爲渠談。"]'),
('98989e20-9520-4f6d-89a7-588f53590dcc','常通判惠虞美人花亦名雙魚兒花','袁說友','宋','宋诗','song-poetry','','[]','好景無窮巷，名園有異姿。',48,'全唐诗/poet.song.161000.json','["好景無窮巷，名園有異姿。", "春今十分好，花又一番奇。", "比目紅綃結，雙魚碧玉枝。", "孤窗還遣伴，空憶美人詞。"]'),
('7b273d55-b6e7-49b6-9205-4a6be0a43e9c','盆池荷花','袁說友','宋','宋诗','song-poetry','','[]','根向盆池束，華敷菡萏叢。',48,'全唐诗/poet.song.161000.json','["根向盆池束，華敷菡萏叢。", "細擎深院宇，低裊半窗風。", "蘸水凝綃翠，當軒試臉紅。", "化工雖力淺，猶折小蓮蓬。"]'),
('418f0d7d-1cf8-4d46-827a-66d726186444','石上玉簪花','袁說友','宋','宋诗','song-poetry','','[]','根齧稜稜石，香銜寸寸心。',48,'全唐诗/poet.song.161000.json','["根齧稜稜石，香銜寸寸心。", "誤人猜落蕊，眩眼拾遺簪。", "掬水滋繁種，柔枝倚短岑。", "清姿浮玉潤，不受暗塵侵。"]'),
('89a38052-45e3-4d0a-b7d0-11efa7b7ef5c','植花於假山','袁說友','宋','宋诗','song-poetry','','[]','巖石稜稜巧，盆池淺淺開。',48,'全唐诗/poet.song.161000.json','["巖石稜稜巧，盆池淺淺開。", "空山初幻化，方丈小飛來。", "屈曲清泉溜，參差細草栽。", "只今山在眼，著眼便徘徊。"]'),
('1a9ae1a0-1d47-4717-be33-3d682023ce91','石上水蕉','袁說友','宋','宋诗','song-poetry','','[]','傍石根斜綴，澄波葉半舒。',48,'全唐诗/poet.song.161000.json','["傍石根斜綴，澄波葉半舒。", "氣涵流水潤，冷徹內心虛。", "带月軒窗外，凝藍雨露餘。", "憑將摩詰畫，雪裏細尋渠。"]'),
('f6111df5-dbfc-4a9f-9513-5d8b471422cc','和林子長種菰韻','袁說友','宋','宋诗','song-poetry','','[]','城郭千林靜，菰蒲二頃宜。',48,'全唐诗/poet.song.161000.json','["城郭千林靜，菰蒲二頃宜。", "移根元不費，殖利已先知。", "僅脫黄泥賤，相從白玉炊。", "平生慣藜藿，於此羨耘耔。"]'),
('be7ceb49-bdd1-4882-84df-14274abf25e9','屋後植竹','袁說友','宋','宋诗','song-poetry','','[]','穩袖三年手，新鋤十丈園。',48,'全唐诗/poet.song.161000.json','["穩袖三年手，新鋤十丈園。", "傍山移早筀，掃徑斸孤根。", "瑣碎梢頭影，凄凉竹外村。", "可人風月地，頭角見龍孫。"]'),
('7f65d729-6a40-4853-bd1d-5360ed01cf45','丹桂','袁說友','宋','宋诗','song-poetry','','[]','月窟分僊種，人間識此花。',48,'全唐诗/poet.song.161000.json','["月窟分僊種，人間識此花。", "十分晴殢酒，一抹晚呈霞。", "曉鏡勻丹臉，香肌挹絳紗。", "相看秋色凈，獨映夕陽斜。"]'),
('7b3588ca-7b5e-4945-9daa-2a963be7d044','水竹','袁說友','宋','宋诗','song-poetry','','[]','拳石環清泚，龍鬚細屈蟠。',48,'全唐诗/poet.song.161000.json','["拳石環清泚，龍鬚細屈蟠。", "兩峰低峍崒，一簇小琅玕。", "密葉風前影，疎枝水底寒。", "相從此君爾，著意問平安。"]'),
('9d7bb95f-f507-4500-8bc2-f3debf1e9166','楊梅','袁說友','宋','宋诗','song-poetry','','[]','酒著圓腮重，珠聯細葉芳。',48,'全唐诗/poet.song.161000.json','["酒著圓腮重，珠聯細葉芳。", "絳紗籠蜜顆，朱粉皺新粧。", "色漬桑間椹，甘傅荔子漿。", "輕酸認梅種，草木有他楊。"]'),
('26e6dbe1-8f73-4f6e-a43b-357734b3ce81','莫子章惠蒲萄','袁說友','宋','宋诗','song-poetry','','[]','慣病宜秋早，分甘荷歲寒。',48,'全唐诗/poet.song.161000.json','["慣病宜秋早，分甘荷歲寒。", "驪珠初壓架，馬乳又堆盤。", "酒美誇重醒，書成欠百端。", "不須煩廣利，移種眩長安。"]'),
('d9919d59-1a23-44b8-bf23-acb29bdb72f2','謝周唐卿分惠宣梨二首  其一','袁說友','宋','宋诗','song-poetry','','[]','啄木門初扣，分甘味占高。',48,'全唐诗/poet.song.161000.json','["啄木門初扣，分甘味占高。", "風標誇飣坐，津潤憶流膏。", "賸受千梨戶，寧辭五藏刀。", "一杯須領意，老欲爲渠饕。"]'),
('0cd7130f-42d1-42b6-9c9d-233ee08cb842','謝周唐卿分惠宣梨二首  其二','袁說友','宋','宋诗','song-poetry','','[]','澹澹夕陽遠，行秋塞鴈高。',48,'全唐诗/poet.song.161000.json','["澹澹夕陽遠，行秋塞鴈高。", "卷舒連夜燭，長短幾檠膏。", "貧豈嗟懸磬，家猶及賣刀。", "藜腸慣羞澀，更覺近來饕。"]'),
('6fdddab3-2cbe-4a38-91d0-08a601d1da29','周可大惠崑崙桃','袁說友','宋','宋诗','song-poetry','','[]','秋雨成蕭瑟，緗桃辱記存。',48,'全唐诗/poet.song.161000.json','["秋雨成蕭瑟，緗桃辱記存。", "品高來禁籞，地遠想崑崙。", "幸有千年實，愁無五石樽。", "欲修瓊玖報，素手愧空言。"]'),
('3fc11ef9-c04d-427f-82ae-40bfffc23744','謝侃老惠乳糕','袁說友','宋','宋诗','song-poetry','','[]','多病柘漿酒，閒愁梅雨天。',48,'全唐诗/poet.song.161000.json','["多病柘漿酒，閒愁梅雨天。", "婆娑清夢斷，剝啄好音傳。", "憐我虀鹽薄，從渠乳酪鮮。", "莫嗟聞道晚，著意問師禪。"]'),
('e6b42032-fa26-4e4e-8f18-f2b2e29a98ac','嘗顧渚新茶','袁說友','宋','宋诗','song-poetry','','[]','碧玉團枝種，青山擷草人。',48,'全唐诗/poet.song.161000.json','["碧玉團枝種，青山擷草人。", "先春迎曉至，未雨得芽新。", "雲疊槍旗細，風生齒頰頻。", "何人修故事，香味徹楓宸。"]'),
('61691d99-e07a-4057-9cce-14a9fc5574c2','惠相之惠顧渚芽答以建茗','袁說友','宋','宋诗','song-poetry','','[]','一室環三徑，諸郎讀五車。',48,'全唐诗/poet.song.161000.json','["一室環三徑，諸郎讀五車。", "山高空鎖翠，澗闊自流花。", "輟我閩山焙，酬君顧渚芽。", "書來驚歲晚，老去各天涯。"]'),
('5f4020c6-976f-4bb2-96b5-cf5657ffbf54','鬬茶','袁說友','宋','宋诗','song-poetry','','[]','截玉誇私鬭，烹泉測嫩湯。',48,'全唐诗/poet.song.161000.json','["截玉誇私鬭，烹泉測嫩湯。", "稍堪膚寸舌，一洗莧藜腸。", "千枕消魔障，春芽敵劍鋩。", "年年較新品，身老玉甌嘗。"]'),
('f9993e10-83c7-4608-be10-98d7999195a9','遺建茶於惠老','袁說友','宋','宋诗','song-poetry','','[]','東入吳中晚，團龍第一匳。',48,'全唐诗/poet.song.161000.json','["東入吳中晚，團龍第一匳。", "政須香齒頰，莫慣下薑鹽。", "笑我便搜攪，從君辨苦甜。", "更煩揮妙手，銀粟看纖纖。"]'),
('c1537968-5200-43da-a5f3-b45122f3b2f5','沈無隠國正惠殿廬所賜香茶','袁說友','宋','宋诗','song-poetry','','[]','公論歸吾黨，平生只故人。',48,'全唐诗/poet.song.161000.json','["公論歸吾黨，平生只故人。", "近書時遣况，舊雨日相親。", "茶輟閩山貢，香分御府珍。", "須公文石陛，回首霅溪濱。"]'),
('9ba720a3-9691-4e2e-9ac8-49918e760dc9','謝吳斗南教授惠貢茶','袁說友','宋','宋诗','song-poetry','','[]','我愧周行久，君方戴席重。',48,'全唐诗/poet.song.161000.json','["我愧周行久，君方戴席重。", "一緘馳素繭，五玉卧烏龍。", "滴雪浮甌淺，濡香過齒濃。", "欲酬新句好，官事正填胸。"]'),
('ae64fa5e-7f5f-4c8e-9e87-7f6748fe08d2','謝葉秀州惠酒','袁說友','宋','宋诗','song-poetry','','[]','雅况尊罍重，高情翰墨餘。',48,'全唐诗/poet.song.161000.json','["雅况尊罍重，高情翰墨餘。", "寒窗半杯醁，老眼數行書。", "舊雨故人少，因風來雁疎。", "君侯獨懷舊，一歲幾相於。"]'),
('b714e372-f749-42d8-8389-d3366f038b92','晚春過雨','袁說友','宋','宋诗','song-poetry','','[]','酒惡病成惱，春深愁轉加。',48,'全唐诗/poet.song.161000.json','["酒惡病成惱，春深愁轉加。", "園林三月事，風雨一庭花。", "燕幕自相語，蜂屯爭趁衙。", "傍欄迎霽色，溪上幾人家。"]'),
('b76bc0c3-4a45-4e63-b43d-c33bb4e34960','梅雨踰月始晴甫兩日復大雨','袁說友','宋','宋诗','song-poetry','','[]','猛作連朝雨，愁添一尺溪。',48,'全唐诗/poet.song.161000.json','["猛作連朝雨，愁添一尺溪。", "頹雲驚滿坐，漲水急平堤。", "澤國幾成壑，田家未半犁。", "關心獨朝暮，剛認勃姑啼。"]'),
('7d84609b-2f6e-4257-95ae-f3a72bc47dd9','和林子長池上聽雨韻','袁說友','宋','宋诗','song-poetry','','[]','遠浦鳴疎雨，平林送落暉。',48,'全唐诗/poet.song.161000.json','["遠浦鳴疎雨，平林送落暉。", "霏煙青柳暗，晚霽白鷗歸。", "觸目懷心賞，憑川念昔非。", "池塘消息近，一笑莫身違。"]'),
('c33af351-1bc8-4c5c-8d1d-ec51adaef6aa','歸舟遇大風雨','袁說友','宋','宋诗','song-poetry','','[]','客裏纔三日，歸來僅一程。',48,'全唐诗/poet.song.161000.json','["客裏纔三日，歸來僅一程。", "片雲天外立，短棹雨中行。", "小却黄昏路，猶須半夜晴。", "春光又零落，游子不勝情。"]'),
('2dbdfa87-bac0-42dc-aad9-99d7fdfb376d','夏至日雨','袁說友','宋','宋诗','song-poetry','','[]','煙暝千巖木，溪明一带樓。',48,'全唐诗/poet.song.161000.json','["煙暝千巖木，溪明一带樓。", "片雲封舊恨，急雨罥新愁。", "節又匆匆過，詩從軋軋抽。", "病軀無耐暑，老鬢不禁秋。"]'),
('c7dc50c5-35a0-49c5-882f-5f7360742804','暑雨','袁說友','宋','宋诗','song-poetry','','[]','獵獵蒲欹岸，斑斑蘚漬牆。',48,'全唐诗/poet.song.161000.json','["獵獵蒲欹岸，斑斑蘚漬牆。", "簷低泣蛛網，葉落濺蜂房。", "西嶂暮凝色，北窗新送凉。", "晚來池上過，風擘藕花香。"]'),
('cedff1f4-7313-440f-8802-e12ae2c049b4','溽暑雨後','袁說友','宋','宋诗','song-poetry','','[]','多病愁如許，催人暑奈何。',48,'全唐诗/poet.song.161000.json','["多病愁如許，催人暑奈何。", "簷窮風有限，雲薄雨無多。", "浪捲連村麥，珠旋小葉荷。", "炎凉苦多變，四月未清和。"]'),
('59cac62b-6349-457a-886b-cd80e5ba5256','雨中即事','袁說友','宋','宋诗','song-poetry','','[]','夜雨恰一尺，新秧高九分。',48,'全唐诗/poet.song.161000.json','["夜雨恰一尺，新秧高九分。", "煙深數峰暗，澗急滿山聞。", "蒼蔚添新翠，溟濛藹暮雲。", "田家方樂歲，泥淖也忘勤。"]'),
('8057a4ad-e0e4-4a3d-8237-e4e3476b19f2','喜晴','袁說友','宋','宋诗','song-poetry','','[]','夢斷窗全曙，兒童競報晴。',48,'全唐诗/poet.song.161000.json','["夢斷窗全曙，兒童競報晴。", "層雲擘輕絮，飛鵲噪新聲。", "一水長天靜，雙溪萬櫓鳴。", "傍簷聊覓句，樂處漫蠅營。"]'),
('f743d502-bcb4-4ec8-bbdd-80f130fe2ea3','久雨霽後見月','袁說友','宋','宋诗','song-poetry','','[]','漲水橫侵屋，輕舟半宿溪。',48,'全唐诗/poet.song.161000.json','["漲水橫侵屋，輕舟半宿溪。", "竹風千影亂，簾月一鈎低。", "鼠黠欺殘照，鴉啼識故棲。", "餘樽纔稍稍，薄露已凄凄。"]'),
('6de5be13-ee9a-4005-b756-349f5f4d8aca','暑夜得月','袁說友','宋','宋诗','song-poetry','','[]','風攪桐聲碎，螻鳴鼓吹長。',48,'全唐诗/poet.song.161000.json','["風攪桐聲碎，螻鳴鼓吹長。", "半山蟾吐影，一水鑑浮光。", "冷碧迎秋色，清飈借久凉。", "不堪鷄唱曉，歸枕報朝陽。"]'),
('8f297a1d-8e71-4060-94cb-11fcebe65d22','登屋後城','袁說友','宋','宋诗','song-poetry','','[]','笑傲愁如失，登臨酒半醒。',48,'全唐诗/poet.song.161000.json','["笑傲愁如失，登臨酒半醒。", "故將雙眼碧，割斷半山青。", "土沃差宜竹，城高未著亭。", "可人東郭外，綃翠舞娉婷。"]'),
('4b247696-0295-4e31-89a4-4102a90c8f91','雙溪亭','袁說友','宋','宋诗','song-poetry','','[]','源委縈苕霅，乾坤接水雲。',48,'全唐诗/poet.song.161000.json','["源委縈苕霅，乾坤接水雲。", "半天孤月照，兩派一溪分。", "日落虹垂影，魚翻縠斷紋。", "煙波豈無義，涇渭固難羣。"]'),
('41a9ec75-f01a-47de-969d-c1e7d3e922bd','題小隠九曲亭','袁說友','宋','宋诗','song-poetry','','[]','小隠前山入，空亭往事忙。',48,'全唐诗/poet.song.161000.json','["小隠前山入，空亭往事忙。", "放泉盃曲水，環坐客流觴。", "雅不尋絲竹，歸宜釂酒漿。", "山陰莫專美，更數水雲鄉。"]'),
('848be83c-0e9d-4f5c-8880-d6c029cea5ff','題墨妙亭','袁說友','宋','宋诗','song-poetry','','[]','繭紙奇蹤絕，龜趺古意長。',48,'全唐诗/poet.song.161000.json','["繭紙奇蹤絕，龜趺古意長。", "憐渠風雨厄，爲爾屋廬藏。", "寂寂閒庭靜，迢迢永晝忙。", "傷心三廢碣，猶識漢文章。"]'),
('116ffedf-2f78-4c53-947b-07d6ca37d5af','白蘋亭','袁說友','宋','宋诗','song-poetry','','[]','苕水誇空闊，蘋花笑泬寥。',48,'全唐诗/poet.song.161000.json','["苕水誇空闊，蘋花笑泬寥。", "樓臺溪上女，楊柳岸邊橋。", "凉月明烟渚，春水稱畫橈。", "晚來魚一躍，带雨識魚跳。"]'),
('86cdc64a-070c-4e6e-b6e3-5fb132a05d28','北園','袁說友','宋','宋诗','song-poetry','','[]','菡萏暑風曉，芙蕖秋露時。',48,'全唐诗/poet.song.161000.json','["菡萏暑風曉，芙蕖秋露時。", "青山無限好，明月故相宜。", "雨長穿城竹，湖深隔岸池。", "春堂夜留客，舉首問南箕。"]'),
('329e8300-a0c6-4a9a-9cfa-0c81f5c403b1','水西葉氏園','袁說友','宋','宋诗','song-poetry','','[]','風月欲在眼，園林須傍家。',48,'全唐诗/poet.song.161000.json','["風月欲在眼，園林須傍家。", "崚嶒飛翠巘，颭灧舞綃花。", "門近山光入，堂深樹影斜。", "猶將小西景，更爲石林誇。"]'),
('74ae8176-31c3-41cb-9c71-d1461301f4f1','俞氏園','袁說友','宋','宋诗','song-poetry','','[]','好景環深院，名園得故家。',48,'全唐诗/poet.song.161000.json','["好景環深院，名園得故家。", "樓高春带月，池曲曉催花。", "亭著城頭穩，溪浮眼界賒。", "成陰雖歲月，老樹看槎牙。"]'),
('18cdab86-1460-4e31-a6d2-b1fb44fe6c33','王氏山居','袁說友','宋','宋诗','song-poetry','','[]','豆粥通幽徑，松杉蔽野門。',48,'全唐诗/poet.song.161000.json','["豆粥通幽徑，松杉蔽野門。", "眼空樓外碧，身落洞前村。", "荷靜風巖曉，梅開雪月昏。", "環山書未捲，林薄鳥聲喧。"]'),
('1a848894-c49f-46b4-bcf3-2f08ccf880dd','六客堂','袁說友','宋','宋诗','song-poetry','','[]','山水吳興窟，風流一代雄。',48,'全唐诗/poet.song.161000.json','["山水吳興窟，風流一代雄。", "滿城溪月裏，六客笑談中。", "玉骨埋黄陌，雲書掛碧空。", "聲名百年舊，無復二三公。"]'),
('c1c478a4-bf19-4821-b458-158c5f516abf','碧瀾堂','袁說友','宋','宋诗','song-poetry','','[]','照影瀾飛碧，臨深雨過凉。',48,'全唐诗/poet.song.161000.json','["照影瀾飛碧，臨深雨過凉。", "夜橫千櫂月，冷浸一溪堂。", "魚躍翻寒藻，鷗閒戲夕陽。", "百年數行客，幾度落危檣。"]'),
('b7f94c00-2004-42b7-bab7-94c6f24caa62','題顔魯公懷忠堂','袁說友','宋','宋诗','song-poetry','','[]','羽化仙家久，祠嚴霅水東。',48,'全唐诗/poet.song.161000.json','["羽化仙家久，祠嚴霅水東。", "一身終許國，千載獨懷忠。", "徙倚豐碑舊，瞻依古像雄。", "堂堂祭如在，從祀有坡公。"]'),
('bddebfd4-d9c5-42a6-91c7-6ef23f172485','慈感寺','袁說友','宋','宋诗','song-poetry','','[]','門近滄浪水，堂深泰華蓮。',48,'全唐诗/poet.song.161000.json','["門近滄浪水，堂深泰華蓮。", "光芒珠一粟，相貌佛諸天。", "樹老半無葉，僧閒誰問禪。", "雨暘須大士，澤國屢豐年。"]'),
('cd5f0620-8688-403e-8a3f-2b35ca802fa9','遊慈感寺用壁間趙安石韻','袁說友','宋','宋诗','song-poetry','','[]','薄俗冷還暖，餘年春復秋。',48,'全唐诗/poet.song.161000.json','["薄俗冷還暖，餘年春復秋。", "詩窮無限意，身老半生愁。", "飽睡書慵展，居閒客强留。", "功名羞鏡裏，白髮奈盈頭。"]'),
('2bbb8d09-3910-4d46-8101-d7fe2ee5d752','慈感寺放生','袁說友','宋','宋诗','song-poetry','','[]','生滅成宗劫，慈悲種善因。',48,'全唐诗/poet.song.161000.json','["生滅成宗劫，慈悲種善因。", "紛紛嗟蠢動，一一付波臣。", "物我形聲異，人禽愛惡均。", "不堪明月夜，小艇擲絲綸。"]'),
('6be05df9-d2ee-4164-8fe9-93085a9d977b','慈感寺四月八日浴佛會','袁說友','宋','宋诗','song-poetry','','[]','一剎傳經地，諸天誕佛辰。',48,'全唐诗/poet.song.161000.json','["一剎傳經地，諸天誕佛辰。", "猶將清浄水，更浴涅盤身。", "居士應無垢，菩提各有因。", "要須憑苦海，萬里滌情塵。"]'),
('f8420302-c2e7-46cf-af67-ba0268939c23','同周可大莫子章同遊證通寺','袁說友','宋','宋诗','song-poetry','','[]','好友頻相過，閒愁一笑忘。',48,'全唐诗/poet.song.161000.json','["好友頻相過，閒愁一笑忘。", "逶迤蕭寺徑，淡薄老僧房。", "飽飯溪山足，空門日月長。", "歸來懷妙語，心地轉清凉。"]'),
('a1f671c5-9457-4454-9b1b-5d25c192f112','天寧寺有白石曰卞山脚石上多名公題識','袁說友','宋','宋诗','song-poetry','','[]','隠隠來崗續，沈沈土脈縈。',48,'全唐诗/poet.song.161000.json','["隠隠來崗續，沈沈土脈縈。", "一峰庭下立，十里地中行。", "石脚猶依佛，山腰恰近城。", "摩挱嗟歲月，風雨幾題名。"]'),
('0d289be7-aa40-4bf1-ae8f-e5c3dceedfca','侃老捨天寧寺往遊何道二山二首  其一','袁說友','宋','宋诗','song-poetry','','[]','拍手笑無語，挑包去不還。',48,'全唐诗/poet.song.161000.json','["拍手笑無語，挑包去不還。", "行行餘一鉢，歷歷上諸山。", "明月隨方照，孤雲任意閒。", "猊床待師處，猿鳥撤松關。"]'),
('f85b2af1-916b-4ad4-a896-95e20d6c7e2b','侃老捨天寧寺往遊何道二山二首  其二','袁說友','宋','宋诗','song-poetry','','[]','飛錫真游戲，論詩解往還。',48,'全唐诗/poet.song.161000.json','["飛錫真游戲，論詩解往還。", "一聲獅子吼，十里道場山。", "綠竹靜無語，白雲長自閒。", "趙州應路滑，無復嘆間關。"]'),
('f5dd94fc-0ce9-4eb2-91c0-c5ead424d276','遊清凉寺逢說命者傅會云帥垣星照西方','袁說友','宋','宋诗','song-poetry','','[]','奔走纔千里，辛勤說五行。',48,'全唐诗/poet.song.161000.json','["奔走纔千里，辛勤說五行。", "星躔初下照，君命趣東征。", "萬壑乾坤注，千艘日夜橫。", "江山看不暇，此役快平生。"]'),
('51c9b1dc-cfbe-4431-9c53-dc5e00ca9b36','峴山塔院','袁說友','宋','宋诗','song-poetry','','[]','野寺埋荒草，浮屠出近郊。',48,'全唐诗/poet.song.161000.json','["野寺埋荒草，浮屠出近郊。", "松聲來葆樂，竹影亂旗梢。", "地僻鐘魚響，庭空燕雀巢。", "斷崖流澗遠，隠隠下山坳。"]'),
('346bb453-5a40-4743-808b-b986e9754041','送惠老往住上方','袁說友','宋','宋诗','song-poetry','','[]','又作西山去，潮音鼓一通。',48,'全唐诗/poet.song.161000.json','["又作西山去，潮音鼓一通。", "叢林推此老，詩社得諸公。", "著眼浮生外，衝風逆水中。", "殷勤三請已，此意不雷同。"]'),
('ec7ebf8f-0529-4d57-88fb-6d467da81de5','過富池廟','袁說友','宋','宋诗','song-poetry','','[]','祀典名稱重，神靈遠近聞。',48,'全唐诗/poet.song.161000.json','["祀典名稱重，神靈遠近聞。", "陳牲共豕一，裹飯集烏羣。", "水旱憂民切，江山護國勤。", "丹誠禱祠下，不敢事虛文。"]'),
('ead04610-6b82-4f6e-a3e5-6ec6accb7a61','霸王廟','袁說友','宋','宋诗','song-poetry','','[]','志大無遺策，天亡有愧心。',48,'全唐诗/poet.song.161000.json','["志大無遺策，天亡有愧心。", "威稜空炯炯，祠殿獨陰陰。", "木秀千年古，溪流萬折深。", "江東父老意，羯鼓奏新音。"]'),
('faee72d8-e695-404d-b89b-76d5ede461e8','過三山磯有廟祀李氏女嘗以詩託之過客夢中江神曰遊奕將嘗求經於陳惠公得冥司遷職','袁說友','宋','宋诗','song-poetry','','[]','磯到三山峻，濤奔亂石濱。',48,'全唐诗/poet.song.161000.json','["磯到三山峻，濤奔亂石濱。", "吟哦靈女廟，遊奕護江神。", "古往人何在，幽冥事已深。", "平生仗忠信，持此問天津。"]'),
('d3628570-d43e-4ae7-abfb-d2649acb3d90','訪趙王北園荷池','袁說友','宋','宋诗','song-poetry','','[]','小熟烏程釀，重遊習氏園。',48,'全唐诗/poet.song.161000.json','["小熟烏程釀，重遊習氏園。", "亂蟬依柳噪，疎雨趁荷喧。", "短棹雙溪靜，輕鷗一羽翻。", "青山滿歸路，新月送黄昏。"]'),
('977c029e-447b-41e6-aab7-e9d0b6772514','過鄰水縣橫碧川','袁說友','宋','宋诗','song-poetry','','[]','一水橫空翠，羣山送遠陰。',48,'全唐诗/poet.song.161000.json','["一水橫空翠，羣山送遠陰。", "臨流新柳媚，隔岸小樓深。", "五斗淵明米，朞年子賤琴。", "可人山水縣，莫倦讀書音。"]'),
('849d581f-4f20-457f-9ece-64d1763ecb12','出東城觀水','袁說友','宋','宋诗','song-poetry','','[]','浩蕩東城外，微茫病眼開。',48,'全唐诗/poet.song.161000.json','["浩蕩東城外，微茫病眼開。", "烟帆一鳥過，雲插亂峰堆。", "綠水漫漫去，青山衮衮來。", "飛邊雙鷺沒，天末晚風迴。"]'),
('650022ce-b281-4b0b-8c07-d36d7e72763e','駱駝橋','袁說友','宋','宋诗','song-poetry','','[]','家住水雲窟，路分苕霅溪。',48,'全唐诗/poet.song.161000.json','["家住水雲窟，路分苕霅溪。", "天高橫蝃蝀，水闊跨鯨鯢。", "捲浪去還却，行人東望西。", "帆檣驚歲月，橋柱幾人題。"]'),
('a8ad9054-13e7-49f6-a520-4bce5ceb975c','甘棠橋','袁說友','宋','宋诗','song-poetry','','[]','波入南溪綠，荷薰夾岸香。',48,'全唐诗/poet.song.161000.json','["波入南溪綠，荷薰夾岸香。", "一川虹倒影，百步带橫塘。", "舟榜橋邊柳，魚驚月下榔。", "人亡遺愛遠，誰復賦甘棠。"]'),
('18ecec19-6c25-48d9-8824-3867848eff24','舟行夜過甘棠橋','袁說友','宋','宋诗','song-poetry','','[]','遠鼓三更急，長虹十丈低。',48,'全唐诗/poet.song.161000.json','["遠鼓三更急，長虹十丈低。", "影浮冰鑑月，身渡玉壺溪。", "畫燭人應醉，桃源路肯迷。", "疎星與殘月，點點下玻璃。"]'),
('25822444-96c7-4275-83ee-3748fc728a95','舟泊竹篠港夜坐誦後山詩','袁說友','宋','宋诗','song-poetry','','[]','沙岸人歸後，船窗月上時。',48,'全唐诗/poet.song.161000.json','["沙岸人歸後，船窗月上時。", "霜風竹篠港，燈火後山詩。", "歲晚羈懷惡，江空熟路遲。", "鄰舟一樽酒，不使老夫知。"]'),
('0ab13f41-69b1-4bad-a4f3-796549f7b38c','舟發黄州連日遇逆風泊赤壁','袁說友','宋','宋诗','song-poetry','','[]','赤壁磯方到，黄州路未遥。',48,'全唐诗/poet.song.161000.json','["赤壁磯方到，黄州路未遥。", "辛勤四十里，跋涉兩三朝。", "戢戢牛羊下，閒閒鷗鷺驕。", "忍將今歲月，容易客中銷。"]'),
('887dae60-a39f-4f2c-8174-95fbad60070a','舟遇逆風有葉舟坐二小兒以一竿掛二笠代帆而來','袁說友','宋','宋诗','song-poetry','','[]','小艇浮孤葦，垂髫識二童。',48,'全唐诗/poet.song.161000.json','["小艇浮孤葦，垂髫識二童。", "巧將雙箬笠，快奪一帆風。", "去去漁歌裏，翩翩麥浪中。", "吳兒慣浮浪，早已逐飄蓬。"]'),
('2334f100-aecb-4d1a-a738-e84efdeac0fe','舟行邂逅別吳子明郎中','袁說友','宋','宋诗','song-poetry','','[]','杜宇催歸急，青山送客忙。',48,'全唐诗/poet.song.161000.json','["杜宇催歸急，青山送客忙。", "去帆辭斷港，過眼接危檣。", "親戚五年別，尊罍一笑長。", "山西墮殘照，不忍酹離觴。"]'),
('575e3a2f-08f5-42bb-938a-6dd6719079d4','庖人舟以風殿後早飯不繼','袁說友','宋','宋诗','song-poetry','','[]','帆蓆攙前去，炊煙落後陳。',48,'全唐诗/poet.song.161000.json','["帆蓆攙前去，炊煙落後陳。", "一杯羹已飫，方丈食何因。", "自分貧兼客，休嗟愁殺人。", "江風吹送穩，晚酌待頻頻。"]'),
('d2132466-15ba-4c98-8e75-1cca58d783a4','舟中懷稚子','袁說友','宋','宋诗','song-poetry','','[]','遠浦三更月，春風一夜程。',48,'全唐诗/poet.song.161000.json','["遠浦三更月，春風一夜程。", "平生慣安靜，多病怯征行。", "急櫓誇先後，連山護送迎。", "關心小兒女，幽夢落東城。"]'),
('7f8cac00-bfbb-47a8-b7f3-e6028432fdca','觀漁舟得巨魚','袁說友','宋','宋诗','song-poetry','','[]','猛作修鱗想，觀漁憶故濠。',48,'全唐诗/poet.song.161000.json','["猛作修鱗想，觀漁憶故濠。", "橫舟排雪浪，敏手奪銀刀。", "過熟偏宜酒，餘鮮更带糟。", "忍窮須忍口，老矣爲渠饕。"]'),
('0eae435c-aef9-49cb-ac6c-6f57052b5203','舟過七里店迓客','袁說友','宋','宋诗','song-poetry','','[]','漲水一篙足，環山七里長。',48,'全唐诗/poet.song.161000.json','["漲水一篙足，環山七里長。", "維舟橫略彴，驚鷺入菰蔣。", "話舊人俱老，相嗟鬢各霜。", "年來慵不出，猶未免迎將。"]'),
('fe59379c-0cb6-42da-ac08-fef517eef5e9','舟中酒味酸許深父漕使以家釀來亦不欲受','袁說友','宋','宋诗','song-poetry','','[]','樽酒稱臺餽，牢辭以例陳。',48,'全唐诗/poet.song.161000.json','["樽酒稱臺餽，牢辭以例陳。", "獨醒心已醉，不飲意如春。", "凝望嗟陶令，誇醒笑伯倫。", "兼金有前訓，寄謝白衣人。"]'),
('b20dc740-566b-429c-bf88-0ab3e5f79ade','月河','袁說友','宋','宋诗','song-poetry','','[]','路轉雙溪曲，河灣一逕通。',48,'全唐诗/poet.song.161000.json','["路轉雙溪曲，河灣一逕通。", "清秋楊柳月，落日芰荷風。", "直抵濯纓水，當前文筆峰。", "滿城佳氣聚，擢秀美羣公。"]'),
('1dad22e2-a0b7-4ec8-a461-baff0f39da7f','練湖','袁說友','宋','宋诗','song-poetry','','[]','練湖四十里，往往半徐州。',48,'全唐诗/poet.song.161000.json','["練湖四十里，往往半徐州。", "巨浸膏千畝，餘波濟萬艘。", "回旋迷宿鳥，浩蕩狎飛鷗。", "父老相迎問，猶懷旱暵憂。"]'),
('ad51fbf8-db9b-496f-b69a-c39941a135cb','入淮','袁說友','宋','宋诗','song-poetry','','[]','桐柏分源遠，清流接泗濱。',48,'全唐诗/poet.song.161000.json','["桐柏分源遠，清流接泗濱。", "於何號邊境，不忍問淮民。", "北顧關山在，西風草木新。", "天河如可挽，吾欲洗邊塵。"]'),
('4ed81aa0-b4d8-4dab-8104-bac56a572c1a','上官桀詐令人爲燕王旦上書言光疑有非常臣願歸符璽宿衛察變上曰朕知是書詐也後桀燕王等謀廢立事覺盡誅','袁說友','宋','宋诗','song-poetry','','[]','燕國歸符璽，將軍有謗書。',48,'全唐诗/poet.song.161000.json','["燕國歸符璽，將軍有謗書。", "君王嗟詭詐，黨與悉趦趄。", "白日中天照，浮雲掃地除。", "狂謀身一敗，邪骨滿丘墟。"]'),
('fcd547f5-4b9d-43fb-8978-72e697cb5675','高廟災董仲舒推說其意稿未上主父偃候仲舒私見嫉之竊其書而奏焉上召視諸儒呂步舒以爲大愚下仲舒吏當死詔赦之','袁說友','宋','宋诗','song-poetry','','[]','老學推占後，姦人娼嫉初。',48,'全唐诗/poet.song.161000.json','["老學推占後，姦人娼嫉初。", "懷私真詭計，候見竊成書。", "猛欲擠賢轍，寧思戒覆車。", "那知一回首，身已斃誅鋤。"]'),
('0ecc05ed-8c91-4410-a9bc-be1cbf4fe600','文帝登虎圈問尉禽獸簿不能對虎圈嗇夫對甚悉上拜嗇夫爲上林令張釋之曰今以口辨超遷恐天下爭口辨無實遂不拜','袁說友','宋','宋诗','song-poetry','','[]','辨舌機鋒銳，言簧巧意傾。',48,'全唐诗/poet.song.161000.json','["辨舌機鋒銳，言簧巧意傾。", "一聞賢者議，衆鄙嗇夫名。", "利口宜深戒，違顔願力爭。", "須知玄默化，帝已久躬行。"]'),
('6b1f6be4-1bf6-4ba6-b589-3eb3eb3eb00b','文帝議以賈誼任公卿絳灌馮敬等害之乃毀誼曰洛陽年少擅權於是天子疏之以誼爲長沙王太傅','袁說友','宋','宋诗','song-poetry','','[]','諸老讒言入，長沙遠地留。',48,'全唐诗/poet.song.161000.json','["諸老讒言入，長沙遠地留。", "一聞天子議，衆嫉少年謀。", "自墮姦諛術，誰寬痛哭憂。", "至今言絳灌，猶爲孔門羞。"]'),
('800f31c2-b0cd-4a91-8e9c-0d25e3306cb3','張湯治獄皆窮根本上欲釋嚴助伍被湯曰弗誅後不可治巧排大臣益見尊任後以懷詐面欺上使使簿責湯湯爲書謝遂自殺','袁說友','宋','宋诗','song-poetry','','[]','最是慈祥日，爲臣慘刻聞。',48,'全唐诗/poet.song.161000.json','["最是慈祥日，爲臣慘刻聞。", "彎弓屠善類，刺骨見深文。", "流毒嗟苛吏，傷恩負此君。", "不知慚簿責，一死尚何云。"]'),
('3dd2e354-39a3-4b1a-b6a3-14f91841872e','遇張玉叔荆漕自潼州易節來言蜀人兩載前以制帥相期矣','袁說友','宋','宋诗','song-poetry','','[]','上愧三朝老，深慚四蜀民。',48,'全唐诗/poet.song.161000.json','["上愧三朝老，深慚四蜀民。", "君恩無語報，世事有前因。", "叱馭寧論遠，捫參敢愛身。", "但思强健日，歸計莫因循。"]'),
('43a031d3-f921-4e0c-b4ba-39df6339ea83','孟子開宰餘杭二首  其一','袁說友','宋','宋诗','song-poetry','','[]','畿邑三年令，先聲百里春。',48,'全唐诗/poet.song.161000.json','["畿邑三年令，先聲百里春。", "公朝勤恤隠，吾道足親民。", "不作勞人想，猶堪發刃新。", "從渠清俗論，峩豸已知津。"]'),
('d6f2c6ae-1ab7-48c3-8783-3c19ed5d518b','孟子開宰餘杭二首  其二','袁說友','宋','宋诗','song-poetry','','[]','得友寧論少，登門不愧遲。',48,'全唐诗/poet.song.161000.json','["得友寧論少，登門不愧遲。", "交游今有幾，襟抱獨相期。", "笑我方椎鈍，如公政驟馳。", "我今懷舊意，不敢愛於詩。"]'),
('16c38b43-d615-4014-b3e4-a2fce185bc00','武康縣治松桂林二首  其一','袁說友','宋','宋诗','song-poetry','','[]','松桂論交久，詩書造道深。',48,'全唐诗/poet.song.161000.json','["松桂論交久，詩書造道深。", "猶於官事日，不忘歲寒心。", "此地賡酬句，他年蔽芾陰。", "男邦有佳政，應促詔綸音。"]'),
('e4910fdc-21ab-4190-8efc-091bc3cfecb7','武康縣治松桂林二首  其二','袁說友','宋','宋诗','song-poetry','','[]','詩競山川秀，亭隨草木新。',48,'全唐诗/poet.song.161000.json','["詩競山川秀，亭隨草木新。", "弦歌魯言偃，吏隠漢梅真。", "淇苑雪霜操，廣寒宮殿春。", "相望不百里，一葦要身親。"]'),
('3e499597-6445-4970-87ca-6d6c8aeaab48','遺雲液新醇花胯正焙於制幕','袁說友','宋','宋诗','song-poetry','','[]','彥聚有英倫，公餘無雜賓。',48,'全唐诗/poet.song.161000.json','["彥聚有英倫，公餘無雜賓。", "一樽雲送液，寸玉雪先春。", "浮蟻酒中聖，團龍天上珍。", "遣之陪幕府，聊以款車巾。"]'),
('bb810ac3-dca6-4960-b30c-78fcfca88ca6','曾同年南仲至自德清二首  其一','袁說友','宋','宋诗','song-poetry','','[]','歲月飛梭疾，交游舊雨疎。',48,'全唐诗/poet.song.161000.json','["歲月飛梭疾，交游舊雨疎。", "故人欣戾止，之子最相於。", "話舊須樽酒，奔忙缺飯蔬。", "不酬千種意，空寄一行書。"]'),
('dcef2ad2-b26d-4d7a-9a19-ba52d00804d9','曾同年南仲至自德清二首  其二','袁說友','宋','宋诗','song-poetry','','[]','老去慵馳騖，詩來慰闊疏。',48,'全唐诗/poet.song.161000.json','["老去慵馳騖，詩來慰闊疏。", "吾廬聊復爾，仁里盍依於。", "乞米慚書帖，呼兒笑擷蔬。", "强吟鬚撚句，博得玉鈎書。"]'),
('9555b722-8d33-4a0a-a888-37d5fab17c90','和同年張唐英懷弟晉英韻二首  其一','袁說友','宋','宋诗','song-poetry','','[]','舊學知何補，丹心早已平。',48,'全唐诗/poet.song.161000.json','["舊學知何補，丹心早已平。", "過從欣故侶，慨慕熟英聲。", "笑洽愁腸釋，詩來俗眼清。", "君家好兄弟，何愧洛中程。"]'),
('53e386ab-7910-4a0d-80f8-0850a4bf11b0','和同年張唐英懷弟晉英韻二首  其二','袁說友','宋','宋诗','song-poetry','','[]','嗜利終羞澀，論交愧懶昏。',48,'全唐诗/poet.song.161000.json','["嗜利終羞澀，論交愧懶昏。", "日高忺閉戶，客至倦迎門。", "多謝鏗金語，來如挾纊溫。", "窮年得佳友，花柳樂村村。"]'),
('c775c9b7-6cc0-4692-a676-159529023bd8','和張思濟縣尉韻二首  其一','袁說友','宋','宋诗','song-poetry','','[]','作計尋山徑，論交獨兩生。',48,'全唐诗/poet.song.161000.json','["作計尋山徑，論交獨兩生。", "相過真有意，多病只垂情。", "老怯終年別，詩煩一夜程。", "懷思幾秋夢，月落曉溪橫。"]'),
('c0feefa7-2293-4254-959d-c9a4eeb46a73','和張思濟縣尉韻二首  其二','袁說友','宋','宋诗','song-poetry','','[]','書債頻年積，舟行一水期。',48,'全唐诗/poet.song.161000.json','["書債頻年積，舟行一水期。", "稍吟秋夜雨，不盡故人思。", "正爲才高累，寧論事了嗤。", "相忘心屢折，落筆更蜚馳。"]'),
('684e9abe-0f54-4e36-bad9-c0ec0c23b4c8','和唐英韻','袁說友','宋','宋诗','song-poetry','','[]','客久催歸馭，愁牢愛大杯。',48,'全唐诗/poet.song.161000.json','["客久催歸馭，愁牢愛大杯。", "驪駒勤詠歎，行李尚淹回。", "皇甫有書至，蓋公何日來。", "巾車莫濡滯，祇此趣鹽梅。"]'),
('b2e40ff5-075c-4a6b-8cd8-9688d2a9cdd7','和丁端叔九日韻','袁說友','宋','宋诗','song-poetry','','[]','風雨重陽候，旌旗五客遊。',48,'全唐诗/poet.song.161000.json','["風雨重陽候，旌旗五客遊。", "清樽煩卜夜，歸鬢但驚秋。", "薄暮靄雲散，傾城終日留。", "晚樓東望際，萸菊故園丘。"]'),
('11792781-07ba-4b8f-a1a7-ba227944aa85','和人懷歸','袁說友','宋','宋诗','song-poetry','','[]','宦海風波惡，窮途故舊新。',48,'全唐诗/poet.song.161000.json','["宦海風波惡，窮途故舊新。", "匹夫猶按劍，夜璧莫投人。", "狎水舟沈羽，防城口累身。", "歸來老丘壑，一笑樂吾真。"]'),
('5bb3fdb3-f1dc-4b36-9dd2-2f6bf7f31987','和林子長家庭韻','袁說友','宋','宋诗','song-poetry','','[]','諸郎方競秀，蘭玉謝庭家。',48,'全唐诗/poet.song.161000.json','["諸郎方競秀，蘭玉謝庭家。", "國士無雙譽，蟾宮第一花。", "侍嬪歌采苢，笄鬢綰堆鴉。", "已辦如椽筆，綿綿賦瓞瓜。"]'),
('7f673c66-f62d-4b9e-abef-1c53851d8523','和惠老自上方來住廣福寺','袁說友','宋','宋诗','song-poetry','','[]','歲晚逢三友，身閒愛一丘。',48,'全唐诗/poet.song.161000.json','["歲晚逢三友，身閒愛一丘。", "喜聞孤錫至，又向白蘋留。", "失笑拈花手，無人野渡舟。", "個中須具眼，著語待公酬。"]'),
('9ed46a10-ad3e-41b8-9f7a-3d72adaac8ba','鄉人徐辯道見過自云有升平遺策當挾之西遊乞詩祖行聊作一首','袁說友','宋','宋诗','song-poetry','','[]','鄉翁初識面，獨往定何如。',48,'全唐诗/poet.song.161000.json','["鄉翁初識面，獨往定何如。", "客舍風霜急，權門韋布疎。", "北書應有犬，南食尚無魚。", "身外祇遺策，蒼苔空故廬。"]'),
('36a547ee-c3aa-4e7f-88a0-dd500f6c70b2','故人爽貸粟之約','袁說友','宋','宋诗','song-poetry','','[]','小泊漁舟晚，春風燕子回。',48,'全唐诗/poet.song.161000.json','["小泊漁舟晚，春風燕子回。", "從渠三月約，誤我一舟來。", "風雨故相厄，溪山猶可陪。", "人生竟何有，此抱向誰開。"]'),
('698c8eb3-41f6-46a9-a0c5-4b2336cee65d','謝王進士惠近作','袁說友','宋','宋诗','song-poetry','','[]','秋入淮鄉老，風連塞鴈悲。',48,'全唐诗/poet.song.161000.json','["秋入淮鄉老，風連塞鴈悲。", "一書煩故舊，七字更新奇。", "我已歸帆日，公方客館時。", "天涯每相遇，不敢愛於詩。"]'),
('065a12f5-d836-4a74-b3d0-5c97409d5f97','謝李兼善書庫寄近作','袁說友','宋','宋诗','song-poetry','','[]','筆下陳無己，香分一瓣奇。',48,'全唐诗/poet.song.161000.json','["筆下陳無己，香分一瓣奇。", "有孫今見嫡，得髓政忘皮。", "懷舊書來日，驚人語妙時。", "猶思頻咀嚼，嚥子百篇詩。"]'),
('3aed8ec7-a1ae-48e9-867d-d525035f0e11','謝趙周錫制幹和篇','袁說友','宋','宋诗','song-poetry','','[]','甫擲拋磚句，俄驚翻水成。',48,'全唐诗/poet.song.161000.json','["甫擲拋磚句，俄驚翻水成。", "源泉誇敏思，擊鉢噤無聲。", "白玉彫鎸巧，黄金煅煉精。", "我慚非腹稿，不復敢披呈。"]'),
('bc7f4f40-e16f-4ae1-bee0-373cca469d7e','疑獨學錄屢過僕言詩又遺以成編蓋區區每有意於此而拙無佳語爲大恨因作鄙言奉報','袁說友','宋','宋诗','song-poetry','','[]','初聞富經術，頗復事風騷。',48,'全唐诗/poet.song.161000.json','["初聞富經術，頗復事風騷。", "作者意不盡，斯人才已高。", "大編來警策，短髮對爬搔。", "好語遠相避，獨憐曾幾遭。"]'),
('1be40ed9-6c54-4998-8c68-81f44604ac5c','泊金陵得仲元書','袁說友','宋','宋诗','song-poetry','','[]','親戚不忍別，弟兄那可離。',48,'全唐诗/poet.song.161000.json','["親戚不忍別，弟兄那可離。", "枕邊鴻鴈信，天外鶺鴒詩。", "老大須長健，音書莫較遲。", "今朝萬金至，無語不成思。"]'),
('23334f11-bcc2-4263-99e4-8fa9e9839799','興化吳宰商卿來書','袁說友','宋','宋诗','song-poetry','','[]','百里報消息，一緘勞寄馳。',48,'全唐诗/poet.song.161000.json','["百里報消息，一緘勞寄馳。", "但知懷舊切，猶恨得書遲。", "儒者可言政，懷邦當易爲。", "問君安否外，別後幾篇詩。"]'),
('70023fe0-08b7-4d42-b856-54db1db62c9f','讀書','袁說友','宋','宋诗','song-poetry','','[]','宦牒剛馳逐，篇章半掃除。',48,'全唐诗/poet.song.161000.json','["宦牒剛馳逐，篇章半掃除。", "稍尋無事日，重理舊詩書。", "筆硯寒燈寂，軒窗晝景舒。", "政須堂下問，糟粕意何如。"]'),
('5c99d1bf-74bf-4cae-9ce9-45d0ebb26a7c','持課','袁說友','宋','宋诗','song-poetry','','[]','夢接三乘境，香勝一炷薰。',48,'全唐诗/poet.song.161000.json','["夢接三乘境，香勝一炷薰。", "風窗獨趺坐，鳥雀聽聲聞。", "目想金剛會，心存貝葉文。", "稍蠲煩惱毒，天雨看繽紛。"]'),
('5e5f3014-fe59-459a-bb38-17ff8c518026','周可大携子入山讀書','袁說友','宋','宋诗','song-poetry','','[]','一日不覿面，三秋應動心。',48,'全唐诗/poet.song.161000.json','["一日不覿面，三秋應動心。", "剛聞將子去，又慣入山深。", "飯飽羣書樂，窗閒萬竹陰。", "扁舟纔十里，得得要相尋。"]'),
('75f79e4e-43b3-4aaa-ba63-5936913d2d87','訓子','袁說友','宋','宋诗','song-poetry','','[]','投老尋三窟，傳家只一經。',48,'全唐诗/poet.song.161000.json','["投老尋三窟，傳家只一經。", "呼兒親料理，開卷熟叮嚀。", "我已頭居白，誰堪芥拾青。", "頗懷蘭與玉，長憶謝家庭。"]'),
('26bcf867-0efe-437e-93c1-3c8e620e1e23','展掃先塋','袁說友','宋','宋诗','song-poetry','','[]','寂寞千松老，縈紆一水通。',48,'全唐诗/poet.song.161000.json','["寂寞千松老，縈紆一水通。", "重來驚鬢雪，遺恨滿春風。", "拱木人何在，傷心淚已窮。", "羈懷不成寐，月落半山空。"]'),
('ff9279bf-3b24-418e-a9de-142bad3a2ecd','展掃先塋省伯氏用前韻','袁說友','宋','宋诗','song-poetry','','[]','久作弟兄別，相看笑語通。',48,'全唐诗/poet.song.161000.json','["久作弟兄別，相看笑語通。", "寒窗酬酒夜，落月對床風。", "志得寧論晚，名高不畏窮。", "君看天下事，一一漫彫空。"]'),
('887c4b5a-69b0-452c-8db8-1f1a4c421599','閉戶','袁說友','宋','宋诗','song-poetry','','[]','戶屨無人滿，庭羅盡日張。',48,'全唐诗/poet.song.161000.json','["戶屨無人滿，庭羅盡日張。", "閒窗書白羽，清夢熟黄粱。", "瓦甕苕溪淥，銅鑪柏子香。", "出門本無礙，龜穴慣深藏。"]'),
('b9d4b878-b5af-4838-b72a-57ff4c261695','曝書','袁說友','宋','宋诗','song-poetry','','[]','紅日庭初熭，青編手自摩。',48,'全唐诗/poet.song.161000.json','["紅日庭初熭，青編手自摩。", "烏踆浮竹簡，魚蠹眩陽和。", "眼恨頻催老，書慚未觸多。", "相看不相棄，同老故山阿。"]'),
('776b1c64-4f38-44f2-b384-ce178ffdab46','試硯','袁說友','宋','宋诗','song-poetry','','[]','斷璧推良質，寒窗足雅供。',48,'全唐诗/poet.song.161000.json','["斷璧推良質，寒窗足雅供。", "點分鸜眼秀，色漬馬肝濃。", "巖浸端溪月，紋藏古歙峰。", "可憐方寸石，筆下幾迎逢。"]'),
('a18cb589-949b-4d82-95b5-25bcbaa718e8','治藥','袁說友','宋','宋诗','song-poetry','','[]','藥採人間足，方從肘後參。',48,'全唐诗/poet.song.161000.json','["藥採人間足，方從肘後參。", "年來醫罕問，老去病多諳。", "風雨關淫疾，刀圭辨苦甘。", "君看不龜手，猶敗越人南。"]'),
('07b03f50-ba39-4aae-b43f-e386164c63da','理髮','袁說友','宋','宋诗','song-poetry','','[]','揀髮亭移晝，臨風手獨搔。',48,'全唐诗/poet.song.161000.json','["揀髮亭移晝，臨風手獨搔。", "愁添絲幾縷，老怯鬢雙毛。", "自歎頭顱薄，空懷膽氣豪。", "年華莫相逼，疎櫛已如繅。"]'),
('4ecfea35-6d9f-4113-a59f-18d2288bc00f','懷仲子病目','袁說友','宋','宋诗','song-poetry','','[]','秋日家鄉遠，西風去鴈遲。',48,'全唐诗/poet.song.161000.json','["秋日家鄉遠，西風去鴈遲。", "小兒應藥喜，老父數歸期。", "昨夜三江夢，今朝五字詩。", "至情如飲水，冷暖自深知。"]'),
('d017361a-16e4-4f0b-9343-4b5d5cc165a0','家信報仲子目疾已平用前韻','袁說友','宋','宋诗','song-poetry','','[]','峴也平安久，書云傳遽遲。',48,'全唐诗/poet.song.161000.json','["峴也平安久，書云傳遽遲。", "意寬千里遠，歸更一旬期。", "眼過無非景，身閒足可詩。", "江湖終欲老，鷗鳥已先知。"]'),
('ce755d7d-64a6-40ec-ada7-2dd9fe376695','有感','袁說友','宋','宋诗','song-poetry','','[]','萬事緣憎愛，孤衷只惷愚。',48,'全唐诗/poet.song.161000.json','["萬事緣憎愛，孤衷只惷愚。", "歸與乖俗好，老矣誤時須。", "舉世沖霄鵠，何人濫吹竽。", "窮通一不問，無復鬼揶揄。"]'),
('a48a5f1a-e6e5-45b1-a07b-9675dc1670c2','偶成','袁說友','宋','宋诗','song-poetry','','[]','老眼慵開闔，閒窗獨欠伸。',48,'全唐诗/poet.song.161000.json','["老眼慵開闔，閒窗獨欠伸。", "夢殘亭過午，漏永箭浮申。", "黄卷卷舒足，黑甜滋味真。", "生涯惟一枕，百慮不關身。"]'),
('e72a391a-89f1-44df-94d8-4dea323599b1','燈花','袁說友','宋','宋诗','song-poetry','','[]','一點寒釭照，樓頭夜鼓撾。',48,'全唐诗/poet.song.161000.json','["一點寒釭照，樓頭夜鼓撾。", "報人初綴玉，戲我只空花。", "身已遺榮辱，燈應誤逞誇。", "焚膏疇昔事，牆角幾檠斜。"]'),
('f5b5524d-0894-4ebd-b743-eefb6c0289f7','自適','袁說友','宋','宋诗','song-poetry','','[]','有地容投老，無田解賦歸。',48,'全唐诗/poet.song.161000.json','["有地容投老，無田解賦歸。", "浮生幾朝露，活計一書幃。", "閒只詩添債，愁應带減圍。", "人間翻覆手，莫怨是中非。"]'),
('144a3748-cab0-41b1-91e7-0bee606f2747','絕糧','袁說友','宋','宋诗','song-poetry','','[]','舊索長安米，今無負郭田。',48,'全唐诗/poet.song.161000.json','["舊索長安米，今無負郭田。", "平生一飽計，歲晚百憂煎。", "漂母今何有，王孫空自憐。", "日高亭欲午，寒屋竈無煙。"]'),
('dc902844-5650-4fd0-bbcf-02e44f994969','淮白','袁說友','宋','宋诗','song-poetry','','[]','未識淮鄉味，饕饞老不衰。',48,'全唐诗/poet.song.161000.json','["未識淮鄉味，饕饞老不衰。", "及茲秋水漲，已食小鮮肥。", "衆口雖難美，饑腸本易爲。", "豈無鱸鱠好，物以罕爲奇。"]'),
('cf9ed7b5-5ed6-4e0a-8d07-7567065dd53f','古鏡','袁說友','宋','宋诗','song-poetry','','[]','老眼羞看鏡，華顛怯半霜。',48,'全唐诗/poet.song.161000.json','["老眼羞看鏡，華顛怯半霜。", "棲遲勳業晚，孤負歲年長。", "月透光深杳，花摇影頡頏。", "衣冠從爾正，不趁曉來粧。"]'),
('c0224f06-6c48-4927-903f-3c0a8c4e4360','景山寺古鼎','袁說友','宋','宋诗','song-poetry','','[]','小憩山前路，清談得道僧。',48,'全唐诗/poet.song.161000.json','["小憩山前路，清談得道僧。", "愛渠惟一鼎，持此供三乘。", "製作前無古，摩挲喜不勝。", "茲遊真可樂，著句憶吾曾。"]'),
('7d42aee6-1578-4b9e-b740-29f78317848f','靈壁蹲石','袁說友','宋','宋诗','song-poetry','','[]','幾朶連峰峻，千年古鏡浮。',48,'全唐诗/poet.song.161000.json','["幾朶連峰峻，千年古鏡浮。", "氣分靈壁秀，聲逐泗濱流。", "笑我成孤影，從渠老一丘。", "山川多勝地，擊拊嘆中州。"]'),
('52232f21-5a33-49d7-a076-5542423f3681','洞庭立峰','袁說友','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','絕壁橫翔勢，當軒偉岸姿。',48,'全唐诗/poet.song.161000.json','["絕壁橫翔勢，當軒偉岸姿。", "一峰雲欲下，亂蘚雨頻滋。", "獨立霜寒耐，銜空月影篩。", "緬懷黄石事，猶想穀城時。"]'),
('893fe6ea-56f8-4b9b-ac19-e0636337ebde','玲瓏山','袁說友','宋','宋诗','song-poetry','','[]','頗怪玲瓏景，渾疑雷雨穿。',48,'全唐诗/poet.song.161000.json','["頗怪玲瓏景，渾疑雷雨穿。", "燈分巖下徑，目駭洞中天。", "傍磴莓苔合，環山草木鮮。", "白雲時欲下，煙鎖閉神仙。"]'),
('d6fd74ae-6027-422b-8d81-680e35bc918b','與副伴王領衛論弈象','袁說友','宋','宋诗','song-poetry','','[]','輕兵三十二，一著見安危。',48,'全唐诗/poet.song.161000.json','["輕兵三十二，一著見安危。", "疋馬渡河日，單車馳敵時。", "棘門漫兒戲，淝水付枰棋。", "小試平戎手，將軍更出奇。"]'),
('a5e756b2-e639-477d-a6da-aa29d5f14d43','扇畫雪景','袁說友','宋','宋诗','song-poetry','','[]','杖屨祁寒裏，林巒幻景同。',48,'全唐诗/poet.song.161000.json','["杖屨祁寒裏，林巒幻景同。", "生綃明月影，淡墨老霜叢。", "點染三冬雪，招邀六月風。", "呼童小揮手，殘吹襲簾櫳。"]'),
('9bc84c1e-541d-4415-86f4-6da17ccc6d07','壁畫竹鶴','袁說友','宋','宋诗','song-poetry','','[]','風月寒窗寂，丹青半堵開。',48,'全唐诗/poet.song.161000.json','["風月寒窗寂，丹青半堵開。", "南牆看儼立，華表認歸來。", "邈想風聲唳，求棲鳥雀猜。", "雨餘新著色，點點上蒼苔。"]'),
('263c6e34-99bb-4908-8526-a0e3dc5d3d0f','卞山石林','袁說友','宋','宋诗','song-poetry','','[]','物是人非舊，堂空語不譍。',48,'全唐诗/poet.song.161000.json','["物是人非舊，堂空語不譍。", "千重雲夭矯，百態玉崚嶒。", "斷壁苔封徑，懸巖樹掛藤。", "搘頤重覓日，猶記昔年曾。"]'),
('399b9073-0412-4b1f-8056-1a01a6e98828','午陰小飲','袁說友','宋','宋诗','song-poetry','','[]','草樹澗邊青，人稀自掩扃。',48,'全唐诗/poet.song.161000.json','["草樹澗邊青，人稀自掩扃。", "陰沈端午水，晴映半天星。", "倦枕敷橫榻，枯藜傍小亭。", "誰知一杯酒，小醉不嫌醒。"]'),
('87e56a16-1025-426e-857c-f150e0559b3b','和惠老元日立春復雪韻','袁說友','宋','宋诗','song-poetry','','[]','一聲春正曉，雪裏薦新年。',48,'全唐诗/poet.song.161000.json','["一聲春正曉，雪裏薦新年。", "攬鏡星霜久，催人歲月遷。", "化工原著意，物態漫爭妍。", "我老心尤遠，居閒覺地偏。"]'),
('4db2bcdd-e274-41cf-bbb0-1eb68469f057','歸自郊外遇雪','袁說友','宋','宋诗','song-poetry','','[]','細雨初收脚，飛來已濺身。',48,'全唐诗/poet.song.161000.json','["細雨初收脚，飛來已濺身。", "固應宜瑞雪，未必困行人。", "酒裏寒猶重，吟邊語未新。", "更憐渠白叟，呵手訴車塵。"]'),
('71f15147-74a9-42da-92b6-0b275f815a71','和某提舉喜雪韻','袁說友','宋','宋诗','song-poetry','','[]','冷徹狐裘薄，風團柳絮堆。',48,'全唐诗/poet.song.161000.json','["冷徹狐裘薄，風團柳絮堆。", "雪先迎臘至，梅怯後時開。", "曉色連山老，年華兩鬢催。", "浮生驚節物，誰與賦歸來。"]'),
('670cb0ea-d215-4109-913e-e4e6f186ba67','元日立春','袁說友','宋','宋诗','song-poetry','','[]','春入簾幃線幾添，更隨桃茢快新瞻。',64,'全唐诗/poet.song.161000.json','["春入簾幃線幾添，更隨桃茢快新瞻。", "曉看密密輕絲墮，晚作纖纖細雨兼。", "可喜田家餘穀粟，也應澤國飽魚鹽。", "年豐更樂弦歌化，知是曹裝漸趣嚴。"]'),
('2d32e464-c50a-47b6-9b7b-9b71efa536d9','元日得雨','袁說友','宋','宋诗','song-poetry','','[]','知時膏澤下新正，便覺欣欣物意生。',64,'全唐诗/poet.song.161000.json','["知時膏澤下新正，便覺欣欣物意生。", "細雨寒梢半簷滴，單床孤夢五更聲。", "兩年元日嗟萍梗，萬里殊鄉付酒觥。", "不似斗杓容易轉，只今迎歲指東城。"]'),
('04b863d8-7840-4109-9fc8-148237f31215','惜春','袁說友','宋','宋诗','song-poetry','','[]','不緣雨雪不緣風，九十風光半已窮。',64,'全唐诗/poet.song.161000.json','["不緣雨雪不緣風，九十風光半已窮。", "嫋娜熟眠楊柳綠，夭嬈濃醉海棠紅。", "客懷不直韶光好，詩興猶因景物雄。", "投分東君未應薄，乞花償酒强迎逢。"]'),
('7e6275b0-7b7e-4c35-8b42-7a5c6951bf45','梨花','袁說友','宋','宋诗','song-poetry','','[]','東風日日點征衣，野闊林疎四望奇。',64,'全唐诗/poet.song.161000.json','["東風日日點征衣，野闊林疎四望奇。", "景物賸供行客眼，梨花更索老夫詩。", "登山趁得春三月，带月猶看雪一枝。", "七日崎嶇三百里，倡條冶葉故相隨。"]'),
('948209dd-07e4-483b-b762-53f2a121ec72','和楊誠齋春雨韻','袁說友','宋','宋诗','song-poetry','','[]','十年此袂與君分，一笑樓頭日過晨。',64,'全唐诗/poet.song.161000.json','["十年此袂與君分，一笑樓頭日過晨。", "真箇愁來真似夢，不因詩到不知春。", "雲霄元似非關我，風雨何須故惱人。", "猶得吟邊慰懷抱，絕知膏馥乞諸鄰。"]'),
('5358ed84-91b2-4063-be9c-eefb71b2c958','早行遇雨','袁說友','宋','宋诗','song-poetry','','[]','約得東風二月春，稍陪孤櫂曉溪行。',64,'全唐诗/poet.song.161000.json','["約得東風二月春，稍陪孤櫂曉溪行。", "酒能寬我三更夢，雨不饒人半日程。", "愁對梅殘初話別，懶看桃艷欲欣榮。", "紅塵未踏心先退，不是宵長故獨醒。"]'),
('afe8b630-247d-4abd-a329-8672a4b1d281','四月雨應禱','袁說友','宋','宋诗','song-poetry','','[]','夜半溶溶四面遮，雲峰推起阿香車。',64,'全唐诗/poet.song.161000.json','["夜半溶溶四面遮，雲峰推起阿香車。", "只今隴上誇多麥，誰爲丘中賦有麻。", "喜見綠針初剌水，笑渠青笠趁燒畬。", "偶然精禱誠非昧，應有歡娛田舍家。"]'),
('2455abfa-376d-4a55-b6bd-5fd71f4c7fd2','趙再可邦君六月雨應禱','袁說友','宋','宋诗','song-poetry','','[]','長夏何堪日日晴，德音優渥遍羣氓。',64,'全唐诗/poet.song.161000.json','["長夏何堪日日晴，德音優渥遍羣氓。", "黄堂少試爲霖手，赤地今傳喜雨聲。", "誠意自知關善政，天心正不遠人情。", "四郊已報四家語，一飽應無百計營。"]'),
('9076d2ae-d86a-46a1-b89a-2ed94828ca5f','禱雨於保福寺是日大雨至','袁說友','宋','宋诗','song-poetry','','[]','常暘爲虐勢流金，稽首長松幸屈臨。',64,'全唐诗/poet.song.161000.json','["常暘爲虐勢流金，稽首長松幸屈臨。", "一佛等慈清苦海，衆生度厄浴甘霖。", "沛然而下期中熟，可以無饑免大祲。", "好雨㥄人愁抱釋，退思疇昔尚熏心。"]'),
('2fb9503e-8701-4a5f-b960-503b3fd82a40','和趙成子提幹喜雨韻  其一','袁說友','宋','宋诗','song-poetry','','[]','一天膏澤下民區，此意拳拳敢自居。',64,'全唐诗/poet.song.161000.json','["一天膏澤下民區，此意拳拳敢自居。", "欲寫吳歌誇歲好，苦無傑語愧才虛。", "稍留佳客聯珠履，共酹餘觴笑麴車。", "試問蘇州兩年熟，豈無名筆作農書。"]'),
('a2f0afe6-368f-4c18-8b92-f0b599838140','和趙成子提幹喜雨韻  其二','袁說友','宋','宋诗','song-poetry','','[]','十年三已冒爲州，每每於民有旱憂。',64,'全唐诗/poet.song.161000.json','["十年三已冒爲州，每每於民有旱憂。", "午聽雷聲鳴屋角，晚驚雨脚壓雲頭。", "及時三日爲霖好，爲汝千箱樂歲求。", "欲辦一椽名喜雨，愧無老筆贊宸旒。"]'),
('3f9dd0c7-b31b-4d43-ba7d-7a5d70e6073e','和子西喜雨','袁說友','宋','宋诗','song-poetry','','[]','戰龍捲水動詩兵，著語才非喜雨亭。',64,'全唐诗/poet.song.161000.json','["戰龍捲水動詩兵，著語才非喜雨亭。", "但得雲秔香顆顆，不愁霜髮短星星。", "秧針刺水輕浮綠，麥浪翻風半挾青。", "只願年年飽憂國，庶幾萬里一心寧。"]'),
('55cd93e5-904a-483a-b7a8-f45d66ed42d2','鄂渚得雨','袁說友','宋','宋诗','song-poetry','','[]','江頭一夜水鳴艖，江外歡聲百萬家。',64,'全唐诗/poet.song.161000.json','["江頭一夜水鳴艖，江外歡聲百萬家。", "已報主人詩滿袖，更誇使者雨隨車。", "支離田父烟蓑濕，辟易炎官火傘斜。", "一望阿瞞狼狽地，村村剌水透針芽。"]'),
('3077ba66-3801-4219-a960-3819f8011147','連雨','袁說友','宋','宋诗','song-poetry','','[]','一月長晴窘漕渠，更留殘暑要驅除。',64,'全唐诗/poet.song.161000.json','["一月長晴窘漕渠，更留殘暑要驅除。", "飄風也解終朝久，驟雨新添二尺餘。", "但覺天公真有意，不知民力已潛紓。", "田家是處均膏澤，兩岸歡吟使者車。"]'),
('dfb003a6-fee8-42c4-b6ed-4c2e624989a4','大風雷雨','袁說友','宋','宋诗','song-poetry','','[]','雷風一息到山西，欹側村花不自持。',64,'全唐诗/poet.song.161000.json','["雷風一息到山西，欹側村花不自持。", "際晚甘霖如倒峽，今年香雪可翻匙。", "綠秧蘸脚元非揠，白水齊腰不恨遲。", "浪說隨車誇故事，但知憂國願無饑。"]'),
('2f5bb9e1-0715-4430-9679-76cfbf50f123','中秋無月','袁說友','宋','宋诗','song-poetry','','[]','皓魄埋雲未肯收，佳娥寂寞爲誰羞。',64,'全唐诗/poet.song.161000.json','["皓魄埋雲未肯收，佳娥寂寞爲誰羞。", "可憐數點不多雨，誤却一輪無限秋。", "急掃妖氛天外去，莫教微影暗中流。", "終當永夜清如水，我爲停杯便倚樓。"]'),
('a87fc4fc-ab1e-4887-91a5-718521350611','海棠','袁說友','宋','宋诗','song-poetry','','[]','江行了不按春光，江路欣看得海棠。',64,'全唐诗/poet.song.161000.json','["江行了不按春光，江路欣看得海棠。", "淺蘸深紅叢蓓蕾，細開濃白巧梳粧。", "蜀花但鬭臙脂濕，荆種新傅膩粉香。", "行客紛紛正寥落，爲渠著語快飛觴。"]'),
('b7b52ccc-0595-4382-9e80-562075362e0b','江行得水仙花','袁說友','宋','宋诗','song-poetry','','[]','徹底清姿秀可餐，柔枝不怯膽瓶寒。',64,'全唐诗/poet.song.161000.json','["徹底清姿秀可餐，柔枝不怯膽瓶寒。", "三星細滴黄金盞，六出分成白玉盤。", "是物合陪僊子供，何人遣傍客舟看。", "山礬似俗梅偏瘦，別與詩人較二難。"]'),
('7bb8e212-90b6-4179-a45e-b3a46d6c167d','和施德遠雙蓮韻二首  其一','袁說友','宋','宋诗','song-poetry','','[]','老向塵埃度歲華，不堪才拙負州家。',64,'全唐诗/poet.song.161000.json','["老向塵埃度歲華，不堪才拙負州家。", "天公著意成豐歲，地産無心出異葩。", "亂翠綃中雙暈臉，抹青山外兩凝霞。", "何人欲採蓮歸去，我有輕舟試一拏。"]'),
('39065910-536d-4b44-aa6d-1a7fbabb549f','和施德遠雙蓮韻二首  其二','袁說友','宋','宋诗','song-poetry','','[]','政拙才疎祇具員，也應和氣到吳邊。',64,'全唐诗/poet.song.161000.json','["政拙才疎祇具員，也應和氣到吳邊。", "鄉來偶爾雙岐麥，今復申之並蒂蓮。", "頗覺園丁驚創見，正須騷客賦新聯。", "天休要是傳消息，得得裝成大有年。"]'),
('54ba6c86-3448-4d9c-a9f9-34deab9fcc0d','迓金國聘使舟中逢玉簪花','袁說友','宋','宋诗','song-poetry','','[]','扁舟伊軋亂秋聲，花下新涼暑不侵。',64,'全唐诗/poet.song.161000.json','["扁舟伊軋亂秋聲，花下新涼暑不侵。", "濃葉襯成螺展髻，芳苞拆盡玉垂簪。", "誰將茉莉評高下，未必清香較淺深。", "把酒問花花不語，微吟空伴小蛩吟。"]'),
('b742e919-50c5-402e-8724-c977eb3345b9','新繁縣麥秀兩岐','袁說友','宋','宋诗','song-poetry','','[]','豐碑喜瑞熟摩挲，後至深慚拙政多。',64,'全唐诗/poet.song.161000.json','["豐碑喜瑞熟摩挲，後至深慚拙政多。", "魯國不聞三月治，漁陽敢說兩岐歌。", "年豐今日魚旟夢，農兆前村鸛鵲窠。", "又見東阡西陌雨，倚樓遥望濕輕蓑。"]'),
('2ce7eca8-f977-4bc2-b862-6cd62825ca6e','麥秀三岐','袁說友','宋','宋诗','song-poetry','','[]','用過其才愧弗宜，但於牧養要張施。',64,'全唐诗/poet.song.161000.json','["用過其才愧弗宜，但於牧養要張施。", "未應拙政才兼月，森出來牟過兩岐。", "長短異形垂美穗，青黄間色識新枝。", "懸知瑞應由明主，自是豐年屬聖時。"]'),
('ea056893-c5ed-4721-bdf2-9ae61df2583f','午晴觀孔雀','袁說友','宋','宋诗','song-poetry','','[]','異雀逢人正美觀，一鳴晴日傍欄干。',64,'全唐诗/poet.song.161000.json','["異雀逢人正美觀，一鳴晴日傍欄干。", "昂頭未展雲霄翼，掉尾先摇錦繡盤。", "危坐我方詩興切，薄寒誰伴酒腸寬。", "世間最是羈懷惡，猶得亭花著意看。"]'),
('32922d54-6225-4d80-b673-4b894bf54699','沿溪轉山入野亭小飲甚適','袁說友','宋','宋诗','song-poetry','','[]','惜此青青一日春，愛閒因得兩三人。',64,'全唐诗/poet.song.161000.json','["惜此青青一日春，愛閒因得兩三人。", "放身度密窮山崦，隨意居寬趁水濱。", "逸飲不成愁淡薄，苦吟終是喜清新。", "物華時世相流轉，今古之間幾窖塵。"]'),
('12f3f9a3-da5b-4731-b2e8-6220e4b35e36','過霞山小飲','袁說友','宋','宋诗','song-poetry','','[]','霞山書院醉焚香，細雨輕陰見海棠。',64,'全唐诗/poet.song.161000.json','["霞山書院醉焚香，細雨輕陰見海棠。", "春動舊懷杯酒後，晚吹新恨笛聲長。", "或紅或白花饒笑，爲整爲斜草更芳。", "寄語風光易塵土，相看流轉且相羊。"]'),
('06cce8e0-b17b-43fa-99fb-a363bb3bf785','張守招飲','袁說友','宋','宋诗','song-poetry','','[]','春風吹作萬家春，誰得聯鑣從使君。',64,'全唐诗/poet.song.161000.json','["春風吹作萬家春，誰得聯鑣從使君。", "微徑問花同載酒，深堂剪燭細論文。", "王郎把臂簪仍盍，嚴老呼舟首又分。", "安得雲龍隨上下，佳辰不復歎離羣。"]'),
('3566c47d-5989-4ad6-8df7-57d7cad9d491','余應卿招飲','袁說友','宋','宋诗','song-poetry','','[]','東門郭外七桐裏，知有宣州別駕家。',64,'全唐诗/poet.song.161000.json','["東門郭外七桐裏，知有宣州別駕家。", "再世從遊心自喜，暫時觴咏語無譁。", "平田寒日行孤鶩，枯木淒風集亂鴉。", "酒聖詩狂休問我，淋漓顛倒任橫斜。"]'),
('e67d47d5-cdd8-4fae-ad74-7ddabd5e22f5','陳主管招飲','袁說友','宋','宋诗','song-poetry','','[]','鵲拳庭竹語頻頻，忽有書來寂寞濱。',64,'全唐诗/poet.song.161000.json','["鵲拳庭竹語頻頻，忽有書來寂寞濱。", "盛事許同花燭夜，芳辰仍醉綺羅春。", "璧聯香閣初鳴鳳，霞泛仙觴定脯麟。", "更辦歸裝攟珠玉，一時人物各詩人。"]'),
('d5264b7f-1f27-49ea-87eb-76298877ef12','霞山葉學諭家梅下飲二首  其一','袁說友','宋','宋诗','song-poetry','','[]','歲闌何地看梅花，霜日新晴晚更嘉。',64,'全唐诗/poet.song.161000.json','["歲闌何地看梅花，霜日新晴晚更嘉。", "古觀去尋寒士屋，山園來近舊人家。", "香傳細密聞仍久，影倒高深落又斜。", "同是溪南閒澹者，暫時相賞醉無譁。"]'),
('984e9d1f-fe9a-4721-b6be-598e2f1b58d5','霞山葉學諭家梅下飲二首  其二','袁說友','宋','宋诗','song-poetry','','[]','不待梅梢三兩花，任他酒薄漫殽嘉。',64,'全唐诗/poet.song.161000.json','["不待梅梢三兩花，任他酒薄漫殽嘉。", "恍然靈運穿林屐，妙矣王維入畫家。", "靜聽喔咿雞唱曉，明分疎落鴈行斜。", "醉吟却是尋芳客，借取殘冬一笑譁。"]'),
('295b02ea-c75a-4472-a952-dc24c42fd46b','同子隆次公小飲','袁說友','宋','宋诗','song-poetry','','[]','老境昏昏只醉眠，不知門外艷陽天。',64,'全唐诗/poet.song.161000.json','["老境昏昏只醉眠，不知門外艷陽天。", "奚爲有客携壺至，又以閒人到酒邊。", "山路試登桃映日，溪城一望草如煙。", "春分花事今多少，未覺心情勝去年。"]'),
('6e0a2d3f-95fd-44f5-bb71-4c0d53d468be','送彭世昌山臺小飲','袁說友','宋','宋诗','song-poetry','','[]','象山只在水西頭，雲木猶高瀑更流。',64,'全唐诗/poet.song.161000.json','["象山只在水西頭，雲木猶高瀑更流。", "往事何能話師友，時情徒與惜交遊。", "東風又綠溪邊草，明月還歸天際舟。", "白髮蒼顔吾亦老，一尊臺上洗春愁。"]'),
('d9b42306-d641-4453-8483-ef05ad152dce','登第一山','袁說友','宋','宋诗','song-poetry','','[]','極目俄登最上巖，秋風衰草塞雲閒。',64,'全唐诗/poet.song.161000.json','["極目俄登最上巖，秋風衰草塞雲閒。", "漫游江浙幾千里，今識東南第一山。", "志士逢時寧恨晚，壯懷有淚不須潸。", "興亡自古知多少，天道何曾不好還。"]'),
('dea8291c-2025-401a-b616-5ea5fe1e88c9','和南伯山行韻二首  其一','袁說友','宋','宋诗','song-poetry','','[]','日日登山復下山，崎嶇分寸絕難攀。',64,'全唐诗/poet.song.161000.json','["日日登山復下山，崎嶇分寸絕難攀。", "已無魚腹江湖慮，肯怯羊腸道路彎。", "滿目詩材供客子，一杯醽醁染衰顔。", "四方弧矢男兒事，捫盡參墟莫畏艱。"]'),
('d397d05d-43cc-41f8-9933-747f9134ccae','和南伯山行韻二首  其二','袁說友','宋','宋诗','song-poetry','','[]','千峰踏盡又層坡，冠染征塵不暇峩。',64,'全唐诗/poet.song.161000.json','["千峰踏盡又層坡，冠染征塵不暇峩。", "佳處賞心惟酒爾，愁時引睡奈詩何。", "憩亭尚遠日先暮，脚力已窮山更多。", "白髮對山聊自醉，如公自富郢中歌。"]'),
('bdc9a8fb-5800-4046-8cff-cd4b7ffb9cf3','遊金焦二山至汲江亭用前韻','袁說友','宋','宋诗','song-poetry','','[]','江山萬里憶徐州，十月迎風度小舟。',64,'全唐诗/poet.song.161000.json','["江山萬里憶徐州，十月迎風度小舟。", "極目不知天外景，亂雲遥接水中丘。", "此身五十昔未到，著語再三今可酬。", "欲把邊塵聊一洗，只今更吸大江流。"]'),
('4b0deb2f-d419-4241-8121-549c91432274','過揚州平山堂邂逅許深父主漕','袁說友','宋','宋诗','song-poetry','','[]','平生蹤跡半江湖，歲晚淮鄉識舊都。',64,'全唐诗/poet.song.161000.json','["平生蹤跡半江湖，歲晚淮鄉識舊都。", "小却車塵行復止，要看山色有還無。", "關山回首嗟何限，風景於人豈不殊。", "猶得故人談世事，金城方略政堪圖。"]'),
('0276fb34-7c49-4336-aa41-78ed02b64a86','泊姑蘇館','袁說友','宋','宋诗','song-poetry','','[]','衝風挾雨到蘇州，贏得檣烏半日留。',64,'全唐诗/poet.song.161000.json','["衝風挾雨到蘇州，贏得檣烏半日留。", "豈是甘棠無剪伐，浪持使節幾經由。", "羣觀底事多耆老，一笑猶能認故侯。", "回首齊雲舊游處，西山端欲送行舟。"]'),
('061eac0f-949d-4e60-9a1e-3b54b881523e','遊滄浪亭','袁說友','宋','宋诗','song-poetry','','[]','出門猶未識滄浪，勝日能銷一詠觴。',64,'全唐诗/poet.song.161000.json','["出門猶未識滄浪，勝日能銷一詠觴。", "綠障千巒森羽戟，翠綃十頃颭池塘。", "清談杖履窮幽徑，歸路籃輿带夕陽。", "豈是此纓無地濯，可憐長說簿書忙。"]'),
('0f149800-7cff-4046-840c-6b6c3f2e84db','和應憲使遊滄浪亭韻','袁說友','宋','宋诗','song-poetry','','[]','使星兩兩照前山，筆下高吟萬選錢。',64,'全唐诗/poet.song.161000.json','["使星兩兩照前山，筆下高吟萬選錢。", "絕景政須終日款，茲游真可以詩傳。", "深林遇雨排清晝，晚日迎風浸碧煙。", "千載不渾亭下水，俯欄猶得繼前賢。"]'),
('9b581176-b484-49bc-bbc7-619d166cb635','和韓倅滄浪亭韻','袁說友','宋','宋诗','song-poetry','','[]','平生公賞最巖居，肯作癡兒失故吾。',64,'全唐诗/poet.song.161000.json','["平生公賞最巖居，肯作癡兒失故吾。", "正爾不堪塵滿面，爲君何惜酒隨車。", "十年夜隔青藜杖，一日身游碧玉壺。", "莫道欲歸歸未得，買山作計定何如。"]'),
('6753456e-75a2-4fb6-a9cc-3748f92a03b8','春日懷錢塘西湖','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','只今春色滿皇州，料得西湖已縱游。',64,'全唐诗/poet.song.161000.json','["只今春色滿皇州，料得西湖已縱游。", "出郭競聯城下騎，循隄同上柳邊舟。", "恨無兩翼從渠去，曾有諸公念我不。", "到底長安風物外，遠方何敢詫遨頭。"]'),
('645d6985-b44a-4d1d-abc8-8a554caad6ef','和董顯之留西湖韻','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','開門喜得故人音，訪我浮生一旅亭。',64,'全唐诗/poet.song.161000.json','["開門喜得故人音，訪我浮生一旅亭。", "老大區區驚歲月，功名落落負簪纓。", "有誰知己頭空白，舉世如君眼獨青。", "羨子百篇詩在手，湖山相望不勝情。"]'),
('3d19f567-56f6-4d29-a75a-87b44168c250','和忠父于先生西湖韻','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','先生擺脫世間緣，老去猶堪十萬錢。',64,'全唐诗/poet.song.161000.json','["先生擺脫世間緣，老去猶堪十萬錢。", "氣節向來投匭意，風流今識詠梅篇。", "飽聞東閤掄材久，未許西湖對客眠。", "聖主如天懷讜論，只今此席爲君前。"]'),
('a21c8148-ed1d-4883-96a7-19852b92683e','遊武昌東湖','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','只說西湖在帝都，武昌新又說東湖。',64,'全唐诗/poet.song.161000.json','["只說西湖在帝都，武昌新又說東湖。", "一圍煙浪六十里，幾隊寒鷗千百雛。", "野木迢迢遮去鴈，漁舟點點映飛烏。", "如何不作錢塘景，要與江城作畫圖。"]'),
('338d1719-32d9-4d7b-8e30-9f44b390cd65','和趙周錫制幹峽中韻四首  其一','袁說友','宋','宋诗','song-poetry','','[]','西陵峭壁路初經，但見攙空兩岸青。',64,'全唐诗/poet.song.161000.json','["西陵峭壁路初經，但見攙空兩岸青。", "天近下連蒼玉嶂，山高傍湧翠雲屏。", "劃開龍虎流三峽，敕下雷霆遣六丁。", "終日橫風倚江轉，恍疑身世在滄溟。"]'),
('84303092-8b79-4f50-b348-67b2aa182f19','和趙周錫制幹峽中韻四首  其二','袁說友','宋','宋诗','song-poetry','','[]','千仞山頭更有山，一山去後一山還。',64,'全唐诗/poet.song.161000.json','["千仞山頭更有山，一山去後一山還。", "林巒有路春回綠，僊洞無人夜啟關。", "岫列千屏森葆衛，石藏五色像形顔。", "舉頭待向峽中望，見說青天近一斑。"]'),
('0d72d3b6-bb83-4780-a513-4a9b3558c4be','和趙周錫制幹峽中韻四首  其三','袁說友','宋','宋诗','song-poetry','','[]','急峽高流日夜東，嵌空怪石浪穿礲。',64,'全唐诗/poet.song.161000.json','["急峽高流日夜東，嵌空怪石浪穿礲。", "濤喧灘口波翻雪，雲斷山腰氣吐虹。", "幾陣堂堂峰硉矹，一泉滴滴水玲瓏。", "我行天下今將半，安得名山如此工。"]'),
('59f7eaa1-d3ac-4bba-b976-221e70802b7c','和趙周錫制幹峽中韻四首  其四','袁說友','宋','宋诗','song-poetry','','[]','絕景都忘峽路長，江風時送野花香。',64,'全唐诗/poet.song.161000.json','["絕景都忘峽路長，江風時送野花香。", "峰排玉帳腰凝雪，泉溜珠簾乳滴房。", "後日奇山猶續續，而今偉觀已堂堂。", "雄篇曲盡形容妙，滿袖珠璣到旅囊。"]'),
('b22936dc-7531-41f0-9f9d-10fbe78f5a3c','和同年成峽州韻','袁說友','宋','宋诗','song-poetry','','[]','平生蹤跡鴈門踦，投老猶甘萬里馳。',64,'全唐诗/poet.song.161000.json','["平生蹤跡鴈門踦，投老猶甘萬里馳。", "夜永尚迷行客夢，曉來新得故人詩。", "秋高蓴美念歸處，月白江清下水時。", "此日此身無羽翼，輸君先去訪鴟夷。"]'),
('6d748c2d-4921-4ac4-af41-2f9c654c96b7','過皂角林','袁說友','宋','宋诗','song-poetry','','[]','南北城高俯塹深，過帆猝猝倦登臨。',64,'全唐诗/poet.song.161000.json','["南北城高俯塹深，過帆猝猝倦登臨。", "兩山未遠瓜洲渡，十里俄驚皂角林。", "坐想英靈猶炯炯，眼看祠廟獨陰陰。", "塘村共說興亡處，笑指東河血未沉。"]'),
('740a1a81-1f8f-4832-b80a-ddbe91b5b0b1','和羅春伯奉常寄題稽山閣韻','袁說友','宋','宋诗','song-poetry','','[]','公來祗謁自周行，脚踏稽山意遠翔。',64,'全唐诗/poet.song.161000.json','["公來祗謁自周行，脚踏稽山意遠翔。", "疊嶂排雲煙杳靄，半天得月夜淒涼。", "無言可狀湖山好，有客來時錦繡張。", "底事東吳聲價重，螭頭椽筆冠文場。"]'),
('db79cc0a-5fc3-4dab-ab69-fac7e5021cc9','游齊山用唐杜紫微韻','袁說友','宋','宋诗','song-poetry','','[]','聯鑣出郭疾於飛，好景留人倦式微。',64,'全唐诗/poet.song.161000.json','["聯鑣出郭疾於飛，好景留人倦式微。", "盡日山行惟所適，夕陽堤上詠而歸。", "摩挲苔壁嗟前事，徙倚巖亭惜寸暉。", "空憶樊川秋影去，爲誰重唱縷金衣。"]'),
('c7893129-b71d-468b-b4f4-be8fb1323a1c','泊沙市','袁說友','宋','宋诗','song-poetry','','[]','雪浪雲煙日卷舒，去城遠近聚廛居。',64,'全唐诗/poet.song.161000.json','["雪浪雲煙日卷舒，去城遠近聚廛居。", "千年隄岸圍沙市，十里人煙半竹廬。", "荆國平分荆水闊，楚樓遥接楚天餘。", "江民日與波神狎，只把濤雷當噏噓。"]'),
('91a8d45d-5046-42d0-af7e-e260ce01d4e1','同莫子章方舟下龜溪','袁說友','宋','宋诗','song-poetry','','[]','一舸相從下碧瀾，城南百里話更殘。',64,'全唐诗/poet.song.161000.json','["一舸相從下碧瀾，城南百里話更殘。", "絕知未減在家好，政自不愁行路難。", "舒望最堪詩眼縱，忘形只覺酒腸寬。", "歸來頗訝山頭黑，果是西風一夜寒。"]'),
('ecd78cd4-7d6f-4300-8e48-e5f552cc7cfc','順風至采石','袁說友','宋','宋诗','song-poetry','','[]','快哉真得楚王風，鉦鼓喧江四面雄。',64,'全唐诗/poet.song.161000.json','["快哉真得楚王風，鉦鼓喧江四面雄。", "但欲帆檣催上水，敢辭井路傍西戎。", "江空歲晚飛煙外，人靜霜明過浪中。", "少泊山腰羌笛斷，一樽那肯爲詩窮。"]'),
('74893d9f-dcb8-46ab-a492-51c2fcdce6fd','過楚州用霍希文韻','袁說友','宋','宋诗','song-poetry','','[]','夜入山陽鷁首東，單車出郭更匆匆。',64,'全唐诗/poet.song.161000.json','["夜入山陽鷁首東，單車出郭更匆匆。", "欲知勢扼三江近，政以城高百尺雄。", "此恨終天身未老，何人抵掌氣凌空。", "連雲細草秋風下，把酒長吁問化工。"]'),
('039a4bbd-910e-4017-b56a-9a5ff8a28c9d','被旨往許浦閲兵風雨中舟過梅里','袁說友','宋','宋诗','song-poetry','','[]','濃雲障日卧前山，已覺林深寸步難。',64,'全唐诗/poet.song.161000.json','["濃雲障日卧前山，已覺林深寸步難。", "風雨於人本無意，筋骸如我不禁寒。", "小窗飽聽喧江浪，蕭寺時驚落岸灘。", "慨念興亡千古事，夜闌相對說江干。"]'),
('661f1137-a00b-4227-9a38-7f432e76f884','銅鐵堆','袁說友','宋','宋诗','song-poetry','','[]','千峰插碧繞江面，兩石中分銅鐵堆。',64,'全唐诗/poet.song.161000.json','["千峰插碧繞江面，兩石中分銅鐵堆。", "東岫附庸方崒嵂，西山儼立更崔嵬。", "懸知造物精神巧，幾誤良工斧鑿來。", "萬里西舟今蜀境，安流到此莫辭杯。"]'),
('f8292264-93cb-4a36-a660-e6d7a08189ee','自常熟敲冰行舟半日一夜僅十里','袁說友','宋','宋诗','song-poetry','','[]','到曉纔通十里冰，頗憐黄帽歎征行。',64,'全唐诗/poet.song.161000.json','["到曉纔通十里冰，頗憐黄帽歎征行。", "半篙不下風霜夜，一日之間水陸程。", "無復穩時村路滑，不勝危處斷橋傾。", "驅馳原隰皇華事，筋力猶堪誓此生。"]'),
('aff3a802-9147-499b-8238-c76fb448d030','周錫自蜀歸浙','袁說友','宋','宋诗','song-poetry','','[]','東甌西浙兩夤緣，齊止金陵萬里船。',64,'全唐诗/poet.song.161000.json','["東甌西浙兩夤緣，齊止金陵萬里船。", "風月醉中同客夢，簿書叢裏讀詩篇。", "懷歸念我方投劾，勇去輸君已著鞭。", "歲晚江空帆力滿，長安春好正朝天。"]'),
('7571562b-8bd2-4a73-9e93-854150e5885b','送葉表姪歸鄉','袁說友','宋','宋诗','song-poetry','','[]','枌榆離別幾春秋，作計吳中祇謬悠。',64,'全唐诗/poet.song.161000.json','["枌榆離別幾春秋，作計吳中祇謬悠。", "回首故園三歎息，喜公歸路兩經由。", "懷鄉誰不思邱首，游宦余方愧督郵。", "千里相忘未歸去，家山時向夢中求。"]'),
('d3b41420-68ff-40eb-9c71-40e52a003000','新河','袁說友','宋','宋诗','song-poetry','','[]','路轉風回四面歌，新河磨盡磨盤河。',64,'全唐诗/poet.song.161000.json','["路轉風回四面歌，新河磨盡磨盤河。", "一川漲碧分灘遠，萬柳排青夾岸多。", "此日經行空歎息，當年功績未鎸磨。", "客遊爲愛瀟湘楚，五日之間一再過。"]'),
('32ce3a0a-2f0c-4bd3-acc6-970cafa9d08a','荆州道中','袁說友','宋','宋诗','song-poetry','','[]','硉矹奇峰繞復環，淼茫大水枕前灣。',64,'全唐诗/poet.song.161000.json','["硉矹奇峰繞復環，淼茫大水枕前灣。", "望迷荆楚山川外，浮遍乾坤日夜間。", "舉酒欲吞雲夢去，倚樓無復利名干。", "霧船風纜經多少，老盡行人只此山。"]'),
('cf51b82b-92ef-43d5-b2c1-ea92f9b3eed8','觀潮','袁說友','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','倏見江頭萬鼓催，更聞脚底一聲雷。',64,'全唐诗/poet.song.161000.json','["倏見江頭萬鼓催，更聞脚底一聲雷。", "怒濤直欲浮天去，急浪猶能带雨來。", "豈但皇都誇偉觀，要令區宇絕纖埃。", "靈胥勇志嗟何在，共弔江山付此杯。"]'),
('ee38800d-8cda-43d8-b6e0-c021d156475c','閘柱','袁說友','宋','宋诗','song-poetry','','[]','三丈圍寬兩木靈，千年閘骨狀如城。',64,'全唐诗/poet.song.161000.json','["三丈圍寬兩木靈，千年閘骨狀如城。", "揚帆欲過心先動，擊柱纔聞念已驚。", "東越梅梁猶逞異，南城老樹也爲精。", "昔聞求福木居士，今向枯株免禍成。"]'),
('61dc1ae6-9f0a-4979-b3ea-75933d530fd0','宿鄰水縣','袁說友','宋','宋诗','song-poetry','','[]','酒餘孤館夢初回，漸覺茅簷淅淅來。',64,'全唐诗/poet.song.161000.json','["酒餘孤館夢初回，漸覺茅簷淅淅來。", "夜半山前風薦雨，曉來崖底澗鳴雷。", "賸添崗翠三分色，呈出秧針一寸栽。", "恰得烏雲天外少，鶑花無數惱人懷。"]'),
('96779d25-1e8e-4f95-9aec-d95594e8b7e0','紹興府學齋宿','袁說友','宋','宋诗','song-poetry','','[]','從容黌舍日西流，淺飲猶看夜氣浮。',64,'全唐诗/poet.song.161000.json','["從容黌舍日西流，淺飲猶看夜氣浮。", "小款話時殊淡薄，細論文處轉清幽。", "諸公學業方加銳，一戰功名要早收。", "我了齋祠便歸賦，故園已作夢中游。"]'),
('dd6117d7-ea25-45aa-94b7-a05eda018ffe','釋奠齋宿','袁說友','宋','宋诗','song-poetry','','[]','雲高天白夜沉沉，牆外誰家送遠砧。',64,'全唐诗/poet.song.161000.json','["雲高天白夜沉沉，牆外誰家送遠砧。", "有月林梢鳴翠羽，無風窗下落黄金。", "百年已老安仁鬢，三徑空懷靖節心。", "病眼細書何齟齬，短檠猶得對孤斟。"]'),
('e8493be5-58dd-4236-8f7d-a8189b3d0bd1','和薛公叔留都城韻','袁說友','宋','宋诗','song-poetry','','[]','年來更覺一身難，却掃應須早閉關。',64,'全唐诗/poet.song.161000.json','["年來更覺一身難，却掃應須早閉關。", "老矣壯懷空歲月，歸歟活計只溪山。", "未堪鵾化摇而上，肯類蠅營去復還。", "白璧深藏有餘地，區區何必苦躋攀。"]'),
('01f640ef-6580-49c0-80fa-7460327618b9','和劉叔驥司戶韻','袁說友','宋','宋诗','song-poetry','','[]','不飲無何一味羶，聽渠七字輒欣然。',64,'全唐诗/poet.song.161000.json','["不飲無何一味羶，聽渠七字輒欣然。", "念非公子誰堪比，可奈吾衰不待年。", "料得詩魔排錦繡，却從筆力裹山川。", "蘭亭若未歸修禊，更伴劉郎發祕傳。"]'),
('428c2545-d65a-4e28-8590-1a930efd4e4a','和潘德久韻','袁說友','宋','宋诗','song-poetry','','[]','曾讀桐江路上題，斯文便合請君司。',64,'全唐诗/poet.song.161000.json','["曾讀桐江路上題，斯文便合請君司。", "向來吳會連朝語，晚歲揚州七字詩。", "憂世自憐聞道晚，論心猶恨結交遲。", "帆檣百里孤吟罷，坐愛雄風約雨師。"]'),
('464e775b-9d06-4806-b7c6-0f08cc4e60a9','和陸成父韻','袁說友','宋','宋诗','song-poetry','','[]','功名落落愧强年，晚到淮鄉意惘然。',64,'全唐诗/poet.song.161000.json','["功名落落愧强年，晚到淮鄉意惘然。", "問月高歌聊自適，吟秋苦思替渠憐。", "據鞍剩欲誇馳駿，釃酒猶堪醉擊鮮。", "坐對晴雲浄如拭，水光秋色正連天。"]'),
('54553c22-163f-400e-8062-59ea18d4d0f5','和兼善韻','袁說友','宋','宋诗','song-poetry','','[]','江湖蹤跡厭萍游，只有詩魔老未休。',64,'全唐诗/poet.song.161000.json','["江湖蹤跡厭萍游，只有詩魔老未休。", "平日故人談語句，朞年裹眼識風流。", "自能作意閒中趣，無復關心世外愁。", "趁此百年身偶健，爲君一語竟須酬。"]'),
('246ccd04-861a-4186-b42e-733f51bb4d18','和惠國博韻','袁說友','宋','宋诗','song-poetry','','[]','平生心賞有高蹤，更喜夤緣造化中。',64,'全唐诗/poet.song.161000.json','["平生心賞有高蹤，更喜夤緣造化中。", "語次欲傳須柳子，詩宗不愧是江翁。", "無言可究稱醇德，有眼能看拜下風。", "共覩謝庭蘭玉秀，只今攀桂廣寒宮。"]'),
('74c68911-36b2-4b8d-82b2-7b2d665a2447','用吳知立韻','袁說友','宋','宋诗','song-poetry','','[]','老去胸中句甚豪，清風應笑我徒勞。',64,'全唐诗/poet.song.161000.json','["老去胸中句甚豪，清風應笑我徒勞。", "可憐官事何時了，肯使詩盟取次逃。", "剩欲論交思擊節，不妨飲德要投醪。", "如君豈是長貧者，自古詩成得繡袍。"]'),
('4cf2f0b6-c3f9-4e4b-8a2f-4f79bd89c624','呈浙西張提倉','袁說友','宋','宋诗','song-poetry','','[]','老掾當年意已傾，執鞭雖晚眼仍青。',64,'全唐诗/poet.song.161000.json','["老掾當年意已傾，執鞭雖晚眼仍青。", "繡衣公子初雲漢，璧水先生尚典刑。", "負弩前驅容漫叟，下帷覃思媿玄經。", "催科欲付翻羹手，照我山行定幾星。"]'),
('ba34e4ac-67ac-4699-87cc-42c54ef50e7b','入山呈孫使君','袁說友','宋','宋诗','song-poetry','','[]','平生懶慢豈能剛，身外微官似漫郎。',64,'全唐诗/poet.song.161000.json','["平生懶慢豈能剛，身外微官似漫郎。", "不怪閒居爲消渴，何勞多酌本醒狂。", "雪晴欲試穿雲履，背冷仍尋曝日牀。", "爲想騎牛破山碧，晚風吹笛野梅香。"]'),
('27c5a9b3-38ed-47c2-ae26-721483a27255','簡唐英同年四首  其一','袁說友','宋','宋诗','song-poetry','','[]','春風已落百花中，鏡裏空嗟兩鬢蓬。',64,'全唐诗/poet.song.161000.json','["春風已落百花中，鏡裏空嗟兩鬢蓬。", "病懶未能禁酒困，多愁元不爲詩窮。", "偶然貞曜生同世，尤喜丁寬易未東。", "聚散由來皆造化，一篇我欲謝天公。"]'),
('0f9cdd3e-c4dc-459f-855f-faa56fca230b','簡唐英同年四首  其二','袁說友','宋','宋诗','song-poetry','','[]','早起孤舟掀浪中，自憐老大要飄蓬。',64,'全唐诗/poet.song.161000.json','["早起孤舟掀浪中，自憐老大要飄蓬。", "風前索酒輕寒殺，夢裏尋詩始意窮。", "帆飽急隨山脚去，櫓回强趁水頭東。", "明朝已作掃門計，未必堂堂舍蓋公。"]'),
('db80a2d4-6938-4823-9489-dc4a42f220c5','簡唐英同年四首  其三','袁說友','宋','宋诗','song-poetry','','[]','書生懷贄大門中，一見歸來話小蓬。',64,'全唐诗/poet.song.161000.json','["書生懷贄大門中，一見歸來話小蓬。", "坐喜情文渾不薄，退嗟吾道豈憂窮。", "更將儒術重熙載，要使君心亦欲東。", "若也銘勳在彝鼎，古今何止一周公。"]'),
('d46ba1c6-d66b-4c9d-a3fb-e19f0ca9f2f9','簡唐英同年四首  其四','袁說友','宋','宋诗','song-poetry','','[]','舊言山色有無中，今日環觀在短蓬。',64,'全唐诗/poet.song.161000.json','["舊言山色有無中，今日環觀在短蓬。", "遊子不堪歸路冷，篙師愁殺裹囊窮。", "便回溪口風尤急，欲到山頭月已東。", "贏得閒言擾詩社，煩君更語主人公。"]'),
('eb96cee9-a5a1-4679-919a-113223a066f0','丁端叔茶馬會同年同庚','袁說友','宋','宋诗','song-poetry','','[]','竹林賓主樂襟期，並榜齊年兩見之。',64,'全唐诗/poet.song.161000.json','["竹林賓主樂襟期，並榜齊年兩見之。", "丙午同生雖共老，甲辰笑我獨爲雌。", "秋鴻社燕時難值，桂酒椒漿醉莫辭。", "半是天涯老行客，耆英當繼洛中詩。"]'),
('9fe32330-1998-4303-8047-41021135e7c8','登蓬萊閤','袁說友','宋','宋诗','song-poetry','','[]','癡兒官事苦相臨，每到蓬萊慰賞心。',64,'全唐诗/poet.song.161000.json','["癡兒官事苦相臨，每到蓬萊慰賞心。", "一水縈湖連海去，片雲带雨入山深。", "自憐老客從渠晚，喜有詩翁到此尋。", "中外升沉政懸絕，强抽荒思續高吟。"]'),
('3fe91052-57d7-400f-aafd-e42d85fec116','饋春茶于制司屬官','袁說友','宋','宋诗','song-poetry','','[]','戊午新芽上蜀江，表情未有敢先嘗。',64,'全唐诗/poet.song.161000.json','["戊午新芽上蜀江，表情未有敢先嘗。", "幾年爭鬭無雙品，萬里書來第一綱。", "水截龍章浮碾玉，爐煎蟹眼試憑湯。", "知君文字五千卷，正欲冥搜錦繡腸。"]'),
('349c873b-076f-4236-93d2-4801fc2fa3f6','求酒於邵元實刪定','袁說友','宋','宋诗','song-poetry','','[]','骨相酸寒不足論，平生心賞舊家村。',64,'全唐诗/poet.song.161000.json','["骨相酸寒不足論，平生心賞舊家村。", "七年誤索長安米，百病幾成楚客魂。", "命薄不堪嗟分定，官閒猶得荷君恩。", "秋風一醉餘疴殄，須乞莊生五石樽。"]'),
('85b063c1-295f-4d59-8b74-d96954d8f94e','乞酒於林子長通判','袁說友','宋','宋诗','song-poetry','','[]','衰顔得酒尚能赬，笑我維罍恥弗盈。',64,'全唐诗/poet.song.161000.json','["衰顔得酒尚能赬，笑我維罍恥弗盈。", "無計青州幾從事，可憐白面一書生。", "新篘競說鄰家熟，好句慚無健筆成。", "傳語白衣人記取，何須秋帽始關情。"]'),
('fc95d1a6-8d97-4897-84ff-a0876b7e8f76','謝誠齋惠酒','袁說友','宋','宋诗','song-poetry','','[]','褰裳樂得送迎翁，遣句猶煩七字工。',64,'全唐诗/poet.song.161000.json','["褰裳樂得送迎翁，遣句猶煩七字工。", "頗識當年斤斧手，却慚昔日馬牛風。", "平生楊敬惟稱項，晚歲侯芭只守雄。", "便把黄封紅客眼，一尊已當百壺豐。"]'),
('c4c61cd1-7619-4c37-b454-865df45bbf23','饋蝦腊彎魚乾於端叔','袁說友','宋','宋诗','song-poetry','','[]','東西萬里苦相望，海物時來自故鄉。',64,'全唐诗/poet.song.161000.json','["東西萬里苦相望，海物時來自故鄉。", "兩眼尚能驅水族，一彎猶解詫丁香。", "莫孤念遠勤將意，且欲均甘未敢嘗。", "有詔知君便歸去，古人驛寄願頻將。"]'),
('56a60d5a-6fa7-4308-b761-9bf433c985cc','和沈德遠寄江鰩韻','袁說友','宋','宋诗','song-poetry','','[]','粉身截玉慰渠貪，浪迹泥塗遽著籃。',64,'全唐诗/poet.song.161000.json','["粉身截玉慰渠貪，浪迹泥塗遽著籃。", "坐缺江生嗟不樂，詩來東老謝分甘。", "世間風味鄞江頰，傳裏形容太史談。", "欲報瓊瑶無一可，移文空到北山南。"]'),
('795727e0-4217-49b0-9a4e-975f3854c9f7','橄欖來自嘉州','袁說友','宋','宋诗','song-poetry','','[]','筠籠相逐到天涯，喜見森森色正佳。',64,'全唐诗/poet.song.161000.json','["筠籠相逐到天涯，喜見森森色正佳。", "尚想紅鹽落青子，未誇黄蜜挂蒼崖。", "眼中鄉味催歸夢，足下跫音慰遠懷。", "稍待酒殘回齒頰，餘甘猶足助談諧。"]'),
('b6dfdd1d-ab2e-40c2-b29a-38a5bafeb0ca','岳大用寺簿惠佩刀','袁說友','宋','宋诗','song-poetry','','[]','文陣談鋒不可當，小恢游刃向朝行。',64,'全唐诗/poet.song.161000.json','["文陣談鋒不可當，小恢游刃向朝行。", "一夫敵爾嗟長劍，十九人中見穎囊。", "徐子身非逢季札，呂虔心已識王祥。", "善刀我亦知藏去，他日猶煩賜尚方。"]'),
('d92a42ca-9e21-485e-853a-d08acba6fdbd','謝梁飭父通判登樓賞雪之約','袁說友','宋','宋诗','song-poetry','','[]','蘢葱天闊曉光浮，滿地斜飛玉作毬。',64,'全唐诗/poet.song.161000.json','["蘢葱天闊曉光浮，滿地斜飛玉作毬。", "好趁陽春歌白雪，政須從事謁青州。", "打門報我樽前約，乘興須君剡上遊。", "清絕有人誇盛事，貳車携客醉南樓。"]'),
('8b5e90b4-f1ef-4bc9-ac2b-391d83947e29','和程閣學觀雪韻','袁說友','宋','宋诗','song-poetry','','[]','入竹投窗細細添，兩山瓊玉稱遐瞻。',64,'全唐诗/poet.song.161000.json','["入竹投窗細細添，兩山瓊玉稱遐瞻。", "巧於夜半將新歲，每以風回蹴上簾。", "寒雀棲枝驚落屑，饑烏鳴食訝堆鹽。", "正須度臘成三白，已覺西風勢轉嚴。"]'),
('4689dfb8-8419-4e6e-b8c4-122ca637aee3','和梁曹池陽道中遇雪韻','袁說友','宋','宋诗','song-poetry','','[]','癡兒汩汩尚尋梅，點檢花梢次第開。',64,'全唐诗/poet.song.161000.json','["癡兒汩汩尚尋梅，點檢花梢次第開。", "客裏相逢秋日好，雪中重喜故人來。", "歲寒過我留佳句，夜半論文酹此杯。", "毋疾其驅行有詔，江頭準擬送君回。"]'),
('14f329cf-2d28-40f9-a210-e15cce7e4589','臘雪二首  其一','袁說友','宋','宋诗','song-poetry','','[]','歲事無多臘近殘，謝渠飛屑破天慳。',64,'全唐诗/poet.song.161000.json','["歲事無多臘近殘，謝渠飛屑破天慳。", "褥祠空愧兼旬力，造物惟消一夜間。", "是則化工端有意，要於官政亦相關。", "雪催詩後詩催雪，更欲堆鹽滿四山。"]'),
('29ca6997-29d2-4bca-beff-9ef6348c9dfb','臘雪二首  其二','袁說友','宋','宋诗','song-poetry','','[]','無計遮留歲月殘，頗驚節物愧才慳。',64,'全唐诗/poet.song.161000.json','["無計遮留歲月殘，頗驚節物愧才慳。", "可人臘雪偏宜處，屈指春風未到間。", "猶得微吟供午枕，不須高卧閉晨關。", "晚來碎玉零珠後，已老蘇州一半山。"]'),
('eb47926b-4b1e-43f0-a5c3-9a8420c24480','喜雪','袁說友','宋','宋诗','song-poetry','','[]','玉龍方急戰寒聲，滿陣江風雪作茵。',64,'全唐诗/poet.song.161000.json','["玉龍方急戰寒聲，滿陣江風雪作茵。", "準擬豐年須造物，編排佳境付詩人。", "莫辭樽酒偏勞勸，更喜江梅欲鬭新。", "愧我爲州無善狀，楊花何事已先春。"]'),
('50850394-af9f-4390-a7ea-e012c015eafb','誠齋指簷頭雪爲詩材二首  其一','袁說友','宋','宋诗','song-poetry','','[]','春風著意向春宵，巧作冰澌細細飄。',64,'全唐诗/poet.song.161000.json','["春風著意向春宵，巧作冰澌細細飄。", "正好千門競燈火，故添萬瓦燦瓊瑶。", "誰憐梅蕊猶含玉，大遣楊花爲奪標。", "一段風光付詩手，物華正恐爲君撩。"]'),
('93d0f200-4155-4035-b7df-11205d4c24b2','誠齋指簷頭雪爲詩材二首  其二','袁說友','宋','宋诗','song-poetry','','[]','使旌獵獵晝連宵，賸說吟邊湧思飄。',64,'全唐诗/poet.song.161000.json','["使旌獵獵晝連宵，賸說吟邊湧思飄。", "曉枕已哦千樹雪，夜船更踏一溪瑶。", "誰將春霰天然巧，來伴寒梅別樣標。", "贏得袁家僵卧者，開門今爲好詩撩。"]'),
('38081c60-0559-489a-8ef8-b9005bed52ed','立春日雪','袁說友','宋','宋诗','song-poetry','','[]','料理風光興未殘，老無詩手一何慳。',64,'全唐诗/poet.song.161000.json','["料理風光興未殘，老無詩手一何慳。", "新傳綵勝排枝上，趁得冰花落鬢間。", "噪雀曉來埋屋角，土牛聲已動譙關。", "寒窗我欲觴眉壽，不是羊羔醉玉山。"]'),
('7fe3844b-b220-4ce2-b309-deef52e5d214','恭和御製賜進士詩韻二首  其一','袁說友','宋','宋诗','song-poetry','','[]','雲漢昭回下建章，鸞翔鳳翥燦龍光。',64,'全唐诗/poet.song.161000.json','["雲漢昭回下建章，鸞翔鳳翥燦龍光。", "宸奎錯落皆謨訓，聖語丁寧示抑揚。", "自古求言開數路，只今兼聽極羣方。", "一篇默寓憂勤意，正爲成王不敢康。"]'),
('7b81cf49-c56d-417f-82e8-89643db5b5f7','恭和御製賜進士詩韻二首  其二','袁說友','宋','宋诗','song-poetry','','[]','堯言不數漢文章，漫說唐人萬丈光。',64,'全唐诗/poet.song.161000.json','["堯言不數漢文章，漫說唐人萬丈光。", "百辟共知尊上指，羣儒何止戴言揚。", "絲綸甫幸來中禁，琬琰俄欣奏上方。", "京邑小臣觀盛事，願輸忠悃贊明康。"]'),
('051c6d4f-2fe6-45de-a79d-b7f510008b2e','車駕過重華宮和陳止齋韻','袁說友','宋','宋诗','song-poetry','','[]','曉到觚棱簇仗齊，千官星拱馬無嘶。',64,'全唐诗/poet.song.161000.json','["曉到觚棱簇仗齊，千官星拱馬無嘶。", "清塵警蹕來宮闕，夾道歡聲浹耄倪。", "孝治未應誇鄭隧，皇威今已竦邊鼙。", "小臣何以揚君德，手舞相呼醉月溪。"]'),
('9cd1c8c2-19bf-407e-a401-6f6956293692','擬詠展觀太上皇帝御書','袁說友','宋','宋诗','song-poetry','','[]','龍顔祗肅閲堯章，寶軸神毫赫有光。',64,'全唐诗/poet.song.161000.json','["龍顔祗肅閲堯章，寶軸神毫赫有光。", "八法心傳齊帝學，萬年奎畫與天長。", "襲藏肯比唐三傑，墨妙尤卑晉二王。", "舜治方隆定于一，區區發問陋梁襄。"]'),
('1189da3a-9aea-4ec5-956e-b2973eec087d','擬詠宴羣臣','袁說友','宋','宋诗','song-poetry','','[]','宴錫蓬山煥舊章，羣工列席侍龍光。',64,'全唐诗/poet.song.161000.json','["宴錫蓬山煥舊章，羣工列席侍龍光。", "加籩折俎君恩重，合奏迴風韻語長。", "擊筑爲歌嗤漢祖，舉觴隆禮視周王。", "幸哉盛事今逢見，願赴功名敢入襄。"]'),
('d1b99e4b-c58c-4174-9450-3c981dd12cae','端叔奉詔還朝二首  其一','袁說友','宋','宋诗','song-poetry','','[]','清樽連日話辛酸，正爲中年作別難。',64,'全唐诗/poet.song.161000.json','["清樽連日話辛酸，正爲中年作別難。", "二十年間嗟契闊，八千里外得團欒。", "湖山覺夢俱萍迹，風月題詩徧錦官。", "一舸輸君已僊去，微吟空抱屈平嘆。"]'),
('751e8cb3-b017-4103-b332-3fdfe58aec85','端叔奉詔還朝二首  其二','袁說友','宋','宋诗','song-poetry','','[]','萬目環觀一節東，江酣遲日漾春風。',64,'全唐诗/poet.song.161000.json','["萬目環觀一節東，江酣遲日漾春風。", "君王恨見嚴徐晚，廊廟方資稷契忠。", "四蜀正須煩筆下，一言知已定胸中。", "少焉我欲歸田去，拭目期君鼎鼐功。"]'),
('8ec4b952-ddd4-4dc7-b8c3-ac28b58af3c7','閲兵給賚','袁說友','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','小臣銜命入雲屯，聖主如天詔語溫。',64,'全唐诗/poet.song.161000.json','["小臣銜命入雲屯，聖主如天詔語溫。", "萬甲衝風隆士氣，一言挾纊荷君恩。", "頗驚霹靂燒殘壘，更想蒙衝上海門。", "欲挽長江問豪傑，豈無擊檝歎中原。"]'),
('c5d602d1-e4f0-4e91-8e15-3567b864760b','盧德華郎中將漕福建','袁說友','宋','宋诗','song-poetry','','[]','疇昔相從在帝關，更于歲晚接清班。',64,'全唐诗/poet.song.161000.json','["疇昔相從在帝關，更于歲晚接清班。", "同朝所恨常疎闊，一歲之中幾往還。", "便合橫翔來楚路，未應清夢落閩山。", "誰將好雪留征櫂，毋疾其驅有詔頒。"]'),
('11c3f64e-a472-425c-a779-14d0c6d87f21','和虞仲房潼川運使韻','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖樽俎憶風流，今日檣烏過我州。',64,'全唐诗/poet.song.161000.json','["西湖樽俎憶風流，今日檣烏過我州。", "萬里相忘嗟又別，九華何惜更同游。", "中郎有字新鎸石，小子無言只點頭。", "及此公餘多暇日，爲君作計且邀留。"]'),
('124a8142-bcc0-4e24-a7be-4d39becdcbb1','再賦','袁說友','宋','宋诗','song-poetry','','[]','飄然擊檝問中流，仗節觀風十四州。',64,'全唐诗/poet.song.161000.json','["飄然擊檝問中流，仗節觀風十四州。", "見說九重天語好，不妨萬里蜀山游。", "大書競照光山色，好句應題灧澦頭。", "稍辦澄清早歸去，周南寧復嘆淹留。"]'),
('36ca04ec-b25f-4ea9-b926-a1d83c0ce492','和閭丘資深轉運判官送張同年韻','袁說友','宋','宋诗','song-poetry','','[]','造門剝啄笑談餘，過我頻迂長者車。',64,'全唐诗/poet.song.161000.json','["造門剝啄笑談餘，過我頻迂長者車。", "八詠繼吳推翰長，一封諭蜀屬相如。", "岷峨詩富追風雅，韶濩聲諧復古初。", "仰止騷壇方北面，不堪官事蠹書魚。"]'),
('b1e969db-32e9-4bc6-b473-d2ea1ef3c930','和浦勉道轉運判官巡行出關韻','袁說友','宋','宋诗','song-poetry','','[]','濤雷殷晝候前驅，駟馬橋邊使者車。',64,'全唐诗/poet.song.161000.json','["濤雷殷晝候前驅，駟馬橋邊使者車。", "風約江聲喧笑語，山迎雨脚傍閻閭。", "城頭北海傾樽後，馬耳西風攬轡初。", "關外秋來聞小熟，更將餘瘵入呵噓。"]'),
('91c3fa7c-f18a-49d4-b036-9d6ac963da11','和許深父轉運判官韻二首  其一','袁說友','宋','宋诗','song-poetry','','[]','我輩難忘故舊情，爲君滿意說詩清。',64,'全唐诗/poet.song.161000.json','["我輩難忘故舊情，爲君滿意說詩清。", "拋磚不愧塵埃想，剖蚌俄驚的皪明。", "宦路幾年嗟契闊，長安累月話平生。", "詩筩却趁郵筩急，吟到揚州更袖呈。"]'),
('6be468a6-7268-468f-b3bf-faa0c1ed165f','和許深父轉運判官韻二首  其二','袁說友','宋','宋诗','song-poetry','','[]','詩裏論交淡淡情，箇中風味不勝清。',64,'全唐诗/poet.song.161000.json','["詩裏論交淡淡情，箇中風味不勝清。", "錦囊著句知才盡，山色逢人作意明。", "已覺頭顱侵晚景，尚堪風月快餘生。", "與君握手關心處，媿乏琅玕腹可呈。"]'),
('33d4b778-f980-4837-999d-763f84b1088f','送吳子明知閬州','袁說友','宋','宋诗','song-poetry','','[]','聖主方勤西顧憂，大朝臨遣遴賢侯。',64,'全唐诗/poet.song.161000.json','["聖主方勤西顧憂，大朝臨遣遴賢侯。", "蘭香昔在潛郎地，符竹今分古閬州。", "蜀道難時雖萬里，漢川佳處正三秋。", "莫嗟身落江湖遠，魏闕心存記子牟。"]'),
('692a3dac-afff-4a4a-ba01-f0f1f60de7e0','送同年曾南仲寺丞知溫州','袁說友','宋','宋诗','song-poetry','','[]','久同朝蹟又同年，更送旌麾過海邊。',64,'全唐诗/poet.song.161000.json','["久同朝蹟又同年，更送旌麾過海邊。", "多士向來親戴席，斯民今幸得蘇天。", "潛心閣上書千卷，鴈蕩山中草一川。", "小待公餘尋舊迹，便歸玉笋聽鳴鞭。"]'),
('894a5eb6-32b2-4cb0-bdd2-659b2c03a030','送樓攻愧知婺州二首  其一','袁說友','宋','宋诗','song-poetry','','[]','壯年才氣壓詞場，衆已相期白玉堂。',64,'全唐诗/poet.song.161000.json','["壯年才氣壓詞場，衆已相期白玉堂。", "垣制孰非經大手，斯文無復數他楊。", "諸公政爾需調鼎，一語翻然忽抗章。", "汲黯固知當大用，得君徒欲重淮陽。"]'),
('e9af64fb-694f-4f9c-889f-cce0709ea4e6','送樓攻愧知婺州二首  其二','袁說友','宋','宋诗','song-poetry','','[]','三十年間企絕塵，久同朝蹟話平生。',64,'全唐诗/poet.song.161000.json','["三十年間企絕塵，久同朝蹟話平生。", "論文密處雖朋友，投分深時即弟兄。", "自恨我無分袂語，但輸君已著鞭行。", "東陽一葦杭之便，毋惜公餘蚤寄聲。"]'),
('3c37f394-a1ed-4235-bc3d-543e94b7725d','日華書自通州來言其同僚多唱酬','袁說友','宋','宋诗','song-poetry','','[]','題輿贏得錦囊歸，酬唱西崑事可追。',64,'全唐诗/poet.song.161000.json','["題輿贏得錦囊歸，酬唱西崑事可追。", "久不陪君三日語，政須嚥子百篇詩。", "寧甘咄咄癡兒事，稍愧紛紛俗吏爲。", "我亦湖山多暇日，秋蟬時解噪寒枝。"]'),
('284b6bdd-bc32-4dff-96b0-0c4d127512e5','餞金使出北關風雨大作','袁說友','宋','宋诗','song-poetry','','[]','出郭初行十里賒，狂風急雨閙田家。',64,'全唐诗/poet.song.161000.json','["出郭初行十里賒，狂風急雨閙田家。", "香秔飽熟雲翻浪，蕎麥新開雪作花。", "淺水半村環野趣，好山一带接京華。", "晚來踏盡臨平路，風脚全收雨脚斜。"]'),
('ffe7b349-9e82-4698-a916-102bc99ea9c8','次常熟縣先君舊所攝宰也','袁說友','宋','宋诗','song-poetry','','[]','衝寒一舸下琴川，小纜依依市柳邊。',64,'全唐诗/poet.song.161000.json','["衝寒一舸下琴川，小纜依依市柳邊。", "花縣重來聽好語，棠陰深處不論年。", "釣遊頗憶兒童舊，風物徒驚歲月遷。", "老恐不任奔走力，問儂何日賦歸田。"]'),
('863e856b-987d-48d5-818b-515f0ce43d6d','守郡不能同憲使倉使游靈巖','袁說友','宋','宋诗','song-poetry','','[]','秋風敲葉漾湖光，兩兩星華古寺傍。',64,'全唐诗/poet.song.161000.json','["秋風敲葉漾湖光，兩兩星華古寺傍。", "曉日一川迎使節，晚山十里送歸艎。", "風流我已非山簡，賓客公應念葛彊。", "豈是清游本無分，紛紛鴈鶩苦相妨。"]'),
('81bff464-4fd4-41dd-a87e-ddff39078cb7','司庾會稽道中答衢民綵幟送行','袁說友','宋','宋诗','song-poetry','','[]','征車何事不容征，綵旆歌謠塞路津。',64,'全唐诗/poet.song.161000.json','["征車何事不容征，綵旆歌謠塞路津。", "徒以平生多拙政，偶於歲晚得衢民。", "我方州縣慚尸祿，汝向閭閻切愛身。", "料得去思均彼此，一詩聊復慰邦人。"]'),
('da82425b-4871-4783-aefa-ba68478305ba','過池陽舊治和呂子西韻','袁說友','宋','宋诗','song-poetry','','[]','浮沈宦海幾春秋，歲晚重來舊典州。',64,'全唐诗/poet.song.161000.json','["浮沈宦海幾春秋，歲晚重來舊典州。", "昔日青山雖在眼，故侯白髮已盈頭。", "吟邊感慨關情久，忙裏工夫著意偷。", "聞說峽江春漲晚，捲帆聊爲此邦留。"]'),
('d7dc2d0c-1605-4a0f-935b-dd6ce659e606','送惠縣丞之官','袁說友','宋','宋诗','song-poetry','','[]','立之何事屈藍田，隠忍功名古已然。',64,'全唐诗/poet.song.161000.json','["立之何事屈藍田，隠忍功名古已然。", "預信鵷鴻只他日，莫嫌鳬鶩尚頻年。", "征帆夜濕三更雨，去路人欣八月天。", "話別匆匆毋重惜，一封丹詔下天邊。"]'),
('d06b4333-d76b-4f2b-ad10-61ab328a2538','和魏南伯縣丞韻','袁說友','宋','宋诗','song-poetry','','[]','著語相過見一斑，我慚尺寸强躋攀。',64,'全唐诗/poet.song.161000.json','["著語相過見一斑，我慚尺寸强躋攀。", "羈懷衮衮三江水，去路迢迢萬里山。", "酒盞逢花尋客處，詩筒將月對船間。", "固應侯喜多知己，未必詩聲只汗顔。"]'),
('4869cf34-4aa7-4523-8fa9-1443d4381718','和洪叔昞主簿浮玉亭韻','袁說友','宋','宋诗','song-poetry','','[]','亭爲君來又得名，公餘贏取眼雙明。',64,'全唐诗/poet.song.161000.json','["亭爲君來又得名，公餘贏取眼雙明。", "溪光影碎黄金艷，波面聲流白玉琤。", "夜半吳歌緣底恨，晚來山色不勝情。", "風光我欲平分破，故把吟邊當結盟。"]'),
('0bcbd24f-abe1-40b5-b354-d8eea172cbb4','肅客借重金紫綬','袁說友','宋','宋诗','song-poetry','','[]','平生青紫濫於身，更冒金章肅使賓。',64,'全唐诗/poet.song.161000.json','["平生青紫濫於身，更冒金章肅使賓。", "何以假爲誠豈敢，烏知非有笑無因。", "猨狙自是羞華服，鵷鷺姑容接後塵。", "回首紛紛天下事，有時宜假不宜真。"]'),
('784de2bd-d00a-42c4-a890-8d7c5f7fd419','成都府學釋奠','袁說友','宋','宋诗','song-poetry','','[]','西風淅淅露漙漙，釋菜雍容禮可觀。',64,'全唐诗/poet.song.161000.json','["西風淅淅露漙漙，釋菜雍容禮可觀。", "冠带三千嚴鵠立，風雲九萬欲鵬摶。", "錦江曾吐胸中鳳，泮水新回筆下瀾。", "拭目諸君快秋捷，臚傳高壓萬人看。"]'),
('619185ae-ae29-4daf-8d1d-bf4a7f712324','送呂武仲司戶范純之司法赴南宮試','袁說友','宋','宋诗','song-poetry','','[]','欣然願作送行詩，盛事江邦獨見之。',64,'全唐诗/poet.song.161000.json','["欣然願作送行詩，盛事江邦獨見之。", "釃酒且同明月醉，驅車未怕朔風吹。", "相逢暫入紅蓮幕，穩去高攀丹桂枝。", "莫負玉階方寸地，爲言民力要扶持。"]'),
('3bcd8d32-d9e0-4b26-998f-f286c26e10ff','送柯伯東省試','袁說友','宋','宋诗','song-poetry','','[]','道義如君只幾人，相從了不見塵侵。',64,'全唐诗/poet.song.161000.json','["道義如君只幾人，相從了不見塵侵。", "一樽但覺論文細，三畫從知得意深。", "自是强年應折桂，不妨朞月早傳音。", "我今已辦如椽筆，擬稱瓊林最後吟。"]'),
('705ee970-93f6-4ecd-95a2-dc03ec4c9107','送惠補之昆仲秋試','袁說友','宋','宋诗','song-poetry','','[]','斑斑蘭玉不勝清，長羨于門久日榮。',64,'全唐诗/poet.song.161000.json','["斑斑蘭玉不勝清，長羨于門久日榮。", "共慶兩蘇離蜀道，從今二宋到神京。", "三年刻楮真餘事，一日乘槎定策名。", "想得頤山來歲好，綠袍黄裏照溪明。"]'),
('5e33fb9d-049d-4ce4-949f-94ae4c9c9058','送聘儒姪秋試','袁說友','宋','宋诗','song-poetry','','[]','八月靈槎萬里秋，乘風得雋要遨頭。',64,'全唐诗/poet.song.161000.json','["八月靈槎萬里秋，乘風得雋要遨頭。", "吾家連已躋儒級，汝業今宜濟巨舟。", "掘井莫令嗟九仞，善刀終自見全牛。", "儒冠豈解真相誤，有志應當萬戶侯。"]'),
('b935709e-863e-4d51-9097-e26abc716392','送薛公叔秋試','袁說友','宋','宋诗','song-poetry','','[]','流落相逢霅水濱，與君傾蓋即平生。',64,'全唐诗/poet.song.161000.json','["流落相逢霅水濱，與君傾蓋即平生。", "湖山十里雙溪畔，賓主三年一日情。", "學海波瀾誇健筆，夜窗燈火幾長檠。", "不堪送客杭州路，更聽驚人快一鳴。"]'),
('adf8e328-39a6-4c5e-9b7a-ebf6a4fd71a5','鹿鳴宴','袁說友','宋','宋诗','song-poetry','','[]','秋影涵江暇日長，銀袍濟濟宴公堂。',64,'全唐诗/poet.song.161000.json','["秋影涵江暇日長，銀袍濟濟宴公堂。", "九華佳氣眉間色，千佛高名馬上郎。", "賸數連珠誇瑞應，會看僊桂滿枝芳。", "春風得意歸來好，衣錦聯鑣入故鄉。"]'),
('ffe04b41-d7e3-4d36-8eee-bc6d342052b4','成都府鹿鳴宴','袁說友','宋','宋诗','song-poetry','','[]','大啟文明會勝流，同升更合上西樓。',64,'全唐诗/poet.song.161000.json','["大啟文明會勝流，同升更合上西樓。", "三春得意桃花浪，八月乘槎桂子秋。", "結綬偏應登鳳闕，拏雲直欲釣鰲頭。", "乘除但看今年好，六八名高五十州。"]'),
('55ac971d-1b06-4056-8196-00b82c1ceb53','集同年於聚景圖','袁說友','宋','宋诗','song-poetry','','[]','慈恩回首幾番春，樽酒相期在帝京。',64,'全唐诗/poet.song.161000.json','["慈恩回首幾番春，樽酒相期在帝京。", "人事好乖知歲久，天宮作意得朝晴。", "向來禁籞所未到，同此英遊真可榮。", "無奈斜陽又催去，更憑餘酌話平生。"]'),
('8f206260-488b-40a9-88a7-ad8ad974ac95','餞送蜀進士入奉廷對','袁說友','宋','宋诗','song-poetry','','[]','蜀才卓犖照賓筵，秀出斯文萬選錢。',64,'全唐诗/poet.song.161000.json','["蜀才卓犖照賓筵，秀出斯文萬選錢。", "聖主龍飛初策士，皇朝春好正朝天。", "丹墀獨對三千字，黄甲重魁四十年。", "歸把羣書觀未見，要令學業到純全。"]'),
('5bdc738f-c98f-40cb-b995-25b897e93349','宴許成子魏華文二魁吳文伯節判陳表之教授盧仲修軍資以考西省試同集','袁說友','宋','宋诗','song-poetry','','[]','晝繡歸來自帝京，魁星雙照錦官城。',64,'全唐诗/poet.song.161000.json','["晝繡歸來自帝京，魁星雙照錦官城。", "持衡稱職真能事，勸駕何功亦與榮。", "細與論文重款接，要看落筆更縱橫。", "我歸便作江湖計，試目需君輔太平。"]'),
('5db7a1e5-1a95-4476-9df1-154af98ec9c8','同張元善集癸未同年','袁說友','宋','宋诗','song-poetry','','[]','同年幾合幾分違，三十年間見日稀。',64,'全唐诗/poet.song.161000.json','["同年幾合幾分違，三十年間見日稀。", "尊酒相逢今也幸，詩書論政舊焉依。", "慈恩故事嗟回首，吳地清談對落暉。", "平世功臣在公等，尚期努力佐龍飛。"]'),
('4103eecf-a49a-4e8b-811d-fd00d3717896','和薛子晉來慶癸未登第韻二首  其一','袁說友','宋','宋诗','song-poetry','','[]','雲霧油然託應龍，姓名偶徹大明宮。',64,'全唐诗/poet.song.161000.json','["雲霧油然託應龍，姓名偶徹大明宮。", "臚傳殿廡千官肅，聲到旌旗萬馬雄。", "黄蝶飛來驚拜命，青衫誤著敢言功。", "如何李郃猶能第，造物何心本至公。"]'),
('4fb5ca72-91a9-46bd-8aca-533cd25ae078','和薛子晉來慶癸未登第韻二首  其二','袁說友','宋','宋诗','song-poetry','','[]','寒荄也趁百花新，眼懶猶貪上國春。',64,'全唐诗/poet.song.161000.json','["寒荄也趁百花新，眼懶猶貪上國春。", "五技怪能成薄命，一名却喜繼前人。", "喚將好意詩頻賦，洗却閒憂酒再巡。", "底事牛堪有歸序，韓公平日最相親。"]'),
('e1a963ce-e7cb-4da0-bb53-12fb0e2209d6','會新第進士和陳振享韻','袁說友','宋','宋诗','song-poetry','','[]','梧桐風細月將樓，猶得公餘款俊游。',64,'全唐诗/poet.song.161000.json','["梧桐風細月將樓，猶得公餘款俊游。", "喜入芳樽涼徹夜，風生綺席氣橫秋。", "兩魁前躅高三輔，八雋飛觴照一州。", "屈指吳門多盛事，眼看勳業佐宸旒。"]'),
('917a5fce-7e15-49ec-a8a7-0952039f89d2','蜀進士許成子魁天下用其殿前賦詩韻以志喜','袁說友','宋','宋诗','song-poetry','','[]','岷峨策足問修程，入對明光近太清。',64,'全唐诗/poet.song.161000.json','["岷峨策足問修程，入對明光近太清。", "五十年間多士賦，三千筆下一魁榮。", "斯文焜燿由奎畫，是處流傳仰蜀纓。", "我已夤緣觀盛事，更看公等致隆平。"]'),
('b62789fd-806e-484f-b968-213a19f56b72','送誠齋二首  其一','袁說友','宋','宋诗','song-poetry','','[]','誰作朝陽一鳳鳴，公朝今復歎斯人。',64,'全唐诗/poet.song.161000.json','["誰作朝陽一鳳鳴，公朝今復歎斯人。", "抗章寧奪三軍帥，去國尤輕一葉身。", "政以青蒲姑夕駐，更聞白簡爲前陳。", "只今小試回天力，它日擎天看柱臣。"]'),
('17482758-1380-4fd5-aa93-168b095dbd26','送誠齋二首  其二','袁說友','宋','宋诗','song-poetry','','[]','長裾端欲曳賓墀，人事何乖遽別離。',64,'全唐诗/poet.song.161000.json','["長裾端欲曳賓墀，人事何乖遽別離。", "未盡胸中懷舊意，又吟江上送行詩。", "公名此去如山重，我老誰憐似足踦。", "憑得征鴻寄消息，書來猶記別君時。"]'),
('a9a1d60a-7c26-484f-b9f7-6ee4bdb12c89','寄李兼善','袁說友','宋','宋诗','song-poetry','','[]','湖山昔日記清游，百遍相過語未休。',64,'全唐诗/poet.song.161000.json','["湖山昔日記清游，百遍相過語未休。", "遠邇漫勞人室念，東西空望浙江流。", "中年別去情尤惡，幅紙書來意轉愁。", "歲晚漸於詩興好，待君歸後飽賡酬。"]'),
('4e396d3f-a16b-4d91-8429-b453d23093c4','祝子正從范使君鍛以詩寄之','袁說友','宋','宋诗','song-poetry','','[]','柳下嵇郎好在無，深居應得靜工夫。',64,'全唐诗/poet.song.161000.json','["柳下嵇郎好在無，深居應得靜工夫。", "丹成便許隨雞犬，分定初知豢鶴鳬。", "癢處端能窺鳥爪，夢中不用斷龍胡。", "別來亦有閒忙事，日向黄家問酒壚。"]'),
('f7236aa6-7971-42d3-8900-9d70c13d5e2f','贈應童子','袁說友','宋','宋诗','song-poetry','','[]','閩山佳氣毓英儒，丱角胸中敵萬夫。',64,'全唐诗/poet.song.161000.json','["閩山佳氣毓英儒，丱角胸中敵萬夫。", "黄石固應傳孺子，玄文真可與童烏。", "飽充器識觀他日，莫負聲名滿上都。", "更憶韓公序文好，成人之禮正相須。"]'),
('68127d99-3c3f-41f3-905e-e752d9e0b248','姚行簡撫幹歸霅川','袁說友','宋','宋诗','song-poetry','','[]','一見油然慰所望，巾車更辱到他鄉。',64,'全唐诗/poet.song.161000.json','["一見油然慰所望，巾車更辱到他鄉。", "相從樂處光陰速，索笑濃時意味長。", "樽酒未堪留好客，湖山早已送歸艎。", "秋來尚憶門前路，莫惜溪頭屢買航。"]'),
('47b3842f-9709-43c4-a162-f7ee48bacfd5','和楊誠齋韻謝惠南海集詩三首  其一','袁說友','宋','宋诗','song-poetry','','[]','斯文宗主頼公歸，不使它楊僭等夷。',64,'全唐诗/poet.song.161000.json','["斯文宗主頼公歸，不使它楊僭等夷。", "四海聲名今大手，萬人辟易幾降旗。", "天方欲治將焉往，用不崇朝尚竊遲。", "整頓乾坤從小試，南州昔日洗潢池。"]'),
('cbdda64d-f9c4-4d2b-bceb-ec365fdb0cb3','和楊誠齋韻謝惠南海集詩三首  其二','袁說友','宋','宋诗','song-poetry','','[]','玉海書來喜欲狂，餐霞食瀣齒牙香。',64,'全唐诗/poet.song.161000.json','["玉海書來喜欲狂，餐霞食瀣齒牙香。", "固應宗派名江右，底用宮袍入建章。", "今代歐黄真有種，向來沈鮑肯同行。", "只今五集三千首，但覺熒煌錦繡張。"]'),
('bcd7b314-bb1a-406d-a1af-e0ec455c561f','和楊誠齋韻謝惠南海集詩三首  其三','袁說友','宋','宋诗','song-poetry','','[]','芸閣登儒拜黼衣，鳳凰來泊鳳凰枝。',64,'全唐诗/poet.song.161000.json','["芸閣登儒拜黼衣，鳳凰來泊鳳凰枝。", "待教黄閣調元去，暫對青藜下燭時。", "身到三山真得路，君留羣玉幾題詩。", "十年前訪岷峨事，也作書郎慕左思。"]'),
('0c085848-d9ba-46ba-a557-d696f83ec52f','胡元邁編呂仙翁傳','袁說友','宋','宋诗','song-poetry','','[]','工夫未達性中天，九轉還丹漫費年。',64,'全唐诗/poet.song.161000.json','["工夫未達性中天，九轉還丹漫費年。", "至理本無多智巧，此公自有一神仙。", "絕知開卷翁如在，剩欲忘言意自傳。", "功行世間千百億，諸天更辦筆如椽。"]'),
('a47c64b9-5762-4730-90dd-941ef7e882c7','同鄂州都統制司登壓雲亭','袁說友','宋','宋诗','song-poetry','','[]','一带城頭四望全，壓雲亭上更無邊。',64,'全唐诗/poet.song.161000.json','["一带城頭四望全，壓雲亭上更無邊。", "手攀北斗輕飛肉，目盼南樓僅及肩。", "城郭千年高復下，江湖萬里後還先。", "平生頗負昂霄志，便欲乘風送上天。"]'),
('ec1a3939-7901-4b2e-a69d-2ac4c36c1011','張思濟縣尉創舞翠亭','袁說友','宋','宋诗','song-poetry','','[]','新築成時秋事高，滿天風月下岧嶢。',64,'全唐诗/poet.song.161000.json','["新築成時秋事高，滿天風月下岧嶢。", "佳名欲奪雙溪景，淡墨須煩六幅綃。", "一簇穿楊誇箭羽，幾番伐鼓動溪潮。", "此亭政合貪山水，百里之間患已銷。"]'),
('dcfd887e-d1ee-4851-a7ae-21688b8c1c7c','題廟池上新創瀛紅舞綃亭','袁說友','宋','宋诗','song-poetry','','[]','高青遠綠映回塘，菡萏菰蒲細細涼。',64,'全唐诗/poet.song.161000.json','["高青遠綠映回塘，菡萏菰蒲細細涼。", "蘸水瀛紅羅襪渡，舞霓綃翠綺襦香。", "瓊珠碎落風前雨，蘭櫂夷猶月下觴。", "老帥如何太風味，兩年池上送殘陽。"]'),
('58180fc5-1ecc-4042-b65f-01859eb1b174','廟南新創塵外亭','袁說友','宋','宋诗','song-poetry','','[]','城頭拄頰俯橫塘，塵外躋攀四面涼。',64,'全唐诗/poet.song.161000.json','["城頭拄頰俯橫塘，塵外躋攀四面涼。", "南瀆夜鳴江水瀧，北窗曉浥芰荷香。", "著亭盡得山川景，携客同甘醴盎觴。", "寄興江村家八九，平分我欲卧南陽。"]'),
('f057287c-34a8-4407-91d9-a213450bdc36','和資深同游塵外亭韻','袁說友','宋','宋诗','song-poetry','','[]','城南絕景半林端，城北荷塘十畝寬。',64,'全唐诗/poet.song.161000.json','["城南絕景半林端，城北荷塘十畝寬。", "風月無塵頻入座，江山弔古一憑欄。", "瀛紅淺露嬌啼臉，綃翠輕颸醉倚干。", "日暮對花吟不足，三翁步屧小橋看。"]'),
('f631ee9f-eff6-4289-9743-a05d8599bac8','用劉汀洲左顧亭韻','袁說友','宋','宋诗','song-poetry','','[]','杖屨東風欲濫巾，小舟重泊一亭春。',64,'全唐诗/poet.song.161000.json','["杖屨東風欲濫巾，小舟重泊一亭春。", "醉看梅月無新語，老與溪山作故人。", "意氣不驚雙白鬢，功名忍負百年身。", "我來又續題詩柱，敬爲劉郎細拂塵。"]'),
('968a1048-33b5-4858-9bc8-464b9e09dd5f','用陳和父太博韻題江州高遠亭四首  其一','袁說友','宋','宋诗','song-poetry','','[]','鮮新棟宇出樓顛，盡得江山四面全。',64,'全唐诗/poet.song.161000.json','["鮮新棟宇出樓顛，盡得江山四面全。", "高摘星辰風月夜，遠迷河嶽水雲天。", "一湖尚想甘棠愛，萬井誰呼大隠廛。", "見說松關頻却掃，兩賢吟處日回旋。"]'),
('91215d14-6a26-49f5-b309-2b6120c5719b','用陳和父太博韻題江州高遠亭四首  其二','袁說友','宋','宋诗','song-poetry','','[]','亭高未涉意先申，五馬同來却報春。',64,'全唐诗/poet.song.161000.json','["亭高未涉意先申，五馬同來却報春。", "一笑孰知今在旅，茲游端不厭居塵。", "分張好景因人重，排拶佳篇逐日新。", "我是東州西上客，也來吟作社中人。"]'),
('beaaffb0-d1c2-47f6-a58a-d06c8fbb3e49','用陳和父太博韻題江州高遠亭四首  其三','袁說友','宋','宋诗','song-poetry','','[]','潯陽名郡敢言支，最愛江山左右之。',64,'全唐诗/poet.song.161000.json','["潯陽名郡敢言支，最愛江山左右之。", "松蓋前傾渾似故，詩兵捷出愈稱奇。", "案頭朱墨無多事，亭面東風足四時。", "相與平分賸遺愛，未饒白傅去時思。"]'),
('789892e7-817e-4132-a486-a842c8bdee9d','用陳和父太博韻題江州高遠亭四首  其四','袁說友','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','久說匡廬喜暫經，遐觀但覺眼青青。',64,'全唐诗/poet.song.161000.json','["久說匡廬喜暫經，遐觀但覺眼青青。", "倚欄萬事雙頹鬢，撫掌千年一古亭。", "珠玉名章方競賦，江山喜色已先形。", "我來落筆真如助，撩得詩狂不爲醒。"]'),
('b92c237f-90e1-4024-83e1-a38d9853ae2f','清暉閣','袁說友','宋','宋诗','song-poetry','','[]','清暉傑閣幾朝昏，吟咏曾喧白下門。',64,'全唐诗/poet.song.161000.json','["清暉傑閣幾朝昏，吟咏曾喧白下門。", "一別朱欄陪綺席，重來青草接荒村。", "名章尚憶江秋句，短些誰招月夜魂。", "老去情懷更蕭瑟，懶從孤館覓清樽。"]'),
('beb5c015-821a-4db2-a537-6a22a24e9444','會文堂','袁說友','宋','宋诗','song-poetry','','[]','束带峩冠集會文，郡侯著語到諸君。',64,'全唐诗/poet.song.161000.json','["束带峩冠集會文，郡侯著語到諸君。", "平居講習須朋友，退食工夫在典墳。", "士學何先先尚志，書生務業業惟勤。", "鵾鵬他日扶摇上，共致雲霄慶策勳。"]'),
('5fd95e2a-30a8-4593-9dec-882ae9ae6aaf','善頌堂','袁說友','宋','宋诗','song-poetry','','[]','庭前雲蓋碧巉嚴，堂上先生雪滿髯。',64,'全唐诗/poet.song.161000.json','["庭前雲蓋碧巉嚴，堂上先生雪滿髯。", "說藥客來聊下榻，謁齋僧去便垂簾。", "種時法好花難謝，買處錢多石易添。", "子舍光榮身壯健，只將香火事華嚴。"]'),
('d59e14c8-4322-4f8d-8f1c-d7cfbd21b9dc','桂椿堂','袁說友','宋','宋诗','song-poetry','','[]','欈李于門伯仲佳，聲名籍籍到天涯。',64,'全唐诗/poet.song.161000.json','["欈李于門伯仲佳，聲名籍籍到天涯。", "一經早已傳韋氏，五桂今重說竇家。", "滿眼衣冠真盛事，幾年棠棣看聯華。", "蘭臺曷與編青史，要使文風萬世誇。"]'),
('9e702b39-789a-467c-89ea-48fa5c38d469','白雪堂','袁說友','宋','宋诗','song-poetry','','[]','今代斯文只此翁，乾旋坤轉獨孤忠。',64,'全唐诗/poet.song.161000.json','["今代斯文只此翁，乾旋坤轉獨孤忠。", "千年此地江山裏，一日東坡翰墨中。", "莫起黄泉空老淚，可憐赤壁幾春風。", "瀟瀟暮雨雙雙竹，白雪堂前忍酹公。"]'),
('74d96141-3cb7-43c0-9564-018739395771','知止堂','袁說友','宋','宋诗','song-poetry','','[]','先生七十已垂車，父子俱榮出帝都。',64,'全唐诗/poet.song.161000.json','["先生七十已垂車，父子俱榮出帝都。", "當世若無知止者，公朝何以勵貪夫。", "升堂展卷人何在，訪竹尋梅色尚臞。", "我老自憐生也後，拊編猶得歎前蕪。"]'),
('a52b21dc-bfe0-4b45-bf7c-811e0a6c6de4','題韓元吉可止齋','袁說友','宋','宋诗','song-poetry','','[]','平生我亦愛知休，三徑如公最早謀。',64,'全唐诗/poet.song.161000.json','["平生我亦愛知休，三徑如公最早謀。", "歸意酒醲何切切，宦情紙薄正悠悠。", "書來誨語如親面，別後光陰歎轉頭。", "更爲蒼生須一起，志功元自合封留。"]'),
('59358391-6296-4bb1-9b84-079a318794ca','游揚子雲墨池','袁說友','宋','宋诗','song-poetry','','[]','平隄修柏轉林塘，飛蓋同升吐鳳堂。',64,'全唐诗/poet.song.161000.json','["平隄修柏轉林塘，飛蓋同升吐鳳堂。", "後世有傳由準易，斯文無復數他揚。", "草玄大啟天人奧，池色猶關翰墨場。", "弔古懷賢尚遺恨，不然晁董可相頏。"]'),
('eeb3c263-758c-4871-a6b4-d2427f724199','遂寧府境內火池','袁說友','宋','宋诗','song-poetry','','[]','澤中有火猶爲革，焰出方池更異常。',64,'全唐诗/poet.song.161000.json','["澤中有火猶爲革，焰出方池更異常。", "氣烈羣山酣土赤，陽潛深地液硫黄。", "書生考訂言雖確，造化工夫理甚彰。", "君看輿薪一杯水，物因偏勝故爲强。"]'),
('da213bcf-8da8-4cc1-a281-04978165b4bf','過廣安軍王恭父大著墓','袁說友','宋','宋诗','song-poetry','','[]','與君執友共爲郎，尚憶松江送客艎。',64,'全唐诗/poet.song.161000.json','["與君執友共爲郎，尚憶松江送客艎。", "在昔清班方衮衮，至今衰草恨茫茫。", "百年名世嗟天喪，一日修文在帝傍。", "雲檟風杉空掛劍，不勝老淚灑危岡。"]'),
('c512692a-c25f-478c-bb95-5cafb7747508','謁洪澤鎮龍祠','袁說友','宋','宋诗','song-poetry','','[]','平生忠孝徹幽冥，稽首龍祠鑒此誠。',64,'全唐诗/poet.song.161000.json','["平生忠孝徹幽冥，稽首龍祠鑒此誠。", "自是皇靈頻震疊，也知神力解因成。", "片帆以往無多路，百里之間只一程。", "目斷長淮嗟往事，孤哀有淚落邊城。"]'),
('9d1f5a58-5b5f-4324-a4dd-c72d42a88528','遊江瀆廟用故侯吳龍圖韻','袁說友','宋','宋诗','song-poetry','','[]','馬嘶楊柳泊林塘，六月城南趁曉涼。',64,'全唐诗/poet.song.161000.json','["馬嘶楊柳泊林塘，六月城南趁曉涼。", "萬古叢祠千木暗，五風十雨一爐香。", "翬飛棟宇新輪奐，鼓奏犧牲薦豆觴。", "努力爲民祈福地，年豐今已格陰陽。"]'),
('645f5258-b6b4-4846-bab5-65567d56fcb2','劉德修殿院持節歸蜀','袁說友','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','堂堂柏府幾人過，屈指精忠竟若何。',64,'全唐诗/poet.song.161000.json','["堂堂柏府幾人過，屈指精忠竟若何。", "正爾浮雲遮白日，頼公砥柱立頹波。", "回天力挽千鈞重，去國身輕一葉多。", "萬里長江向東去，清明無日可鎸磨。"]'),
('2c2e39c5-ec89-453e-b339-3dba24e1aff3','過忠州酆都觀','袁說友','宋','宋诗','song-poetry','','[]','古柏修篁萬木顛，盤山百折叩真僊。',64,'全唐诗/poet.song.161000.json','["古柏修篁萬木顛，盤山百折叩真僊。", "便疑脚踏如來地，已覺身遊洞府天。", "空翠遐觀浮海日，偃雲時汲濯纓泉。", "我來只恨無僊骨，未必丹爐不再燃。"]'),
('d100463d-7ae6-4268-a0d2-1b44bec7dbaf','和野堂僧子惠韻','袁說友','宋','宋诗','song-poetry','','[]','與公林下昔閒人，別後書來意轉親。',64,'全唐诗/poet.song.161000.json','["與公林下昔閒人，別後書來意轉親。", "老去興懷空繾綣，詩來得句愛清新。", "眼看吳地千峰月，心在苕溪一釣綸。", "猶得支郎消息好，錦囊時寄筆端春。"]'),
('a0107131-b8b9-46d7-b7e7-3d21ea67fc04','堅老住廣福','袁說友','宋','宋诗','song-poetry','','[]','高僧七十未龍鍾，飛錫飄然百里中。',64,'全唐诗/poet.song.161000.json','["高僧七十未龍鍾，飛錫飄然百里中。", "正欲逢場施手段，不妨臨老入花叢。", "把茅便可傳宗旨，一鉢由來是祖風。", "直要空門高著眼，看渠拍手任西東。"]'),
('62c24ea1-a757-4688-b711-1134f17e6bae','飯西湖兜率寺','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風爐煮餠梵王家，一日平湖十里賒。',64,'全唐诗/poet.song.161000.json','["風爐煮餠梵王家，一日平湖十里賒。", "遊子政須供杖屨，老僧應有痼煙霞。", "絕知咳唾新珠玉，想見冰霜遶齒牙。", "我恨三山無路到，望中贏得眼昏花。"]'),
('8086aae2-7acc-4e7c-9c47-facd9cd347fb','題浄相寺','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清詩冷閣更佳名，一段家風太瘦生。',64,'全唐诗/poet.song.161000.json','["清詩冷閣更佳名，一段家風太瘦生。", "東老懸知有餘樂，西湖今可問前盟。", "年來信覺青山好，老去休驚白髮更。", "欲識箇中無盡意，挑包急急看吾行。"]'),
('98172059-5b9f-478f-b6b7-7027327674e5','過懷安軍雲頂寺','袁說友','宋','宋诗','song-poetry','','[]','拂雲絕頂俯金囦，直上重山最上顛。',64,'全唐诗/poet.song.161000.json','["拂雲絕頂俯金囦，直上重山最上顛。", "一佛嚮來臨大地，萬松今獨近高天。", "枯楠夭矯渾生意，斷石盤陀幾合年。", "大士重來聞囑付，毫光端欲掃烽煙。"]'),
('7fa15778-a54b-42c7-aab3-eb82d5e96f0d','善頌堂','袁說友','宋','宋诗','song-poetry','','[]','家法傳忠孝，朝英仰正平。',72,'全唐诗/poet.song.161000.json','["家法傳忠孝，朝英仰正平。", "抗詞嚴廟制，勇去樂親榮。", "一室從新扁，羣公詠落成。", "清風天籟靜，斜日雪山橫。", "養志閔曾重，浮名廣受輕。", "聞風千載下，凜凜萬夫驚。"]'),
('606d93b1-eaac-4e0f-a772-9a19deb9f4bc','和程泰之閣學春雪韻','袁說友','宋','宋诗','song-poetry','','[]','妬臘三呈白，欺春六出花。',132,'全唐诗/poet.song.161000.json','["妬臘三呈白，欺春六出花。", "玉層渾欲墮，珠霰一何奢。", "巧態穿庭樹，餘寒戀釣槎。", "積難殊未密，散易已成賒。", "有客門間卧，何人帳裏遮。", "淺斟羞獨舉，低唱敢言譁。", "故壓梅花信，猶先柳絮斜。", "晚澌方歷亂，夜櫓正咿啞。", "剩把新年雪，初烹改火茶。", "剪裁歸妙造，比興屬詩家。", "應有呵纖手，朝窗學畫鴉。"]'),
('aa3d1ca4-b37b-4e55-b55d-7dea1bc2b4af','飲寓隠軒','袁說友','宋','宋诗','song-poetry','','[]','軒亭曉清曠，行樂未妨頻。',144,'全唐诗/poet.song.161000.json','["軒亭曉清曠，行樂未妨頻。", "無客不堪醉，有花長是春。", "憑欄尚紅藥，結伴擅芳辰。", "笑駐凌波步，香分折角巾。", "鶑聲殊自健，杏子况嘗新。", "仰止宗英伯，來爲鄭驛賓。", "言辭獨樂樂，仍命可人人。", "鴻弄舞時影，梁蜚歌處塵。", "棋枰誰得雋，詩筆自疑神。", "欹倒何妨屢，歌呼却甚真。", "升沈塞上馬，容易鬢如銀。", "奈許追歡地，回頭迹便陳。"]'),
('dc9efd4a-98bd-4063-9d3d-8f0eacce7ef8','贈相士林石','袁說友','宋','宋诗','song-poetry','','[]','豈是無仙骨，平生百念輕。',24,'全唐诗/poet.song.161000.json','["豈是無仙骨，平生百念輕。", "但存方寸地，吾不計前程。"]'),
('ef6cf372-6a83-4aa4-abc6-e7a92a90f311','題關都官西湖孤山四照閣圖','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三賢堂趣遠，四照閣詩傳。',24,'全唐诗/poet.song.161000.json','["三賢堂趣遠，四照閣詩傳。", "高節無人繼，孤山只儼然。"]'),
('9d3f9a39-2c6f-406b-b6c5-d0fc13bfa087','跋本朝六名公帖','袁說友','宋','宋诗','song-poetry','','[]','道喪嗟耆舊，人亡獨簡編。',24,'全唐诗/poet.song.161000.json','["道喪嗟耆舊，人亡獨簡編。", "家藏六君帖，何必萬人傳。"]'),
('7aacd7ef-2214-4f45-ae5c-d63fd4ae3a18','十三日飲俞園昌甫斯遠彥章畢至','袁說友','宋','宋诗','song-poetry','','[]','忽爾嚴冬設鱠，更於晴日觀梅。',28,'全唐诗/poet.song.161000.json','["忽爾嚴冬設鱠，更於晴日觀梅。", "人道荒尋邂逅，我忻良集而來。"]'),
('9c316e7a-20fc-4bd0-8ed6-c5741c2572fb','題米元暉太湖圖卷','袁說友','宋','宋诗','song-poetry','','["\u592a\u6e56"]','水際天低岸遠，山腰霧捲雲鋪。',28,'全唐诗/poet.song.161000.json','["水際天低岸遠，山腰霧捲雲鋪。", "擬喚松江小艇，歸來好趁蓴鱸。"]'),
('ae71237b-081e-4308-9dd2-7ffedac03f16','題東坡蘇公三笑圖帖','袁說友','宋','宋诗','song-poetry','','[]','不覺虎溪過却，軒渠一笑而歸。',28,'全唐诗/poet.song.161000.json','["不覺虎溪過却，軒渠一笑而歸。", "此笑此心真處，自然魚躍鳶飛。"]'),
('7d306245-1426-455d-a5c0-4ba12953aa6c','和程泰之閣學汎舟南溪遇雪韻三首  其一','袁說友','宋','宋诗','song-poetry','','[]','目斷山前浮玉，春回雪裏宜城。',28,'全唐诗/poet.song.161000.json','["目斷山前浮玉，春回雪裏宜城。", "得意扁舟乘興，歸來好語增明。"]'),
('f5bfe673-3c0e-4d46-97bd-62d054e9b775','和程泰之閣學汎舟南溪遇雪韻三首  其二','袁說友','宋','宋诗','song-poetry','','[]','憐我閉門卧雪，慚渠有酒盈樽。',28,'全唐诗/poet.song.161000.json','["憐我閉門卧雪，慚渠有酒盈樽。", "老盡青山曉色，愁添白髮霜根。"]'),
('5b4c12cf-9f8c-4ea1-aa5b-eb678b0a941f','和程泰之閣學汎舟南溪遇雪韻三首  其三','袁說友','宋','宋诗','song-poetry','','[]','孤鴈聲悲南浦，漁人冷徹歸蓑。',28,'全唐诗/poet.song.161000.json','["孤鴈聲悲南浦，漁人冷徹歸蓑。", "獨有耐寒瓊玉，一枝先奪陽和。"]'),
('07d1b689-fd74-4e42-9740-0830551ad0ae','和康叔探梅韻三首  其一','袁說友','宋','宋诗','song-poetry','','[]','今年人憶去年梅，試問今年花已開。',32,'全唐诗/poet.song.161000.json','["今年人憶去年梅，試問今年花已開。", "見說春風正料理，不應小雨便花摧。"]'),
('19ed2d05-3142-40ea-82ca-1cabaaec4650','和康叔探梅韻三首  其二','袁說友','宋','宋诗','song-poetry','','[]','詩壇傳檄未應虛，忍負東君自作疎。',32,'全唐诗/poet.song.161000.json','["詩壇傳檄未應虛，忍負東君自作疎。", "急急花前巖下看，橫斜清淺兩何如。"]'),
('64a976f8-210c-4a8a-baff-28b170dbbeb0','和康叔探梅韻三首  其三','袁說友','宋','宋诗','song-poetry','','[]','尋梅著語樂清閒，已覺孤山氣象還。',32,'全唐诗/poet.song.161000.json','["尋梅著語樂清閒，已覺孤山氣象還。", "未辦輕舟行百里，也須踏脚法華山。"]'),
('03194c75-0f12-44f1-841b-b467cf12601b','題石上玉簪花  其一','袁說友','宋','宋诗','song-poetry','','[]','欲訪招提倦不禁，空懷落落海潮音。',32,'全唐诗/poet.song.161000.json','["欲訪招提倦不禁，空懷落落海潮音。", "如今不作維摩病，猶記年時賦玉簪。"]'),
('00e6b7d4-5d4f-497f-9442-eb02f37ba9b6','題石上玉簪花  其二','袁說友','宋','宋诗','song-poetry','','[]','翠鈿瓊葩別樣芳，凉風微雨淡梳粧。',32,'全唐诗/poet.song.161000.json','["翠鈿瓊葩別樣芳，凉風微雨淡梳粧。", "姮娥夜半朝天闕，應有遺簪墜帝旁。"]'),
('f15710b0-f474-438c-9d38-f4e1a2fb21f8','和范石湖詠雙蓮三首  其一','袁說友','宋','宋诗','song-poetry','','[]','江妃瑟裏恨沈沈，萬點紅邊意轉深。',32,'全唐诗/poet.song.161000.json','["江妃瑟裏恨沈沈，萬點紅邊意轉深。", "擁出三千歌舞罷，翠綃縈得兩同心。"]'),
('c9ab626d-c339-4549-ab83-db74db6b8e74','和范石湖詠雙蓮三首  其二','袁說友','宋','宋诗','song-poetry','','[]','天泉池上舞晴暉，一別人家未肯歸。',32,'全唐诗/poet.song.161000.json','["天泉池上舞晴暉，一別人家未肯歸。", "千載却隨湘女泣，風前時學鳳凰飛。"]'),
('1304c678-684d-49ce-b687-04fc983654a7','和范石湖詠雙蓮三首  其三','袁說友','宋','宋诗','song-poetry','','[]','鑑湖一曲記蓬萊，櫂入紅蕖挽不回。',32,'全唐诗/poet.song.161000.json','["鑑湖一曲記蓬萊，櫂入紅蕖挽不回。", "今日池光少公事，好懷聊復爲渠開。"]'),
('8c3addaf-4f5b-4fff-ada1-4534144230d6','題尤提舉惠雙蓮二首  其一','袁說友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十年蹤跡落修門，賸憶西湖菡萏風。',32,'全唐诗/poet.song.161000.json','["十年蹤跡落修門，賸憶西湖菡萏風。", "今日江城秋浦上，舞綃依約舊相逢。"]'),
('61b229cc-4be8-4c22-90dc-8f049c5a5583','題尤提舉惠雙蓮二首  其二','袁說友','宋','宋诗','song-poetry','','[]','六月炎歊苦盛長，一枝遣伴北窗凉。',32,'全唐诗/poet.song.161000.json','["六月炎歊苦盛長，一枝遣伴北窗凉。", "此花便合雄文記，擬爲君書瑞應堂。"]'),
('34a99884-e02e-4d64-bb26-b05b0a3f0a7e','致菊種於子長','袁說友','宋','宋诗','song-poetry','','[]','好花一歲幾回開，喜見東籬舊信來。',32,'全唐诗/poet.song.161000.json','["好花一歲幾回開，喜見東籬舊信來。", "不惜移根到鄰里，離披也入畫堂栽。"]'),
('a497db35-567b-4742-a999-5521d1bda796','致盆梔子於同年樓大防天官','袁說友','宋','宋诗','song-poetry','','[]','一輪月影漲幽香，碧玉釵頭白玉粧。',32,'全唐诗/poet.song.161000.json','["一輪月影漲幽香，碧玉釵頭白玉粧。", "持似此花供燕几，玉堂端可壽萱堂。"]'),
('2aa0a059-f745-42be-adbc-aeae40c25eca','和程閣學送小春茶韻四首  其一','袁說友','宋','宋诗','song-poetry','','[]','眼看節物去重來，又見寒梢數點梅。',32,'全唐诗/poet.song.161000.json','["眼看節物去重來，又見寒梢數點梅。", "草木已隨新歲好，冬芽豫占一年魁。"]'),
('eb1e6b1a-4001-4074-9b98-22857607cc93','和程閣學送小春茶韻四首  其二','袁說友','宋','宋诗','song-poetry','','[]','物物呈祥豈偶然，新芽新味更新年。',32,'全唐诗/poet.song.161000.json','["物物呈祥豈偶然，新芽新味更新年。", "靈苗却解爲人壽，請爲君謨續此篇。"]'),
('a6fbf374-21fe-4ccc-8b1f-612d1eae778d','和程閣學送小春茶韻四首  其三','袁說友','宋','宋诗','song-poetry','','[]','七椀由來厭八珍，猶堪代酒亦生春。',32,'全唐诗/poet.song.161000.json','["七椀由來厭八珍，猶堪代酒亦生春。", "箇中風味須知趣，慙愧劉公獨倚新。"]'),
('2310b80b-8f41-4dd0-a734-f4788c037b3b','和程閣學送小春茶韻四首  其四','袁說友','宋','宋诗','song-poetry','','[]','家山歷歷未歸來，投老江湖祇自咍。',32,'全唐诗/poet.song.161000.json','["家山歷歷未歸來，投老江湖祇自咍。", "頼有年年鄉信好，一甌浮玉飽春臺。"]'),
('3994ef9a-adfa-4835-94a6-7b14169d8cef','和子長見招韻四首  其一','袁說友','宋','宋诗','song-poetry','','[]','攻擊愁城從事裏，消磨日月手談中。',32,'全唐诗/poet.song.161000.json','["攻擊愁城從事裏，消磨日月手談中。", "不緣我輩真風味，安得尊前笑語同。"]'),
('230df581-20ea-42b7-ae1b-55769b7d7592','和子長見招韻四首  其二','袁說友','宋','宋诗','song-poetry','','[]','青林綠幄春歸後，翠岫蒼崖雨過初。',32,'全唐诗/poet.song.161000.json','["青林綠幄春歸後，翠岫蒼崖雨過初。", "作意尋幽還得笑，隨宜供客莫求餘。"]'),
('8284665e-57a9-41dd-940e-fbd1cc59d98b','和子長見招韻四首  其三','袁說友','宋','宋诗','song-poetry','','[]','清游已恨朞年別，勝處能消一日情。',32,'全唐诗/poet.song.161000.json','["清游已恨朞年別，勝處能消一日情。", "莫對浮山無好語，相逢草木有佳聲。"]'),
('70a49444-be3d-4996-9a22-30022ae3bfc6','和子長見招韻四首  其四','袁說友','宋','宋诗','song-poetry','','[]','飛香雨過雙溪閣，舞翠荷開十丈花。',32,'全唐诗/poet.song.161000.json','["飛香雨過雙溪閣，舞翠荷開十丈花。", "佳處正須供一賞，相從吾亦豈匏瓜。"]'),
('c9bbe840-474b-4929-a565-747c9d267247','招山陽高徐二生飲二首  其一','袁說友','宋','宋诗','song-poetry','','[]','梅花時節屢開樽，欲贈梅花欠可人。',32,'全唐诗/poet.song.161000.json','["梅花時節屢開樽，欲贈梅花欠可人。", "今日有人梅樣好，逢君同賞雪中春。"]'),
('fa7fdeb1-86aa-4e80-8a22-bb2e5d5d5633','招山陽高徐二生飲二首  其二','袁說友','宋','宋诗','song-poetry','','[]','欲作山陰興盡回，良思與子把離杯。',32,'全唐诗/poet.song.161000.json','["欲作山陰興盡回，良思與子把離杯。", "要須人境俱清絕，好抱瑶琴踏雪來。"]'),
