('7cffd159-915a-44ef-a1c9-b0786654dc2b','偶題','辛棄疾','宋','宋诗','song-poetry','','[]','逢花眼倦開，見酒手頻推。',24,'全唐诗/poet.song.162000.json','["逢花眼倦開，見酒手頻推。", "不恨吾年老，恨他將病來。"]'),
('504f079a-63dd-4bda-9f8b-78cd6e601bc6','哭㔶十五章  其一','辛棄疾','宋','宋诗','song-poetry','','[]','方看竹馬戲，已作薤露歌。',24,'全唐诗/poet.song.162000.json','["方看竹馬戲，已作薤露歌。", "哀哉天喪予，老淚如傾河。"]'),
('8773f54c-128e-4e6c-89b5-b575204c65f7','哭㔶十五章  其二','辛棄疾','宋','宋诗','song-poetry','','[]','玉雪色可愛，金石聲更清。',24,'全唐诗/poet.song.162000.json','["玉雪色可愛，金石聲更清。", "孰知摧輪早，跬步不可行。"]'),
('9e1feb72-2593-4bd4-a266-a1ca90b86df6','哭㔶十五章  其三','辛棄疾','宋','宋诗','song-poetry','','[]','念汝雖孩童，氣已負山嶽。',24,'全唐诗/poet.song.162000.json','["念汝雖孩童，氣已負山嶽。", "送汝已成人，行路已悲愕。"]'),
('7503706c-f12f-45da-a947-eafe8352b143','哭㔶十五章  其四','辛棄疾','宋','宋诗','song-poetry','','[]','他年駟馬車，謂可高吾門。',24,'全唐诗/poet.song.162000.json','["他年駟馬車，謂可高吾門。", "只今關心處，政在青楓根。"]'),
('1c922236-e315-4099-9ea7-0b53725e1655','哭㔶十五章  其五','辛棄疾','宋','宋诗','song-poetry','','[]','糊涂不成書，把筆意甚喜。',24,'全唐诗/poet.song.162000.json','["糊涂不成書，把筆意甚喜。", "舉頭見爺笑，持付三四紙。"]'),
('080fa9ee-c720-4d52-80ce-94c91ecf01e8','哭㔶十五章  其六','辛棄疾','宋','宋诗','song-poetry','','[]','笑揖索酒罷，高吟關關鳩。',24,'全唐诗/poet.song.162000.json','["笑揖索酒罷，高吟關關鳩。", "至今此篇詩，狼籍在床頭。"]'),
('0de2de22-6eb1-4db5-b0a4-ce6dd4c61fe2','哭㔶十五章  其七','辛棄疾','宋','宋诗','song-poetry','','[]','汝父誠有罪，汝母孝且慈。',24,'全唐诗/poet.song.162000.json','["汝父誠有罪，汝母孝且慈。", "獨不爲母計，倉皇去何之。"]'),
('8f356a9d-a88f-48ee-bf13-e83057bdd2ee','哭㔶十五章  其八','辛棄疾','宋','宋诗','song-poetry','','[]','淚盡眼欲枯，痛深腸已絕。',24,'全唐诗/poet.song.162000.json','["淚盡眼欲枯，痛深腸已絕。", "汝方遊浩蕩，萬里挾雄鐵。"]'),
('52e2e504-21d8-41d9-bc0c-e7edde206922','哭㔶十五章  其九','辛棄疾','宋','宋诗','song-poetry','','[]','中堂與曲室，聞汝啼哭聲。',24,'全唐诗/poet.song.162000.json','["中堂與曲室，聞汝啼哭聲。", "汝父與汝母，何處可坐行。"]'),
('17b36e3f-78a2-47da-8616-17606009b713','哭㔶十五章  其一○','辛棄疾','宋','宋诗','song-poetry','','[]','從人索蓮花，手持雙白羽。',24,'全唐诗/poet.song.162000.json','["從人索蓮花，手持雙白羽。", "蓮花不可見，蓮子心獨苦。"]'),
('7f4dc1a6-def0-43f0-9ae6-a3e81c066553','哭㔶十五章  其一一','辛棄疾','宋','宋诗','song-poetry','','[]','足音答答來，多在雪樓下。',24,'全唐诗/poet.song.162000.json','["足音答答來，多在雪樓下。", "尚憶附爺耳，指問壁間畫。"]'),
('996ac70e-0273-4882-b65c-b85428b79257','哭㔶十五章  其一二','辛棄疾','宋','宋诗','song-poetry','','[]','我痛須自排，汝癡故難忘。',24,'全唐诗/poet.song.162000.json','["我痛須自排，汝癡故難忘。", "何時篆岡竹，重來看眉藏。"]'),
('87d9ea32-50a5-466f-a6c0-af2d4f7b1696','哭㔶十五章  其一三','辛棄疾','宋','宋诗','song-poetry','','[]','昨宵北窗下，不敢高聲語。',24,'全唐诗/poet.song.162000.json','["昨宵北窗下，不敢高聲語。", "悲深意顛倒，尚疑驚著汝。"]'),
('890ae1c7-6a26-4b08-926c-d10f7669c53c','哭㔶十五章  其一四','辛棄疾','宋','宋诗','song-poetry','','[]','世無扁和手，遺恨歸砭劑。',24,'全唐诗/poet.song.162000.json','["世無扁和手，遺恨歸砭劑。", "嗟誰使之然，刻舟寧復記。"]'),
('b71a3723-817f-4df4-9339-87826cebbb20','哭㔶十五章  其一五','辛棄疾','宋','宋诗','song-poetry','','[]','百年風雨過，達者齊殤彭。',24,'全唐诗/poet.song.162000.json','["百年風雨過，達者齊殤彭。", "嗟我反不如，其下不及情。"]'),
('6bcce622-a0b7-4ca8-9123-0974d3825701','聞科詔勉諸子','辛棄疾','宋','宋诗','song-poetry','','[]','秋舉無多日，天書已十行。',48,'全唐诗/poet.song.162000.json','["秋舉無多日，天書已十行。", "絕編能自苦，下筆定成章。", "不見三公後，空長七尺强。", "明年吏部選，梅福更仇香。"]'),
('9a8f8d7c-52c9-4283-82be-16c3f80c127f','第四子學春秋發憤不輟書以勉之','辛棄疾','宋','宋诗','song-poetry','','[]','春雨晝連夜，春江冷欲冰。',48,'全唐诗/poet.song.162000.json','["春雨晝連夜，春江冷欲冰。", "清愁殊浩蕩，莫景劇飛騰。", "身是歸休客，心如入定僧。", "西園曾到不，要學仲舒能。"]'),
('113d5326-0a29-490a-90ba-1696210afb6c','送悟老住明教禪院','辛棄疾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','道人匡廬來，籍籍傾衆耳。',72,'全唐诗/poet.song.162000.json','["道人匡廬來，籍籍傾衆耳。", "規摹小軒中，坐穩得坎止。", "慈雲爲誰出，法席應衆啟。", "招提隠山腹，深浄端可喜。", "夜禪餘機鋒，文字入游戲。", "會有化人來，伽陀開短紙。"]'),
('20b31f06-6dcc-48ca-abe0-b0d2a460cb7e','感懷示兒輩','辛棄疾','宋','宋诗','song-poetry','','[]','窮處幽人樂，徂年烈士悲。',48,'全唐诗/poet.song.162000.json','["窮處幽人樂，徂年烈士悲。", "歸田曾有志，責子且無詩。", "舊恨王夷甫，新交蔡克兒。", "淵明去我久，此意有誰知。"]'),
('bc1bfe62-a930-4c34-a71c-9b3db22974f7','即事示兒','辛棄疾','宋','宋诗','song-poetry','','[]','掃迹衡門下，終朝抱膝吟。',48,'全唐诗/poet.song.162000.json','["掃迹衡門下，終朝抱膝吟。", "貧須依稼穡，老不厭山林。", "有酒無餘願，因閑得此心。", "西園早行樂，桃李漸成陰。"]'),
('e7b13e30-1b4b-443c-810d-30a87a3682bc','答余叔良和韻','辛棄疾','宋','宋诗','song-poetry','','[]','東舍延朝爽，西林媚夕曛。',48,'全唐诗/poet.song.162000.json','["東舍延朝爽，西林媚夕曛。", "有生同擾擾，何路出紛紛。", "暖日鵷鸞伴，空山鳥獸羣。", "本來同一致，休笑衆人醺。"]'),
('f3fc0456-02b2-419d-bf30-e82c6db5f787','詠雪','辛棄疾','宋','宋诗','song-poetry','','[]','書窗夜生白，城角曉增悲。',48,'全唐诗/poet.song.162000.json','["書窗夜生白，城角曉增悲。", "未奏蔡州捷，且歌梁苑詩。", "餐氈懷雁使，無酒羨羔兒。", "農事勤憂國，明年喜可知。"]'),
('9cc13504-3caf-4653-a701-53634f763ca7','蔞蒿宜作河豚羹','辛棄疾','宋','宋诗','song-poetry','','[]','河豚挾鴆毒，殺人一臠足。',72,'全唐诗/poet.song.162000.json','["河豚挾鴆毒，殺人一臠足。", "蔞蒿或濟之，赤心置人腹。", "方其在野中，衛青混奴僕。", "及登君子堂，園綺成骨肉。", "暴乾及爲脯，拳曲蝟毛縮。", "寄君頻咀嚼，去翳如折屋。"]'),
('29bfaaff-25ec-4fe0-8bc4-2f8c9863dc4a','吳克明廣文見和再用韻答之','辛棄疾','宋','宋诗','song-poetry','','[]','彼茁江漢姿，當春風露足。',72,'全唐诗/poet.song.162000.json','["彼茁江漢姿，當春風露足。", "美芹或以獻，深媿野人腹。", "君詩窮草木，命騷可奴僕。", "更憐無俗韻，愛竹不愛肉。", "渠儂如石鼎，正作蛟龍縮。", "欲烹無魚來，蒼蠅聲繞屋。"]'),
('c50c82e8-1e67-4d6b-94fa-1d9b3ff31cb8','仙蹟巖','辛棄疾','宋','宋诗','song-poetry','','[]','地秘巖藏骨，谿靈膝印痕。',48,'全唐诗/poet.song.162000.json','["地秘巖藏骨，谿靈膝印痕。", "虛牀惟太姥，別席盡曾孫。", "披牒秦朝遠，遺壇漢祀存。", "何時幔亭側，重復見幢幡。"]'),
('bc3ad025-cc67-457d-93c4-1c1cb76f90b3','周氏敬榮堂詩','辛棄疾','宋','宋诗','song-poetry','','[]','泰伯古至德，以遜天下聞。',288,'全唐诗/poet.song.162000.json','["泰伯古至德，以遜天下聞。", "周公去未遠，二叔乃流言。", "春風棠棣萼，秋日脊令原。", "豈無良友生，歲晏誰急難。", "當年召公詩，慮缺兄弟恩。", "賢哉首陽子，此粟久不餐。", "末俗益可嗟，有貨無天倫。", "倉卒競錙銖，或不暇掩親。", "朝從官府去，暮與妻妾論。", "手植父桑柘，俄頃楚越分。", "口澤母杯圈，改作脣齒寒。", "我觀天地間，孰不知愛身。", "有伐其左臂，那復右者存。", "君看百足蟲，至死身不顛。", "一矢折甚易，累十力則艱。", "世其有不知，利欲令智昏。", "周君千載士，金玉四弟昆。", "狀如商山皓，雍雍古衣冠。", "又如孔門科，行義皆可尊。", "我行前岡上，人指孝友門。", "邀我飲其家，本末能具陳。", "我家所自出，嘉祐劉三元。", "至今起俗說，聞者薄夫醇。", "逮我先君子，仁孝儉且文。"]'),
('8ce7eae3-8bfb-4d49-a9d7-f1ee3b7d1325','和趙晉臣敷文積翠巖去纇石','辛棄疾','宋','宋诗','song-poetry','','[]','兩峰如長喉，有石鯁其內。',288,'全唐诗/poet.song.162000.json','["兩峰如長喉，有石鯁其內。", "千金隨侯珠，磊落見微纇。", "何言西子美，捧心作顰態。", "夷齊立著肩，欲間使分背。", "小虧或大全，知惡及真愛。", "堂堂老充國，荒尋得幽對。", "朝夕與山語，俯仰彌三載。", "謂我知子心，茅塞厭薈薱。", "有美玉於斯，雕琢那可廢。", "芝蘭生當戶，雖芳亦芟刈。", "邑有從事賢，聞之重慷慨。", "太清點浮雲，誰令久滓穢。", "指揮俄頃間，急雨破春塊。", "開豁喜新闢，偪仄忘舊礙。", "得非神禹手，勇鑿恥不逮。", "又如持金篦，刮膜生美睞。", "渠言農去草，見惡佩前誨。", "主人吟古風，格調劇清裁。", "我評此章句，真是杜陵輩。", "入蜀脚未定，欲擲石笋退。", "火與金水同，其石爲鑠焠。", "勸君莫放手，玉石恐俱碎。", "纍然頸下癭，割之命隨潰。", "此石幸勝之，此舉君勿再。"]'),
('7f8c3a2f-033c-46f1-8ffc-6d25629cc4c9','題金相寺浄照軒詩','辛棄疾','宋','宋诗','song-poetry','','[]','浄是浄空空即色，照應照物物非心。',32,'全唐诗/poet.song.162000.json','["浄是浄空空即色，照應照物物非心。", "請看窗外一輪月，正在碧潭千丈深。"]'),
('2eab49d0-87fc-4512-b18b-ce3d767207c9','和傅巖叟梅花二首  其一','辛棄疾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','月澹黄昏欲雪時，小窗猶欠歲寒枝。',32,'全唐诗/poet.song.162000.json','["月澹黄昏欲雪時，小窗猶欠歲寒枝。", "暗香疎影無人處，唯有西湖處士知。"]'),
('a4336d2d-e759-4abb-9f01-6a671a7480a1','和傅巖叟梅花二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','靈均恨不與同時，欲把幽香贈一枝。',32,'全唐诗/poet.song.162000.json','["靈均恨不與同時，欲把幽香贈一枝。", "堪入離騷文字不，當年何事未相知。"]'),
('28188667-33c8-447b-b755-1c3adbd77f4f','江山慶雲橋  其一','辛棄疾','宋','宋诗','song-poetry','','[]','草梢出水已無多，村路瀰漫奈雨何。',32,'全唐诗/poet.song.162000.json','["草梢出水已無多，村路瀰漫奈雨何。", "水底有橋橋有月，只今平地怕風波。"]'),
('d0938d1c-43c4-49cb-b1fa-31e149ea424f','江山慶雲橋  其二','辛棄疾','宋','宋诗','song-poetry','','[]','斷崖老樹互撐拄，白水綠畦相灌輸。',32,'全唐诗/poet.song.162000.json','["斷崖老樹互撐拄，白水綠畦相灌輸。", "焉得溪南一邱壑，放船畫作歸來圖。"]'),
('a1aaeeb1-098b-42d7-b338-d453cd682a8b','賦葡萄','辛棄疾','宋','宋诗','song-poetry','','[]','高架金莖照水寒，纍纍小摘便堆盤。',32,'全唐诗/poet.song.162000.json','["高架金莖照水寒，纍纍小摘便堆盤。", "喜君不釀涼州酒，來救衰翁舌本乾。"]'),
('87148932-5091-478c-843b-51953a0ec234','題福州參泉二首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','兩泉水出更溫泉，這裏原無一二三。',32,'全唐诗/poet.song.162000.json','["兩泉水出更溫泉，這裏原無一二三。", "欲識當年參字意，行人浴罷試求參。"]'),
('8102dc5e-f97e-4b9a-8fe0-a92d29352319','題福州參泉二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','三泉參錯本兒嬉，認作參星轉更癡。',32,'全唐诗/poet.song.162000.json','["三泉參錯本兒嬉，認作參星轉更癡。", "却笑世間真狡獪，古今能有幾人知。"]'),
('226df890-3ab7-4087-baca-3851bf451701','贈延福端老二首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','飄然瓶錫信行藏，偶駐姜峰古道場。',32,'全唐诗/poet.song.162000.json','["飄然瓶錫信行藏，偶駐姜峰古道場。", "欲識高人用心處，白雲堂下一罏香。"]'),
('c43732b3-5603-47de-9c46-4ed12f279488','贈延福端老二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','我來欲問小乘禪，慚愧塵埃未了緣。',32,'全唐诗/poet.song.162000.json','["我來欲問小乘禪，慚愧塵埃未了緣。", "忽憶去年秋夜話，共聽山雨不成眠。"]'),
('f105dddb-11ca-4f8f-b6a8-f30807d7d853','遊武夷作棹歌呈晦翁十首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','一水奔流疊嶂開，谿頭千步響如雷。',32,'全唐诗/poet.song.162000.json','["一水奔流疊嶂開，谿頭千步響如雷。", "扁舟費盡篙師力，咫尺平瀾上不來。"]'),
('109ad029-1587-452f-b3da-2431219b68c9','遊武夷作棹歌呈晦翁十首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','山上風吹笙鶴聲，山前人望翠雲屏。',32,'全唐诗/poet.song.162000.json','["山上風吹笙鶴聲，山前人望翠雲屏。", "蓬萊枉覓瑶池路，不道人間有幔亭。"]'),
('b8615ea0-8c76-4b49-9f45-7e526c88df80','遊武夷作棹歌呈晦翁十首  其三','辛棄疾','宋','宋诗','song-poetry','','[]','玉女峰前一櫂歌，煙鬟霧髻動清波。',32,'全唐诗/poet.song.162000.json','["玉女峰前一櫂歌，煙鬟霧髻動清波。", "遊人去後楓林夜，月滿空山可奈何。"]'),
('7552f590-3017-4cfc-b7e4-3b74bcc9e0ea','遊武夷作棹歌呈晦翁十首  其四','辛棄疾','宋','宋诗','song-poetry','','[]','見說仙人此避秦，愛隨流水一溪雲。',32,'全唐诗/poet.song.162000.json','["見說仙人此避秦，愛隨流水一溪雲。", "花開花落無尋處，彷彿吹簫月夜聞。"]'),
('d1ae208d-abbb-4f63-9f6b-796f62386381','遊武夷作棹歌呈晦翁十首  其五','辛棄疾','宋','宋诗','song-poetry','','[]','千丈攙天翠壁高，定誰狡獪插遺樵。',32,'全唐诗/poet.song.162000.json','["千丈攙天翠壁高，定誰狡獪插遺樵。", "神仙萬里乘風去，更度槎枒箇樣橋。"]'),
('067afa10-6a78-40e9-8458-f051c63a90b4','遊武夷作棹歌呈晦翁十首  其六','辛棄疾','宋','宋诗','song-poetry','','[]','山頭有路接無塵，欲覓王孫試問津。',32,'全唐诗/poet.song.162000.json','["山頭有路接無塵，欲覓王孫試問津。", "瞥向蒼崖高處見，三三兩兩看遊人。"]'),
('9557c86a-cf85-4254-8022-0deebd773231','遊武夷作棹歌呈晦翁十首  其七','辛棄疾','宋','宋诗','song-poetry','','[]','巨石亭亭缺齧多，懸知千古也消磨。',32,'全唐诗/poet.song.162000.json','["巨石亭亭缺齧多，懸知千古也消磨。", "人間正覓擎天柱，無奈風吹雨打何。"]'),
('def13566-873d-485c-ac76-e5e524c4f6a9','遊武夷作棹歌呈晦翁十首  其八','辛棄疾','宋','宋诗','song-poetry','','[]','自有山來幾許年，千奇萬怪只依然。',32,'全唐诗/poet.song.162000.json','["自有山來幾許年，千奇萬怪只依然。", "試從精舍先生問，定在包犧八卦前。"]'),
('23f3b903-c620-4a61-a6a7-446e207e15e8','遊武夷作棹歌呈晦翁十首  其九','辛棄疾','宋','宋诗','song-poetry','','[]','山中有客帝王師，日日吟詩坐釣磯。',32,'全唐诗/poet.song.162000.json','["山中有客帝王師，日日吟詩坐釣磯。", "費盡煙霞供不足，幾時西伯載將歸。"]'),
('9e8e248e-6b4f-44af-9da2-d22cf59626cc','遊武夷作棹歌呈晦翁十首  其一○','辛棄疾','宋','宋诗','song-poetry','','[]','行盡桑麻九曲天，更尋佳處可留連。',32,'全唐诗/poet.song.162000.json','["行盡桑麻九曲天，更尋佳處可留連。", "如今歸棹如掤箭，不似來時上水船。"]'),
('9d3b568b-ab6d-4e22-99df-c31cac553621','鶴鳴亭絕句四首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','飽飯閑遊遶小溪，却將往事細尋思。',32,'全唐诗/poet.song.162000.json','["飽飯閑遊遶小溪，却將往事細尋思。", "有時思到難思處，拍碎闌干人不知。"]'),
('96f3f86e-2591-4df0-8d8e-1ffa975b1ab4','鶴鳴亭絕句四首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','安石榴花翠竹枝，婆娑其下更何爲。',32,'全唐诗/poet.song.162000.json','["安石榴花翠竹枝，婆娑其下更何爲。", "溪流自有無聲處，鶴舞不如閑立時。"]'),
('f6625e9e-348b-49f2-b7f8-2623df7f5796','鶴鳴亭絕句四首  其三','辛棄疾','宋','宋诗','song-poetry','','[]','舊時秋水醉吟者，且作西山病叟呼。',32,'全唐诗/poet.song.162000.json','["舊時秋水醉吟者，且作西山病叟呼。", "可惜黄花逢令節，樽中酒燥筆頭枯。"]'),
('b01944e7-9af6-4264-be2f-07e102e69200','鶴鳴亭絕句四首  其四','辛棄疾','宋','宋诗','song-poetry','','[]','清歡那復笑開口，閒事長令悶破頭。',32,'全唐诗/poet.song.162000.json','["清歡那復笑開口，閒事長令悶破頭。", "更有不堪蕭索處，西風過了菊花秋。"]'),
('ef8f0da9-e129-4782-88ed-4f0d669e7597','鶴鳴亭獨飲','辛棄疾','宋','宋诗','song-poetry','','[]','小亭獨酌興悠哉，忽有清愁到酒杯。',32,'全唐诗/poet.song.162000.json','["小亭獨酌興悠哉，忽有清愁到酒杯。", "四面青山圍欲合，不知愁自那邊來。"]'),
('b519f62e-11a5-4a64-a9ed-fcc497cb5d8b','即事  其一','辛棄疾','宋','宋诗','song-poetry','','[]','野人日日獻花來，只倩渠儂取意栽。',32,'全唐诗/poet.song.162000.json','["野人日日獻花來，只倩渠儂取意栽。", "高下參差無次序，要令不似俗亭臺。"]'),
('3bc6123e-135f-4150-90b4-e68ddd213974','即事  其二','辛棄疾','宋','宋诗','song-poetry','','[]','百憂常與事俱來，莫把胸中荆棘栽。',32,'全唐诗/poet.song.162000.json','["百憂常與事俱來，莫把胸中荆棘栽。", "但只熙熙閑過日，人間無處不春臺。"]'),
('32999809-51e7-4e9b-96b4-2e945ccf2431','重午日戲書','辛棄疾','宋','宋诗','song-poetry','','[]','青山吞吐古今月，綠樹低昂朝暮風。',32,'全唐诗/poet.song.162000.json','["青山吞吐古今月，綠樹低昂朝暮風。", "萬事有爲應有盡，此身無我自無窮。"]'),
('cdd40986-5f2c-41e2-ad6d-17a1cc66343e','林貴文買牡丹見贈至彭村偶題','辛棄疾','宋','宋诗','song-poetry','','[]','寶刀和雨剪流霞，送到彭村刺史家。',32,'全唐诗/poet.song.162000.json','["寶刀和雨剪流霞，送到彭村刺史家。", "聞道名園春已過，千金還買暨家花。"]'),
('1d4f7e5f-2ae1-413d-997f-c5d6fe5a5311','移竹','辛棄疾','宋','宋诗','song-poetry','','[]','每因種樹悲年事，待看成陰是幾時。',32,'全唐诗/poet.song.162000.json','["每因種樹悲年事，待看成陰是幾時。", "眼見子孫孫又子，不如栽竹繞園池。"]'),
('90f71d1c-4b92-49e7-8c50-1be4a8417e7a','和趙茂嘉郎中雙頭芍藥二首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','昨日梅華同語笑，今朝芍藥並芬芳。',32,'全唐诗/poet.song.162000.json','["昨日梅華同語笑，今朝芍藥並芬芳。", "弟兄殿住春風了，却遣花來送一觴。"]'),
('86fa9271-9975-4512-bfb3-aaaa7683dac6','和趙茂嘉郎中雙頭芍藥二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','當年負鼎去干湯，至味須參芍藥芳。',32,'全唐诗/poet.song.162000.json','["當年負鼎去干湯，至味須參芍藥芳。", "豈是調羹雙妙手，故教初發勸持觴。"]'),
('b5b025df-ecdd-4f82-87c6-1bcba6b67b71','壽趙茂嘉郎中二首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','玉色長身白首郎，當年麾節幾甘棠。',64,'全唐诗/poet.song.162000.json','["玉色長身白首郎，當年麾節幾甘棠。", "力貧活物陰功大，未老垂車逸興長。", "久矣如今太公望，巋然真是魯靈光。", "朝廷正爾尊黄髮，穩駕蒲輪覲玉皇。"]'),
('aace3999-bc6d-429f-9399-316d0895a54b','壽趙茂嘉郎中二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','鵝湖山麓湛溪湄，華屋眈眈照綠漪。',64,'全唐诗/poet.song.162000.json','["鵝湖山麓湛溪湄，華屋眈眈照綠漪。", "子姪日爲真率會，弟兄賸有唱酬詩。", "楊花榆莢渾如許，苦笋櫻桃正是時。", "待酌西江援北斗，摩挲金狄與君期。"]'),
('c6cdd13f-1532-4e49-9c0c-8f4c9aeed842','同杜叔高祝彥集觀天保菴瀑布主人留飲兩日且約牡丹之飲  其一','辛棄疾','宋','宋诗','song-poetry','','[]','竹杖芒鞋看瀑回，暮年筋力倦崔嵬。',32,'全唐诗/poet.song.162000.json','["竹杖芒鞋看瀑回，暮年筋力倦崔嵬。", "桃花落盡無春思，直待牡丹開後來。"]'),
('980e3c18-034e-4ed6-9c61-81ab193d1e4b','同杜叔高祝彥集觀天保菴瀑布主人留飲兩日且約牡丹之飲  其二','辛棄疾','宋','宋诗','song-poetry','','[]','只要尋花子細看，不妨草草有杯盤。',32,'全唐诗/poet.song.162000.json','["只要尋花子細看，不妨草草有杯盤。", "莫因紅紫傾城色，却去摧殘黑牡丹。"]'),
('28ffade2-b989-497e-987e-4c40bc7d644d','讀語孟二首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','道言不死真成妄，佛語無生更轉誣。',32,'全唐诗/poet.song.162000.json','["道言不死真成妄，佛語無生更轉誣。", "要識死生真道理，須憑鄒魯聖人儒。"]'),
('b1100482-0971-40bb-8aad-7db70f9886c4','讀語孟二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','屏去佛經與道書，只將語孟味真腴。',32,'全唐诗/poet.song.162000.json','["屏去佛經與道書，只將語孟味真腴。", "出門俯仰見天地，日月光中行坦途。"]'),
('ba5b427b-3962-4e10-a2a1-dcf97981441f','再用儒字韻二首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','人才長與世相疎，若謂無才即厚誣。',32,'全唐诗/poet.song.162000.json','["人才長與世相疎，若謂無才即厚誣。", "方朔長身無飯喫，人間飽死幾侏儒。"]'),
('95c76e69-2bef-4095-9ffa-a1196d1eb3c8','再用儒字韻二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','是是非非好讀書，莫將名實自相誣。',32,'全唐诗/poet.song.162000.json','["是是非非好讀書，莫將名實自相誣。", "由來廢冢誰爲者，詩禮相傳大小儒。"]'),
('9d997817-804e-4ffc-accc-e3157e2b052c','和任師見寄之韻  其一','辛棄疾','宋','宋诗','song-poetry','','[]','老來功業已蹉跎，買得生涯復不多。',32,'全唐诗/poet.song.162000.json','["老來功業已蹉跎，買得生涯復不多。", "十頃芰荷三徑菊，醉鄉容我住無何。"]'),
('74db4899-7106-467b-a8af-27507bf1cce1','和任師見寄之韻  其二','辛棄疾','宋','宋诗','song-poetry','','[]','昨夢春風花滿枝，是花到眼是新詩。',32,'全唐诗/poet.song.162000.json','["昨夢春風花滿枝，是花到眼是新詩。", "如今夢斷春無迹，不記題詩付與誰。"]'),
('cb620722-e3be-4ffe-8c24-e902e3a4f08d','和任師見寄之韻  其三','辛棄疾','宋','宋诗','song-poetry','','[]','幾年魂夢隔高門，歎息潭間闕異聞。',32,'全唐诗/poet.song.162000.json','["幾年魂夢隔高門，歎息潭間闕異聞。", "剩喜風情筋力在，尚能詩似鮑參軍。"]'),
('8c9bddce-b17f-44f1-840c-1e207105b539','和楊民瞻韻','辛棄疾','宋','宋诗','song-poetry','','[]','拄杖閑題祖印來，壁間有句試參懷。',32,'全唐诗/poet.song.162000.json','["拄杖閑題祖印來，壁間有句試參懷。", "從來歌舞新羅襪，不識溪山舊草鞋。"]'),
('51b6bde1-89b4-4d41-94fc-a579b4b4ef62','和諸葛元亮韻','辛棄疾','宋','宋诗','song-poetry','','[]','偊泛清溪李郭船，路旁人已羨登仙。',32,'全唐诗/poet.song.162000.json','["偊泛清溪李郭船，路旁人已羨登仙。", "看君不似南陽卧，只似哦詩孟浩然。"]'),
('b9032ba8-0643-4f39-963d-75295ad3f7df','和周顯先韻二首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','暖日晴風晚蝶忙，平林先著夜來霜。',32,'全唐诗/poet.song.162000.json','["暖日晴風晚蝶忙，平林先著夜來霜。", "寒花畢竟亡聊甚，野菜畦邊慘淡黄。"]'),
('c96e8a3f-fe59-4d4f-8955-644f0fd08cce','和周顯先韻二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','怒濤千里破空飛，洗盡青衫輦路泥。',32,'全唐诗/poet.song.162000.json','["怒濤千里破空飛，洗盡青衫輦路泥。", "更惜秋風一帆足，南樓只在遠山西。"]'),
('891e3b64-dae7-43f3-b4fe-a0cb8980b7db','和郭逢道韻  其一','辛棄疾','宋','宋诗','song-poetry','','[]','棗樹平生歎子陽，里歌雖短意偏長。',32,'全唐诗/poet.song.162000.json','["棗樹平生歎子陽，里歌雖短意偏長。", "東家昨夜梅花發，愧我分他一半香。"]'),
('142f7923-1fc2-4041-8aed-1134f2a07ae9','和郭逢道韻  其二','辛棄疾','宋','宋诗','song-poetry','','[]','君家富貴有汾陽，只要文章光焰長。',32,'全唐诗/poet.song.162000.json','["君家富貴有汾陽，只要文章光焰長。", "莫爲梅花費詩句，細思丹桂是天香。"]'),
('53bbc976-0da3-4c70-8e63-e9cf9cd08d77','黄沙書院','辛棄疾','宋','宋诗','song-poetry','','[]','隠几南窗萬念灰，只疑土木是形骸。',32,'全唐诗/poet.song.162000.json','["隠几南窗萬念灰，只疑土木是形骸。", "柴門不用常關著，怕有文殊問疾來。"]'),
('1cf1a346-cd22-4e0c-8494-db725b7c79fd','信筆再和二首  其一','辛棄疾','宋','宋诗','song-poetry','','[]','此心一似篆煙灰，好向君王早乞骸。',32,'全唐诗/poet.song.162000.json','["此心一似篆煙灰，好向君王早乞骸。", "何處幽人來問訊，橫擔竹杖過溪來。"]'),
('d2e1316d-9269-4b62-8f86-b05ebd368a05','信筆再和二首  其二','辛棄疾','宋','宋诗','song-poetry','','[]','春酒頻開赤印灰，一尊忘我更忘骸。',32,'全唐诗/poet.song.162000.json','["春酒頻開赤印灰，一尊忘我更忘骸。", "青山只隔二三里，恰似高人呼不來。"]'),
('c6602341-0357-4365-b044-7df7630de56a','和李都統詩','辛棄疾','宋','宋诗','song-poetry','','[]','破屋那堪急雨淋，且欣斷港運篙深。',32,'全唐诗/poet.song.162000.json','["破屋那堪急雨淋，且欣斷港運篙深。", "老農定向中宵望，太歲今年合守心。"]'),
('d7cdc75a-ab10-41a4-97e6-7a364cb8ea3c','再用韻','辛棄疾','宋','宋诗','song-poetry','','[]','自古蛾眉嫉者多，須防按劍向隨和。',32,'全唐诗/poet.song.162000.json','["自古蛾眉嫉者多，須防按劍向隨和。", "此身更似滄浪水，聽取當年孺子歌。"]'),
('9b7a3a96-aa4a-4f9e-a14f-2b4b9e9c88ba','書淵明詩後','辛棄疾','宋','宋诗','song-poetry','','[]','淵明避俗未聞道，此是東坡居士云。',32,'全唐诗/poet.song.162000.json','["淵明避俗未聞道，此是東坡居士云。", "身似枯株心似水，此非聞道更誰聞。"]'),
('e5050707-b262-4431-bbd9-161bdf6b1fcb','讀邵堯夫詩','辛棄疾','宋','宋诗','song-poetry','','[]','飲酒已輸陶靖節，作詩猶愛邵堯夫。',32,'全唐诗/poet.song.162000.json','["飲酒已輸陶靖節，作詩猶愛邵堯夫。", "若論老子胸中事，除却溪山一事無。"]'),
('5d89ab49-4e07-4214-b565-4a7e8f6e26a9','再用韻','辛棄疾','宋','宋诗','song-poetry','','[]','欲把身心入太虛，要須勤著浄工夫。',32,'全唐诗/poet.song.162000.json','["欲把身心入太虛，要須勤著浄工夫。", "古人有句須參取，窮到今年錐也無。"]'),
('8c69d22e-4a2f-4cfd-9ab8-8e13f5bc9d1f','偶題  其一','辛棄疾','宋','宋诗','song-poetry','','[]','人生憂患始於名，旦喜無聞過此生。',32,'全唐诗/poet.song.162000.json','["人生憂患始於名，旦喜無聞過此生。", "却得少年耽酒力，讀書學劍兩無成。"]'),
('55122f44-61e0-4eb3-8243-0b05d7cac39d','偶題  其二','辛棄疾','宋','宋诗','song-poetry','','[]','人言大道本强名，畢竟名從有處生。',32,'全唐诗/poet.song.162000.json','["人言大道本强名，畢竟名從有處生。", "昭氏鼓瑟誰解聽，亦無虧處亦無成。"]'),
('898e525b-4ec1-4a6a-b628-3ba5f433be0d','偶題  其三','辛棄疾','宋','宋诗','song-poetry','','[]','閑花浪蕊不知名，又是一番春草生。',32,'全唐诗/poet.song.162000.json','["閑花浪蕊不知名，又是一番春草生。", "病起小園無一事，杖藜看得綠陰成。"]'),
('8cc6c7ee-d2cb-4bfa-a205-64dc7fe9c1e2','偶作','辛棄疾','宋','宋诗','song-poetry','','[]','至性由來稟太和，善人何少惡人多。',32,'全唐诗/poet.song.162000.json','["至性由來稟太和，善人何少惡人多。", "君看瀉水著平地，正作方圓有幾何。"]'),
('3ca9cbaf-0b04-4cf4-ba08-3a9db774d023','和趙晉臣送糟蟹','辛棄疾','宋','宋诗','song-poetry','','[]','人間緩急正須才，郭索能令酒禁開。',32,'全唐诗/poet.song.162000.json','["人間緩急正須才，郭索能令酒禁開。", "一水一山十五日，從來能事不相催。"]'),
('c1132111-497e-4ae2-a415-52364673d6dc','止酒','辛棄疾','宋','宋诗','song-poetry','','[]','淵明愛酒得之天，歲晚還吟止酒篇。',32,'全唐诗/poet.song.162000.json','["淵明愛酒得之天，歲晚還吟止酒篇。", "日醉得非促齡具，只今病渴已三年。"]'),
('28f3aabe-73dc-4ffb-9d14-62f47ba9ca56','送劍與傅巖叟','辛棄疾','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u611f\u6168", "\u58ee\u5fd7\u672a\u916c"]','鏌邪三尺照人寒，試與挑燈子細看。',32,'全唐诗/poet.song.162000.json','["鏌邪三尺照人寒，試與挑燈子細看。", "且挂空齋作琴伴，未須携去斬樓蘭。"]'),
('b1b53d18-379a-41f1-9abf-af5fc3b1ad4c','江郎山和韻','辛棄疾','宋','宋诗','song-poetry','','[]','三峰一一青如削，卓立千尋不可干。',32,'全唐诗/poet.song.162000.json','["三峰一一青如削，卓立千尋不可干。", "正直相扶無倚傍，撐持天地與人看。"]'),
('4d11c1ee-d5c8-4311-a26e-37c349d2de7b','送別湖南部曲','辛棄疾','宋','宋诗','song-poetry','','["\u9001\u522b", "\u58ee\u5fd7\u96be\u916c", "\u6292\u6000"]','青衫匹馬萬人呼，幕府當年急急符。',64,'全唐诗/poet.song.162000.json','["青衫匹馬萬人呼，幕府當年急急符。", "愧我明珠成薏苡，負君赤手縛於菟。", "觀書到老眼如鏡，論事驚人膽滿軀。", "萬里雲霄送君去，不妨風雨破吾廬。"]'),
('fa0e0267-e65b-4b4f-aa0e-d30f698d77b1','感懷示兒輩','辛棄疾','宋','宋诗','song-poetry','','[]','安樂常思病苦時，靜觀山下有雷頤。',64,'全唐诗/poet.song.162000.json','["安樂常思病苦時，靜觀山下有雷頤。", "十千一斗酒無分，六十三年事自知。", "錯處真成九州鐵，樂時能得幾絇絲。", "新春老去惟梅在，一任狂風日夜吹。"]'),
('557a5362-4d3f-4b00-87cd-151dcca59bec','趙文遠見和用韻答之','辛棄疾','宋','宋诗','song-poetry','','[]','糲食粗衣飽暖時，從他鼻涕自垂頤。',64,'全唐诗/poet.song.162000.json','["糲食粗衣飽暖時，從他鼻涕自垂頤。", "萬金藥豈世無有，九折臂餘人始知。", "過雨沾香辭落蔕，隨風飛絮趁遊絲。", "我無妙語酬春事，慚愧新歌值鳳吹。"]'),
('2f477362-7358-47b1-ac64-64757202096a','傅巖叟見和用韻答之','辛棄疾','宋','宋诗','song-poetry','','[]','萬里魚龍會有時，壯懷歌罷涕交頤。',64,'全唐诗/poet.song.162000.json','["萬里魚龍會有時，壯懷歌罷涕交頤。", "一毛未許楊朱拔，三戰空懷鮑叔知。", "明月夜光多白眼，高山流水自朱絲。", "塵埃野馬知多少，擬倩撩天鼻孔吹。"]'),
('204d3e9f-f515-4e6f-9740-39c85e131948','諸葛元亮見和復用韻答之','辛棄疾','宋','宋诗','song-poetry','','[]','大儒學禮小儒詩，聽取臚傳夜控頤。',64,'全唐诗/poet.song.162000.json','["大儒學禮小儒詩，聽取臚傳夜控頤。", "事出肺肝人易見，道如飲食味難知。", "此生能著幾緉屐，何處高懸一縷絲。", "却笑空山頑老子，年來堪受八風吹。"]'),
('83602a4f-3f0e-4ab8-b7a8-a77b92a47122','壽朱晦翁','辛棄疾','宋','宋诗','song-poetry','','[]','西風卷盡護霜筠，碧玉壺天月色新。',64,'全唐诗/poet.song.162000.json','["西風卷盡護霜筠，碧玉壺天月色新。", "鳳曆半千開誕日，龍山重九逼佳辰。", "先心坐使鬼神伏，一笑能回宇宙春。", "歷數唐堯千載下，如公僅有兩三人。"]'),
('0383c954-d62a-4ca9-a68b-6503c5a96de4','和趙昌父問訊新居之作','辛棄疾','宋','宋诗','song-poetry','','[]','草堂經始上元初，四面溪山畫不如。',64,'全唐诗/poet.song.162000.json','["草堂經始上元初，四面溪山畫不如。", "疇昔人憐翁失馬，只今自喜我知魚。", "苦無突兀千間庇，豈負辛勤一束書。", "種木十年渾未辦，此心留待百年餘。"]'),
('fe43dff0-034c-4b68-8705-345c2a5d16c3','題鶴鳴亭  其一','辛棄疾','宋','宋诗','song-poetry','','[]','種竹栽花猝未休，樂天知命且無憂。',64,'全唐诗/poet.song.162000.json','["種竹栽花猝未休，樂天知命且無憂。", "百年自運非人力，萬事從今與鶴謀。", "用力何如巧作湊，封侯原自曲如鉤。", "請看魚鳥飛潛處，更有雞蟲得失不。"]'),
('151c6d7e-c4d5-4ef8-bd63-3cd1360c3e63','題鶴鳴亭  其二','辛棄疾','宋','宋诗','song-poetry','','[]','莫被閒愁撓太和，愁來只用暗消磨。',64,'全唐诗/poet.song.162000.json','["莫被閒愁撓太和，愁來只用暗消磨。", "隨流上下寧能免，驚世功名不用多。", "閒看蜂衙足官府，夢隨蟻鬭有干戈。", "疎簾竹簟山茶碗，此是幽人安樂窩。"]'),
('1816a8dc-c8ee-4b26-9d7e-872c88959c90','題鶴鳴亭  其三','辛棄疾','宋','宋诗','song-poetry','','[]','林下蕭然一禿翁，斜陽扶杖對西風。',64,'全唐诗/poet.song.162000.json','["林下蕭然一禿翁，斜陽扶杖對西風。", "功名此去心如水，富貴由來色是空。", "便好洗心依佛祖，不妨强笑伴兒童。", "客來閒說那堪聽，且喜新來耳漸聾。"]'),
('33002640-1b98-43ce-b5a3-02d6093cba4e','和泉上人','辛棄疾','宋','宋诗','song-poetry','','[]','芒鞋踏遍萬山松，得得歸來丈室中。',64,'全唐诗/poet.song.162000.json','["芒鞋踏遍萬山松，得得歸來丈室中。", "破裓一身在懸磬，清談對客似撞鐘。", "名家要看驚人舉，覓句何須效我窮。", "春雨地罏分半坐，便疑身住古禪叢。"]'),
('66f5cc16-ba45-472d-b3af-2eae4b10a0c9','玉真書院經德堂','辛棄疾','宋','宋诗','song-poetry','','[]','平生經德幾人知，莫忘當年兩字師。',64,'全唐诗/poet.song.162000.json','["平生經德幾人知，莫忘當年兩字師。", "絕代本無空谷歎，逢人且覓瑱山詩。", "千章古木陰濃處，萬卷藏書讀盡時。", "却把一杯堂上笑，世間多少噉名兒。"]'),
('1d11adf2-8538-4e9d-a762-c1c2610cb926','和趙直中提幹韻','辛棄疾','宋','宋诗','song-poetry','','[]','萬事推移本偶然，無虧何處更求全。',64,'全唐诗/poet.song.162000.json','["萬事推移本偶然，無虧何處更求全。", "折腰曾愧五斗米，負郭元無三頃田。", "城礙夕陽宜杖履，山供醉眼費雲煙。", "怪君不顧笙歌誤，政擬新詩去鳥邊。"]'),
('bfcdb51e-3f5d-4a05-97a0-77e5da8a5720','有以事來請者傚康節體作詩以答之','辛棄疾','宋','宋诗','song-poetry','','[]','未能立得自家身，何暇將身更爲人。',64,'全唐诗/poet.song.162000.json','["未能立得自家身，何暇將身更爲人。", "借使有求能盡與，也知方笑已生嗔。", "器纔滿後須招損，鏡太明時易受塵。", "終日閉門無客至，近來魚鳥却相親。"]'),
('07907efc-3596-480e-b8b0-43719a69dedb','江行弔宋齊邱','辛棄疾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嘗笑韓非死說難，先生事業最相關。',64,'全唐诗/poet.song.162000.json','["嘗笑韓非死說難，先生事業最相關。", "能令父子君臣際，常在干戈揖遜間。", "秋浦山高明月在，丹陽人去晚風閑。", "可憐千古長江水，不與渠儂洗厚顔。"]'),
('d8ebb4cb-7cf0-46b0-9968-61f92f04eb0a','新年團拜後和主敬韻並呈雪平','辛棄疾','宋','宋诗','song-poetry','','[]','已把年華遜得翁，滿前依舊祖遺蹤。',64,'全唐诗/poet.song.162000.json','["已把年華遜得翁，滿前依舊祖遺蹤。", "謝家固不多安石，阮氏還能幾嗣宗。", "今是昨非當謂夢，富妍貧醜各爲容。", "修然白髮猶何事，祇好三人自一龍。"]'),
('28c2c7a4-359d-4763-893b-7233da46d624','和人韻','辛棄疾','宋','宋诗','song-poetry','','[]','老奴權至使將軍，非所宜蒙定可黥。',64,'全唐诗/poet.song.162000.json','["老奴權至使將軍，非所宜蒙定可黥。", "嫫母侏儒曾一笑，瓠壺藤蔓便相縈。", "解紛已見立談頃，漏網從今太橫生。", "豈是人間重生女，只應詩老例多情。"]'),
('e8e14ef0-b394-44c3-8a36-337fa1a28c95','和前人韻  其一','辛棄疾','宋','宋诗','song-poetry','','[]','池魚豈足較浮沉，邱貉何曾異古今。',64,'全唐诗/poet.song.162000.json','["池魚豈足較浮沉，邱貉何曾異古今。", "末路長憐鞭馬腹，淡交端可炙牛心。", "山方高卧雲長亂，松本忘言風自吟。", "昨日溪南雞酒社，長卿多病不能臨。"]'),
('406891f8-f469-42fd-81c9-9a39cc7d6d16','和前人韻  其二','辛棄疾','宋','宋诗','song-poetry','','[]','茶瓜不作片時留，又向悠然作勝遊。',64,'全唐诗/poet.song.162000.json','["茶瓜不作片時留，又向悠然作勝遊。", "花徑似經新掃灑，竹林喚起舊風流。", "天教有象皆楷寫，世已無書可校讐。", "長日苦遭蟬噪聒，杖藜擬訪澗泉秋。"]'),
('7ebb7bca-20f6-4580-9ad4-55aee10de4a9','和人韻','辛棄疾','宋','宋诗','song-poetry','','[]','老來筋力上山遲，過眼風光自崛奇。',64,'全唐诗/poet.song.162000.json','["老來筋力上山遲，過眼風光自崛奇。", "擬放狂歌花已笑，正羞短髮雪偏垂。", "谿山能破幾緉屐，風雨連催十二時。", "且鎖君詩怕飛去，從人喚我虎頭癡。"]'),
('5a7ec3e3-5a8c-4b28-be42-fcedb87516a5','和前人觀梅雪有懷見寄','辛棄疾','宋','宋诗','song-poetry','','[]','相思幾欲扣停雲，抱疾還嗟老不文。',64,'全唐诗/poet.song.162000.json','["相思幾欲扣停雲，抱疾還嗟老不文。", "滿眼梅花深雪片，何人野鶴在鷄羣。", "詩肩相見高如舊，酒甲而今蘸幾分。", "且向梁園賦清景，自知才思不如君。"]'),
('fd9ecca5-8497-40db-bef2-8baef4095373','丙寅歲山間競傳諸將有下棘寺者','辛棄疾','宋','宋诗','song-poetry','','[]','去年騎鶴上揚州，意氣平吞萬戶侯。',64,'全唐诗/poet.song.162000.json','["去年騎鶴上揚州，意氣平吞萬戶侯。", "誰使匈奴來塞上，却從廷尉望山頭。", "榮華大抵有時歇，禍福無非自己求。", "記取山西千古恨，李陵門下至今羞。"]'),
('25acbc25-2fed-4c0d-a2e1-7fa2a1dca07c','丙寅九月二十八日作來年將告老','辛棄疾','宋','宋诗','song-poetry','','[]','漸識空虛不二門，掃除諸幻絕根塵。',64,'全唐诗/poet.song.162000.json','["漸識空虛不二門，掃除諸幻絕根塵。", "此心自擬終成佛，許事從今只任真。", "有我故應還起滅，無求何自別冤親。", "西山病叟支離甚，欲向君王乞此身。"]'),
('d62e2562-6cf1-4302-b8e3-9baea3015836','偶作  其一','辛棄疾','宋','宋诗','song-poetry','','[]','兒曹談笑覓封侯，自喜婆娑老此丘。',64,'全唐诗/poet.song.162000.json','["兒曹談笑覓封侯，自喜婆娑老此丘。", "棋鬭機關嫌狡獪，鶴貪吞啖損風流。", "强留客飲渾忘倦，已辦官租百不憂。", "我識簞瓢真樂處，詩書執禮易春秋。"]'),
('2f5792dc-e042-4c37-b6c6-538f253eec66','偶作  其二','辛棄疾','宋','宋诗','song-poetry','','[]','一氣同生天地人，不知何者是吾身。',64,'全唐诗/poet.song.162000.json','["一氣同生天地人，不知何者是吾身。", "欲依佛老心難住，却對漁樵語益真。", "靜處時呼酒賢聖，病來稍識藥君臣。", "由來不樂金朱事，且喜長同壠畝民。"]'),
('0e150ded-9d85-445f-8fc1-4a3a8b975a0b','偶作  其三','辛棄疾','宋','宋诗','song-poetry','','[]','老去都無寵辱驚，靜中時見古今情。',64,'全唐诗/poet.song.162000.json','["老去都無寵辱驚，靜中時見古今情。", "大凡物必有終始，豈有人能脫死生。", "日月相催飛似箭，陰陽爲寇慘於兵。", "此身果欲參天地，且讀中庸盡至誠。"]'),
('9a65a041-a2e4-4f1d-af15-c2b3dfcc878c','和吳克明廣文賦梅','辛棄疾','宋','宋诗','song-poetry','','[]','誰詠寒枝入國風，廣文官冷更詩窮。',64,'全唐诗/poet.song.162000.json','["誰詠寒枝入國風，廣文官冷更詩窮。", "偶隨岸柳春先覺，試比山樊韻不同。", "十頃清風明月外，一杯疎影暗香中。", "遥知一夜相思後，鐵石心腸也惱翁。"]'),
('6d25c66e-8be3-474b-8e28-ec06b91f935b','和趙茂嘉郎中賦梅','辛棄疾','宋','宋诗','song-poetry','','[]','空谷春遲懶却梅，年年不肯犯寒開。',64,'全唐诗/poet.song.162000.json','["空谷春遲懶却梅，年年不肯犯寒開。", "怕看零落雁先去，欲伴孤高人未來。", "解后平生惟酒可，風流抵死要詩催。", "更憐雪屋君家樹，三十年來手自栽。"]'),
('e1cca518-bbe2-4db5-a8dd-091b2f829733','和趙國興知錄贈琴','辛棄疾','宋','宋诗','song-poetry','','[]','趙君胸中何瑰奇，白日照耀珊瑚枝。',194,'全唐诗/poet.song.162000.json','["趙君胸中何瑰奇，白日照耀珊瑚枝。", "新詩哦成七字句，孤桐贈我千金資。", "人間皓齒蛾眉斧，箏笛紛紛君未許。", "自言工作古離騷，十指黄鍾挾大呂。", "芙蓉清江薜荔塘，靈均一去乘鸞凰。", "君試一彈來故鄉，荷衣蕙带芳椒堂。", "往時嵇阮二三子，能以遺音還正始。", "誰令窈窕從戶窺，曾聞長卿心好之。", "低頭兒女調音節，此器豈因渠輩設。", "勸君往和薰風絃，明光珮玉聲璆然。", "此時高山與流水，應有鍾期知妙旨。", "只今欲解無絃嘲，聽取長松萬壑風蕭騷。"]'),
('e0365d8c-169a-486c-9d2f-60235c4aa219','贈申孝子世寧','辛棄疾','宋','宋诗','song-poetry','','[]','六月烈日日正中，時有叛將號羣兇。',224,'全唐诗/poet.song.162000.json','["六月烈日日正中，時有叛將號羣兇。", "平人血染大溪浪，比屋焰照鵝湖峰。", "白刃紛紛避行路，六合茫茫何處去。", "妻見夫亡不敢啼，母棄兒奔那忍顧。", "藥市申公鬢有霜，卧病經時不下床。", "平生未省見兵革，出門正爾逢豺狼。", "豺狼滿市如流水，追索金繒心未已。", "可憐累世積陰功，今日將爲兵死鬼。", "世寧孝行何高高，慨慷性命輕鴻毛。", "爾時自欲赴黄壤，欣然延頸迎霜刀。", "至孝感兮天地動，白日無光百川湧。", "三刀不死古今稀，一命自有神靈擁。", "羣賢激賞爭作歌，要使汝名長不磨。", "何時上書達天聽，詔加旌賞高嵯峨。"]'),
('ed2c9d39-e8f1-46d8-bb65-38d191d8091a','重葉梅  其一','辛棄疾','宋','宋诗','song-poetry','','[]','百花頭上開，冰雪寒中見。',24,'全唐诗/poet.song.162000.json','["百花頭上開，冰雪寒中見。", "霜月定相知，先識春風面。"]'),
('0282dd49-6386-4814-9c52-591e2a42f1ab','重葉梅  其二','辛棄疾','宋','宋诗','song-poetry','','[]','主人情意深，不管江妃怨。',24,'全唐诗/poet.song.162000.json','["主人情意深，不管江妃怨。", "折我最繁枝，還許冰壺薦。"]'),
('94033c58-c43a-427e-a5f6-e84f54b16358','宿驛  其一','辛棄疾','宋','宋诗','song-poetry','','[]','他鄉異縣老何堪，短髮蕭蕭不勝簪。',32,'全唐诗/poet.song.162000.json','["他鄉異縣老何堪，短髮蕭蕭不勝簪。", "旋買一樽持自賀，病身安穩到江南。"]'),
('9e83e4d8-6797-42e9-8811-cd3c30191048','宿驛  其二','辛棄疾','宋','宋诗','song-poetry','','[]','雲外丹青萬仞梯，木陰合處子規啼。',32,'全唐诗/poet.song.162000.json','["雲外丹青萬仞梯，木陰合處子規啼。", "嘉陵棧路吾能說，略似黄亭到紫溪。"]'),
('4868481b-f31f-4169-9516-75e5798b9077','郡齋懷隠庵  其一','辛棄疾','宋','宋诗','song-poetry','','[]','天寒秋色入平林，更著西風月下砧。',32,'全唐诗/poet.song.162000.json','["天寒秋色入平林，更著西風月下砧。", "舊日醉吟渾不管，如今節物總關心。"]'),
('9ee7a5ee-0289-4235-9df3-4d854eacb733','郡齋懷隠庵  其二','辛棄疾','宋','宋诗','song-poetry','','[]','空山鐘鼓梵王家，小立西風數過鴉。',32,'全唐诗/poet.song.162000.json','["空山鐘鼓梵王家，小立西風數過鴉。", "秋色無多誰占斷，長廊西畔佛桑花。"]'),
('d9c8d7f3-d192-4ae6-898b-522f6b21b8ae','憶李白','辛棄疾','宋','宋诗','song-poetry','','[]','當年宮殿賦昭陽，豈信人間過夜郎。',64,'全唐诗/poet.song.162000.json','["當年宮殿賦昭陽，豈信人間過夜郎。", "明月入江依舊好，青山埋骨至今香。", "不尋飯顆山頭伴，却趁汨羅江上狂。", "定要騎鯨歸汗漫，故來濯足戲滄浪。"]'),
('fe420185-f96d-45ff-96f9-a0664f650632','題鵝湖壁','辛棄疾','宋','宋诗','song-poetry','','[]','昔年留此苦思歸，爲憶啼門玉雪兒。',32,'全唐诗/poet.song.162000.json','["昔年留此苦思歸，爲憶啼門玉雪兒。", "鸞鵠飛殘梧竹冷，只今歸興却遲遲。"]'),
('3393e75b-28ec-4724-9654-9e4e788214e9','書清凉境界壁  其一','辛棄疾','宋','宋诗','song-poetry','','[]','從今數到七十歲，一十四度見梅花。',32,'全唐诗/poet.song.162000.json','["從今數到七十歲，一十四度見梅花。", "何况人生七十少，云胡不歸留此耶。"]'),
('c979f49e-8727-4278-9545-3968a45c8ec2','書清凉境界壁  其二','辛棄疾','宋','宋诗','song-poetry','','[]','江左何時見王謝，風流且對竹間梅。',32,'全唐诗/poet.song.162000.json','["江左何時見王謝，風流且對竹間梅。", "最憐飛雪蒼苔上，時有珍禽蹴地來。"]'),
('eab57172-d8cc-4630-b633-5a845b4bd61f','書停雲壁  其一','辛棄疾','宋','宋诗','song-poetry','','[]','學作堯夫自在詩，何曾因物說天機。',32,'全唐诗/poet.song.162000.json','["學作堯夫自在詩，何曾因物說天機。", "斜陽草舍迷歸路，却與牛羊作伴歸。"]'),
('ba5cc42b-a8ff-4eed-a898-7b4e780f4aa7','書停雲壁  其二','辛棄疾','宋','宋诗','song-poetry','','[]','萬事隨緣無所爲，萬法皆空無所思。',32,'全唐诗/poet.song.162000.json','["萬事隨緣無所爲，萬法皆空無所思。", "惟有一條生死路，古今來往更何疑。"]'),
('513b1e3f-0ab2-4780-91e3-c499f0697b27','書鶴鳴亭壁','辛棄疾','宋','宋诗','song-poetry','','[]','翠竹栽成占一丘，清溪映带極風流。',32,'全唐诗/poet.song.162000.json','["翠竹栽成占一丘，清溪映带極風流。", "山翁一向貪奇趣，更引飛泉在上頭。"]'),
('5ebbee03-d570-47ed-bd29-f360b638ce92','醉書其壁  其一','辛棄疾','宋','宋诗','song-poetry','','[]','頗覺參禪近有功，因空成色色成空。',32,'全唐诗/poet.song.162000.json','["頗覺參禪近有功，因空成色色成空。", "色空靜處如何說，且坐清凉境界中。"]'),
('84b93d91-c3de-4e14-a1b9-eb3dbfa2f43c','醉書其壁  其二','辛棄疾','宋','宋诗','song-poetry','','[]','去年冠蓋長安道，客裏因循過了梅。',32,'全唐诗/poet.song.162000.json','["去年冠蓋長安道，客裏因循過了梅。", "今歲花開轉多事，簿書叢裏兩三杯。"]'),
('9f1bcad1-4593-4621-99f0-45c60af088fe','書壽寧寺壁','辛棄疾','宋','宋诗','song-poetry','','[]','門前幽徑踏蒼苔，猶憶前回信步來。',32,'全唐诗/poet.song.162000.json','["門前幽徑踏蒼苔，猶憶前回信步來。", "午醉正酣歸未得，斜陽古殿橘花開。"]'),
('5888dd0a-dd95-4d70-af4d-c943561193c0','讀書','辛棄疾','宋','宋诗','song-poetry','','[]','是非得失兩茫茫，閑把遺書細較量。',32,'全唐诗/poet.song.162000.json','["是非得失兩茫茫，閑把遺書細較量。", "掩卷古人堪笑處，起來摩腹步長廊。"]'),
('7c0772f8-942f-443b-b6a9-0c84a91bdc0f','戲書圓覺經後','辛棄疾','宋','宋诗','song-poetry','','[]','圓覺十二菩薩問，吾取一二餘鄙哉。',32,'全唐诗/poet.song.162000.json','["圓覺十二菩薩問，吾取一二餘鄙哉。", "若是如來真實語，衆生却自勝如來。"]'),
('cf1bed1e-d9a5-4273-abf4-60f099aef2ce','讀圓覺經','辛棄疾','宋','宋诗','song-poetry','','[]','二十五輪清浄觀，上中下期春夏齋。',32,'全唐诗/poet.song.162000.json','["二十五輪清浄觀，上中下期春夏齋。", "本來欲造空虛地，那得許多纏繞來。"]'),
('ef486640-b242-4af4-9964-355a2a419bc1','壽朱文公','辛棄疾','宋','宋诗','song-poetry','','[]','玉漏聲沉曉色回，五雲絢綵映庭槐。',63,'全唐诗/poet.song.162000.json','["玉漏聲沉曉色回，五雲絢綵映庭槐。", "持巾珠履攙稱賀，飛鞚貂璫押賜來。", "黄菊尚遲三日約，碧桃已作十分開。", "洞天春色非人世，不記河第幾回。"]'),
('ae9cac19-0a6e-488a-8504-a5e5784f4262','壽趙守','辛棄疾','宋','宋诗','song-poetry','','[]','天孫錦字織雲烟，來向紅塵了世緣。',63,'全唐诗/poet.song.162000.json','["天孫錦字織雲烟，來向紅塵了世緣。", "前去中秋猶十日，後來甲子更千年。", "牆南竹韵調琴譜，堂北萱香載酒船。", "且與剪圭舊約，不妨却伴橘中仙。"]'),
('36227498-2b10-4d03-8a4b-7125a8edcf4b','句  其一','辛棄疾','宋','宋诗','song-poetry','','[]','身爲參禪老，家因赴詔貧。',12,'全唐诗/poet.song.162000.json','["身爲參禪老，家因赴詔貧。"]'),
('6d68abc6-04b8-4dba-9fff-b9018713842d','句  其二','辛棄疾','宋','宋诗','song-poetry','','[]','酒腸未減長鯨吸，詩思如抽獨繭絲。',16,'全唐诗/poet.song.162000.json','["酒腸未減長鯨吸，詩思如抽獨繭絲。"]'),
('b4890f7b-e9ff-4d2a-af36-75d321e83a35','句  其三','辛棄疾','宋','宋诗','song-poetry','','[]','多情爲我香成陣。',8,'全唐诗/poet.song.162000.json','["多情爲我香成陣。"]');
